CREATE OR REPLACE FUNCTION "public"."accept_delivery_job"("p_job_id" "uuid", "p_worker_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_current_status TEXT;
BEGIN
  -- Check current status
  SELECT status INTO v_current_status FROM grocery_delivery_jobs WHERE id = p_job_id;

  IF v_current_status != 'posted' THEN
    RETURN FALSE;
  END IF;

  -- Accept job
  UPDATE grocery_delivery_jobs SET
    worker_id = p_worker_id,
    worker_accepted_at = now(),
    status = 'accepted',
    updated_at = now()
  WHERE id = p_job_id AND status = 'posted';

  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."accept_delivery_job"("p_job_id" "uuid", "p_worker_id" "uuid") OWNER TO "postgres";


