CREATE OR REPLACE FUNCTION "public"."add_shared_vault_content"("p_authorization_id" "uuid", "p_content_type" "text", "p_title" "text" DEFAULT NULL::"text", "p_description" "text" DEFAULT NULL::"text", "p_file_url" "text" DEFAULT NULL::"text", "p_content_text" "text" DEFAULT NULL::"text", "p_photo_urls" "text"[] DEFAULT NULL::"text"[], "p_original_date" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_location" "text" DEFAULT NULL::"text", "p_tags" "text"[] DEFAULT NULL::"text"[]) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_content_id UUID;
BEGIN
    -- Verify ownership of authorization
    IF NOT EXISTS (
        SELECT 1 FROM vault_sharing_authorizations
        WHERE id = p_authorization_id AND granter_user_id = auth.uid()
    ) THEN
        RETURN jsonb_build_object('success', false, 'error', 'Authorization not found or not yours');
    END IF;

    INSERT INTO vault_shared_content (
        authorization_id,
        content_type,
        title,
        description,
        file_url,
        content_text,
        photo_urls,
        original_date,
        location,
        tags,
        created_by
    ) VALUES (
        p_authorization_id,
        p_content_type,
        p_title,
        p_description,
        p_file_url,
        p_content_text,
        p_photo_urls,
        p_original_date,
        p_location,
        p_tags,
        auth.uid()
    )
    RETURNING id INTO v_content_id;

    RETURN jsonb_build_object('success', true, 'content_id', v_content_id);
END;
$$;


ALTER FUNCTION "public"."add_shared_vault_content"("p_authorization_id" "uuid", "p_content_type" "text", "p_title" "text", "p_description" "text", "p_file_url" "text", "p_content_text" "text", "p_photo_urls" "text"[], "p_original_date" timestamp with time zone, "p_location" "text", "p_tags" "text"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."add_to_ip_ledger"("p_record_type" "text", "p_record_data" "jsonb", "p_medallion_id" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_prev_hash text;
  v_prev_seq bigint;
  v_new_seq bigint;
  v_record_hash text;
  v_new_id uuid;
BEGIN
  -- Get previous record
  SELECT record_hash, sequence_number INTO v_prev_hash, v_prev_seq
  FROM ip_ledger ORDER BY sequence_number DESC LIMIT 1;

  v_new_seq := COALESCE(v_prev_seq, 0) + 1;

  -- Calculate hash (simplified - would use proper crypto in production)
  v_record_hash := encode(sha256(
    (v_new_seq::text || COALESCE(v_prev_hash, 'GENESIS') || p_record_type || p_record_data::text)::bytea
  ), 'hex');

  INSERT INTO ip_ledger (sequence_number, previous_hash, record_hash, record_type, record_data, medallion_id)
  VALUES (v_new_seq, v_prev_hash, v_record_hash, p_record_type, p_record_data, p_medallion_id)
  RETURNING id INTO v_new_id;

  RETURN v_new_id;
END;
$$;


ALTER FUNCTION "public"."add_to_ip_ledger"("p_record_type" "text", "p_record_data" "jsonb", "p_medallion_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."append_compiled_document_chunk"("p_slug" "text", "p_chunk_content" "text", "p_chunk_bytes" integer, "p_mark_lode" boolean DEFAULT true) RETURNS TABLE("id" "uuid", "slug" "text", "content_size_bytes" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  UPDATE compiled_documents
  SET
    compiled_markdown = COALESCE(compiled_markdown, '') || COALESCE(p_chunk_content, ''),
    content_size_bytes = COALESCE(content_size_bytes, 0) + COALESCE(p_chunk_bytes, 0),
    is_lode = CASE WHEN p_mark_lode THEN true ELSE is_lode END,
    updated_at = now()
  WHERE compiled_documents.slug = p_slug
  RETURNING compiled_documents.id, compiled_documents.slug, compiled_documents.content_size_bytes
  INTO id, slug, content_size_bytes;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'compiled_documents row not found for slug %', p_slug
      USING ERRCODE = 'P0002';
  END IF;

  RETURN NEXT;
END;
$$;


ALTER FUNCTION "public"."append_compiled_document_chunk"("p_slug" "text", "p_chunk_content" "text", "p_chunk_bytes" integer, "p_mark_lode" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."approve_cost_plus_certification"("p_audit_id" "uuid", "p_review_notes" "text" DEFAULT NULL::"text", "p_validity_days" integer DEFAULT 365) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_anchor_id UUID;
BEGIN
  -- Get anchor ID from audit
  SELECT anchor_id INTO v_anchor_id FROM public.cost_plus_audits WHERE id = p_audit_id;

  IF v_anchor_id IS NULL THEN
    RAISE EXCEPTION 'Audit request not found';
  END IF;

  -- Update audit record
  UPDATE public.cost_plus_audits
  SET status = 'approved',
      reviewed_by = auth.uid(),
      review_notes = p_review_notes,
      reviewed_at = NOW(),
      valid_from = NOW(),
      valid_until = NOW() + (p_validity_days || ' days')::INTERVAL,
      updated_at = NOW()
  WHERE id = p_audit_id;

  -- Update anchor
  UPDATE public.anchors
  SET verified_cost_plus = true,
      cost_plus_verified_at = NOW(),
      cost_plus_verified_by = auth.uid(),
      cost_plus_notes = p_review_notes,
      cost_plus_revoked_at = NULL,
      cost_plus_revoked_reason = NULL,
      updated_at = NOW()
  WHERE id = v_anchor_id;

  RETURN true;
END;
$$;


ALTER FUNCTION "public"."approve_cost_plus_certification"("p_audit_id" "uuid", "p_review_notes" "text", "p_validity_days" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."approve_cost_plus_certification"("p_audit_id" "uuid", "p_review_notes" "text", "p_validity_days" integer) IS 'Approve a C+20 certification request (admin only)';



CREATE OR REPLACE FUNCTION "public"."are_members_connected"("member_a" "uuid", "member_b" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    a_to_b BOOLEAN;
    b_to_a BOOLEAN;
BEGIN
    SELECT COALESCE(is_connected, true) INTO a_to_b
    FROM member_relationships WHERE from_member = member_a AND to_member = member_b;

    SELECT COALESCE(is_connected, true) INTO b_to_a
    FROM member_relationships WHERE from_member = member_b AND to_member = member_a;

    RETURN COALESCE(a_to_b, true) AND COALESCE(b_to_a, true);
END;
$$;


