CREATE OR REPLACE FUNCTION "public"."assign_harper_audit"("p_node_id" "uuid", "p_audit_type" "text" DEFAULT 'scheduled'::"text") RETURNS "uuid"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_selected_auditor_id UUID;
  v_audit_id UUID;
  v_node_expertise TEXT[];
BEGIN
  -- Get node's expertise domains (placeholder)
  v_node_expertise := ARRAY['general'];

  -- Select eligible auditor
  -- Criteria: different node, different region, 30+ days since last audit, domain match
  SELECT ha.id INTO v_selected_auditor_id
  FROM harper_auditors ha
  WHERE ha.credential_status = 'active'
    AND ha.last_audit_node_id IS DISTINCT FROM p_node_id
    AND (ha.last_audit_date IS NULL OR ha.last_audit_date < NOW() - INTERVAL '30 days')
    AND ha.expertise_domains && v_node_expertise
  ORDER BY
    -- Weight by: higher reputation, more audits completed, longer since last audit
    ha.reputation_score DESC,
    ha.total_audits_completed DESC,
    COALESCE(ha.last_audit_date, '1970-01-01'::timestamptz) ASC
  LIMIT 1;

  IF v_selected_auditor_id IS NULL THEN
    RAISE EXCEPTION 'No eligible Harper auditors available for this node';
  END IF;

  -- Create audit record
  INSERT INTO harper_audits (auditor_id, node_id, audit_type, scheduled_for)
  VALUES (v_selected_auditor_id, p_node_id, p_audit_type, NOW() + INTERVAL '7 days')
  RETURNING id INTO v_audit_id;

  RETURN v_audit_id;
END;
$$;


ALTER FUNCTION "public"."assign_harper_audit"("p_node_id" "uuid", "p_audit_type" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."assign_harper_audit"("p_node_id" "uuid", "p_audit_type" "text") IS 'Audit assignment with geographic separation and domain matching - Claim #5';



CREATE OR REPLACE FUNCTION "public"."assign_pioneer"("p_member_id" "uuid", "p_role" "text") RETURNS TABLE("pioneer_number" integer, "tier" "text", "monthly_bonus" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_next_number INTEGER;
  v_tier RECORD;
  v_expiry TIMESTAMPTZ;
BEGIN
  -- Already a pioneer for this role?
  IF EXISTS (SELECT 1 FROM pioneers WHERE member_id = p_member_id AND cue_card_role = p_role) THEN
    RETURN QUERY SELECT p2.pioneer_number, p2.tier, p2.monthly_bonus_marks
      FROM pioneers p2 WHERE p2.member_id = p_member_id AND p2.cue_card_role = p_role;
    RETURN;
  END IF;

  -- Next number (serialized via advisory lock)
  PERFORM pg_advisory_xact_lock(hashtext(p_role));
  SELECT COALESCE(MAX(p3.pioneer_number), 0) + 1 INTO v_next_number FROM pioneers p3 WHERE p3.cue_card_role = p_role;

  -- Look up tier
  SELECT * INTO v_tier FROM pioneer_tiers pt
    WHERE pt.min_number <= v_next_number AND pt.max_number >= v_next_number
    LIMIT 1;

  IF v_tier IS NULL THEN
    SELECT * INTO v_tier FROM pioneer_tiers pt WHERE pt.tier = 'standard';
  END IF;

  v_expiry := CASE WHEN v_tier.duration_months > 0
    THEN now() + (v_tier.duration_months || ' months')::INTERVAL
    ELSE NULL END;

  INSERT INTO pioneers (member_id, cue_card_role, pioneer_number, tier, monthly_bonus_marks, bonus_duration_months, bonus_expires_at, medallion_serial)
  VALUES (
    p_member_id, p_role, v_next_number, v_tier.tier, v_tier.monthly_bonus,
    v_tier.duration_months, v_expiry,
    CASE WHEN v_tier.gets_medallion THEN 'PIONEER-' || UPPER(REPLACE(p_role, '_', '-')) || '-' || LPAD(v_next_number::TEXT, 3, '0') ELSE NULL END
  );

  RETURN QUERY SELECT v_next_number, v_tier.tier, v_tier.monthly_bonus;
END;
$$;


ALTER FUNCTION "public"."assign_pioneer"("p_member_id" "uuid", "p_role" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."assign_teacher_pioneer"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  next_pioneer INTEGER;
BEGIN
  SELECT COALESCE(MAX(pioneer_number), 0) + 1 INTO next_pioneer
  FROM teacher_profiles
  WHERE pioneer_number IS NOT NULL;

  IF next_pioneer <= 10 THEN
    NEW.pioneer_number := next_pioneer;
  END IF;
  RETURN NEW;
END;
$$;


