CREATE OR REPLACE FUNCTION "public"."attempt_dna_change"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF OLD.is_locked = true AND (
    NEW.parameter_value != OLD.parameter_value OR
    NEW.is_locked != OLD.is_locked
  ) THEN
    -- Log the attempt but REJECT it
    UPDATE public.dna_lock
    SET change_attempts = change_attempts + 1,
        last_change_attempt_at = NOW(),
        last_change_attempt_by = current_user
    WHERE id = OLD.id;

    RAISE EXCEPTION 'DNA LOCK VIOLATION: Parameter "%" is constitutionally locked and CANNOT be changed. This attempt has been logged.', OLD.parameter_key;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."attempt_dna_change"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."authorize_vault_sharing"("p_family_id" "uuid", "p_shared_with_member_id" "uuid" DEFAULT NULL::"uuid", "p_content_scope" "text" DEFAULT 'all'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_granter_member_id UUID;
    v_auth_id UUID;
BEGIN
    -- Get the granter's family member ID
    SELECT id INTO v_granter_member_id
    FROM family_members
    WHERE user_id = auth.uid() AND family_id = p_family_id AND is_active = true;

    IF v_granter_member_id IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'You are not a member of this family');
    END IF;

    -- Create or reactivate authorization
    INSERT INTO vault_sharing_authorizations (
        granter_member_id,
        granter_user_id,
        family_id,
        shared_with_member_id,
        content_scope,
        is_active,
        authorized_at
    ) VALUES (
        v_granter_member_id,
        auth.uid(),
        p_family_id,
        p_shared_with_member_id,
        p_content_scope,
        true,
        NOW()
    )
    ON CONFLICT (granter_member_id, family_id, shared_with_member_id, content_scope)
    DO UPDATE SET
        is_active = true,
        authorized_at = NOW(),
        revoked_at = NULL,
        revoked_reason = NULL,
        updated_at = NOW()
    RETURNING id INTO v_auth_id;

    RETURN jsonb_build_object(
        'success', true,
        'authorization_id', v_auth_id,
        'shared_with', CASE WHEN p_shared_with_member_id IS NULL THEN 'all_family' ELSE 'specific_member' END,
        'scope', p_content_scope
    );
END;
$$;


ALTER FUNCTION "public"."authorize_vault_sharing"("p_family_id" "uuid", "p_shared_with_member_id" "uuid", "p_content_scope" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."authorize_vault_sharing"("p_family_id" "uuid", "p_shared_with_member_id" "uuid", "p_content_scope" "text") IS 'Authorize your vault content to be shared with a specific member or all family. Returns authorization_id.';



CREATE OR REPLACE FUNCTION "public"."auto_graduate_gleaners"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_graduated INTEGER;
BEGIN
  WITH graduated AS (
    UPDATE user_credits
    SET
      is_gleaner = FALSE,
      graduated_from_gleaning_at = NOW()
    WHERE is_gleaner = TRUE
      AND gleaning_period_end IS NOT NULL
      AND gleaning_period_end < NOW()
    RETURNING user_id
  )
  SELECT COUNT(*) INTO v_graduated FROM graduated;

  RETURN v_graduated;
END;
$$;


