CREATE OR REPLACE FUNCTION "public"."award_early_taster_reward"("p_user_id" "uuid", "p_meal_id" "uuid") RETURNS TABLE("marks_awarded" integer, "reputation_awarded" integer, "badge_awarded" "text", "order_number" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_order_num INTEGER;
  v_marks INTEGER := 0;
  v_reputation INTEGER := 0;
  v_badge TEXT := NULL;
BEGIN
  -- Check if user already claimed for this meal
  IF EXISTS (SELECT 1 FROM pantry_early_taster_rewards WHERE user_id = p_user_id AND meal_id = p_meal_id) THEN
    RETURN QUERY SELECT 0, 0, NULL::TEXT, 0;
    RETURN;
  END IF;

  -- Atomically get and increment counter
  UPDATE pantry_taster_counter
  SET total_tasters = total_tasters + 1,
      early_rewards_remaining = GREATEST(0, early_rewards_remaining - 1),
      updated_at = NOW()
  WHERE id = 1 AND early_rewards_remaining > 0
  RETURNING total_tasters INTO v_order_num;

  IF v_order_num IS NULL THEN
    -- No more early rewards available
    RETURN QUERY SELECT 0, 0, NULL::TEXT, 0;
    RETURN;
  END IF;

  -- Calculate rewards based on tier
  IF v_order_num <= 100 THEN
    v_marks := 5;
    v_reputation := 10;
    IF v_order_num <= 10 THEN
      v_badge := 'taste_pioneer';
    END IF;
  ELSIF v_order_num <= 500 THEN
    v_marks := 3;
    v_reputation := 5;
    IF v_order_num <= 50 THEN
      v_badge := 'taste_enthusiast';
    END IF;
  ELSE
    v_marks := 1;
    v_reputation := 2;
    IF v_order_num <= 100 THEN
      v_badge := 'master_taster';
    END IF;
  END IF;

  -- Record the reward
  INSERT INTO pantry_early_taster_rewards (user_id, meal_id, order_number, marks_earned, reputation_earned, badge_earned)
  VALUES (p_user_id, p_meal_id, v_order_num, v_marks, v_reputation, v_badge);

  -- Award MARKS
  IF v_marks > 0 THEN
    INSERT INTO marks_transactions (user_id, amount, reason, reason_type)
    VALUES (p_user_id, v_marks, 'Early Taster reward (order #' || v_order_num || ')', 'early_taster');

    UPDATE user_marks
    SET total_marks = total_marks + v_marks
    WHERE user_id = p_user_id;
  END IF;

  RETURN QUERY SELECT v_marks, v_reputation, v_badge, v_order_num;
END;
$$;


ALTER FUNCTION "public"."award_early_taster_reward"("p_user_id" "uuid", "p_meal_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."award_joules"("_user_id" "uuid", "_credits_spent" numeric, "_multiplier" numeric, "_reason" "text", "_reason_type" "text", "_reference_id" "uuid" DEFAULT NULL::"uuid", "_reference_type" "text" DEFAULT NULL::"text") RETURNS numeric
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  joules_earned NUMERIC;
  new_total NUMERIC;
BEGIN
  joules_earned := _credits_spent * _multiplier;

  -- Upsert user_joules
  INSERT INTO public.user_joules (user_id, total_joules, total_locked_value)
  VALUES (_user_id, joules_earned, _credits_spent)
  ON CONFLICT (user_id) DO UPDATE
  SET total_joules = user_joules.total_joules + joules_earned,
      total_locked_value = user_joules.total_locked_value + _credits_spent,
      updated_at = NOW();

  SELECT total_joules INTO new_total FROM public.user_joules WHERE user_id = _user_id;

  INSERT INTO public.joules_transactions (user_id, joules_amount, credits_spent, multiplier_used, locked_value, reason, reason_type, reference_id, reference_type, balance_after)
  VALUES (_user_id, joules_earned, _credits_spent, _multiplier, _credits_spent, _reason, _reason_type, _reference_id, _reference_type, new_total);

  RETURN new_total;
END;
$$;


ALTER FUNCTION "public"."award_joules"("_user_id" "uuid", "_credits_spent" numeric, "_multiplier" numeric, "_reason" "text", "_reason_type" "text", "_reference_id" "uuid", "_reference_type" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."award_marks"("_user_id" "uuid", "_amount" numeric, "_reason" "text", "_reason_type" "text", "_reference_id" "uuid" DEFAULT NULL::"uuid", "_reference_type" "text" DEFAULT NULL::"text") RETURNS numeric
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  new_total NUMERIC;
BEGIN
  -- Upsert user_marks
  INSERT INTO public.user_marks (user_id, total_marks)
  VALUES (_user_id, _amount)
  ON CONFLICT (user_id) DO UPDATE
  SET total_marks = user_marks.total_marks + _amount,
      updated_at = NOW();

  -- Get new total
  SELECT total_marks INTO new_total FROM public.user_marks WHERE user_id = _user_id;

  -- Log transaction
  INSERT INTO public.marks_transactions (user_id, amount, reason, reason_type, reference_id, reference_type, balance_after)
  VALUES (_user_id, _amount, _reason, _reason_type, _reference_id, _reference_type, new_total);

  RETURN new_total;
END;
$$;


ALTER FUNCTION "public"."award_marks"("_user_id" "uuid", "_amount" numeric, "_reason" "text", "_reason_type" "text", "_reference_id" "uuid", "_reference_type" "text") OWNER TO "postgres";


