CREATE OR REPLACE FUNCTION "public"."award_recipe_shadow_marks"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  category_record RECORD;
  bounty_amount INTEGER;
BEGIN
  -- Find the category for this recipe
  SELECT * INTO category_record
  FROM pantry_categories
  WHERE cuisine ILIKE NEW.cuisine
    AND meal_type ILIKE NEW.meal_type
  LIMIT 1;

  IF category_record IS NOT NULL THEN
    -- Calculate bounty based on current count BEFORE this recipe
    -- Everyone posting at the same tier level gets the same reward
    bounty_amount := calculate_category_bounty(category_record.recipe_count);

    IF bounty_amount > 0 THEN
      -- Award shadow marks — same amount for everyone in this tier
      INSERT INTO shadow_marks (
        user_id,
        source_type,
        source_id,
        initial_amount,
        current_amount,
        votes_needed
      ) VALUES (
        NEW.creator_id,
        'recipe_bounty',
        NEW.id,
        bounty_amount,
        bounty_amount,
        CASE
          WHEN bounty_amount >= 50 THEN 10
          WHEN bounty_amount >= 30 THEN 7
          WHEN bounty_amount >= 15 THEN 5
          ELSE 3
        END
      );

      -- Update category count AFTER awarding (so next person in same tier still gets same amount)
      UPDATE pantry_categories
      SET recipe_count = recipe_count + 1,
          current_bounty_marks = calculate_category_bounty(recipe_count + 1),
          updated_at = NOW()
      WHERE id = category_record.id;
    END IF;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."award_recipe_shadow_marks"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."award_referral_bonus"("p_referrer_code" "text", "p_referred_user_id" "uuid", "p_source_platform" "text" DEFAULT NULL::"text", "p_source_content" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_referrer_id UUID;
  v_bonus_feathers INTEGER := 10; -- Base bonus
  v_result JSONB;
BEGIN
  -- Find referrer by code (first 8 chars of user_id)
  SELECT id INTO v_referrer_id
  FROM auth.users
  WHERE UPPER(LEFT(id::text, 8)) = UPPER(p_referrer_code)
  LIMIT 1;

  IF v_referrer_id IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Invalid referral code');
  END IF;

  -- Don't allow self-referral
  IF v_referrer_id = p_referred_user_id THEN
    RETURN jsonb_build_object('success', false, 'error', 'Cannot refer yourself');
  END IF;

  -- Check if already referred
  IF EXISTS (SELECT 1 FROM public.referral_tracking WHERE referred_user_id = p_referred_user_id) THEN
    RETURN jsonb_build_object('success', false, 'error', 'User already referred');
  END IF;

  -- Insert referral record
  INSERT INTO public.referral_tracking (
    referrer_id, referrer_code, referred_user_id,
    source_platform, source_content, bonus_awarded, bonus_feathers
  ) VALUES (
    v_referrer_id, p_referrer_code, p_referred_user_id,
    p_source_platform, p_source_content, true, v_bonus_feathers
  );

  -- Award feathers to referrer (if user_feathers table exists)
  UPDATE public.user_feathers
  SET total_feathers = total_feathers + v_bonus_feathers
  WHERE user_email = (SELECT email FROM auth.users WHERE id = v_referrer_id);

  RETURN jsonb_build_object(
    'success', true,
    'referrer_id', v_referrer_id,
    'bonus_feathers', v_bonus_feathers
  );
END;
$$;


ALTER FUNCTION "public"."award_referral_bonus"("p_referrer_code" "text", "p_referred_user_id" "uuid", "p_source_platform" "text", "p_source_content" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."award_template_marks"("p_attribution_id" "uuid") RETURNS numeric
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_attribution RECORD;
  v_total_marks DECIMAL := 0;
BEGIN
  SELECT * INTO v_attribution FROM public.template_attribution WHERE id = p_attribution_id;
  IF NOT FOUND THEN RETURN 0; END IF;

  v_total_marks := v_attribution.marks_for_selection;
  IF v_attribution.sent_at IS NOT NULL THEN v_total_marks := v_total_marks + 2; END IF;
  v_total_marks := v_total_marks + (v_attribution.clicks_generated * 0.1);
  v_total_marks := v_total_marks + v_attribution.conversions_generated;
  IF v_attribution.is_derivative THEN v_total_marks := v_total_marks + 5; END IF;

  UPDATE public.template_attribution
  SET
    marks_for_send = CASE WHEN sent_at IS NOT NULL THEN 2 ELSE 0 END,
    marks_for_clicks = clicks_generated * 0.1,
    marks_for_conversions = conversions_generated,
    marks_for_derivative = CASE WHEN is_derivative THEN 5 ELSE 0 END,
    total_marks_awarded = v_total_marks,
    marks_paid_at = NOW(),
    updated_at = NOW()
  WHERE id = p_attribution_id;

  RETURN v_total_marks;
END;
$$;


ALTER FUNCTION "public"."award_template_marks"("p_attribution_id" "uuid") OWNER TO "postgres";


