CREATE OR REPLACE FUNCTION "public"."calculate_category_bounty"("recipe_count" integer) RETURNS integer
    LANGUAGE "plpgsql" IMMUTABLE
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN CASE
    WHEN recipe_count = 0 THEN 50   -- Empty: "Be the first!"
    WHEN recipe_count < 5 THEN 30   -- Sparse: "Help fill the shelf"
    WHEN recipe_count < 10 THEN 15  -- Growing: "Add variety"
    WHEN recipe_count < 20 THEN 5   -- Established: Standard contribution
    ELSE 0                          -- Full: No scarcity bonus
  END;
END;
$$;


ALTER FUNCTION "public"."calculate_category_bounty"("recipe_count" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."calculate_chase_payouts"("p_chase_id" "uuid") RETURNS TABLE("user_id" "uuid", "payout" integer)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_chase wisp_chases%ROWTYPE;
  v_total_pot INTEGER;
  v_winner_pot INTEGER;
  v_winner_count INTEGER;
  v_position INTEGER;
  v_payout INTEGER;
  v_remaining_pot INTEGER;
BEGIN
  -- Get chase details
  SELECT * INTO v_chase FROM wisp_chases WHERE id = p_chase_id;

  IF v_chase.status != 'completed' THEN
    RAISE EXCEPTION 'Chase must be completed to calculate payouts';
  END IF;

  -- Calculate winner pot (after platform cut)
  v_total_pot := v_chase.total_pot;
  v_winner_pot := FLOOR(v_total_pot * (1 - v_chase.platform_cut));

  -- Count winners (top half of finishers)
  SELECT COUNT(*) INTO v_winner_count
  FROM wisp_chase_participants
  WHERE chase_id = p_chase_id
    AND status = 'finished'
    AND finish_position <= CEIL(v_chase.participant_count::DECIMAL / 2);

  IF v_winner_count = 0 THEN
    RETURN;
  END IF;

  -- Tiered payout: 1st gets more than 2nd, etc.
  -- Simple formula: (winner_count - position + 1) / sum(1..winner_count)
  v_remaining_pot := v_winner_pot;

  FOR v_position IN 1..v_winner_count LOOP
    -- Calculate this position's share
    v_payout := FLOOR(
      v_winner_pot * (v_winner_count - v_position + 1)::DECIMAL
      / ((v_winner_count * (v_winner_count + 1)) / 2)
    );

    -- Find user at this position
    RETURN QUERY
    SELECT p.user_id, v_payout
    FROM wisp_chase_participants p
    WHERE p.chase_id = p_chase_id
      AND p.finish_position = v_position;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."calculate_chase_payouts"("p_chase_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."calculate_cost_plus_20"("_gross_amount" numeric, "_transaction_type" "text", "_reference_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("creator_share" numeric, "platform_margin" numeric, "initiative_fund" numeric, "is_compliant" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  creator_pct NUMERIC;
  margin_pct NUMERIC;
  calc_creator NUMERIC;
  calc_margin NUMERIC;
  calc_initiative NUMERIC;
BEGIN
  -- Read from DNA Lock (logged)
  creator_pct := (SELECT public.read_dna_lock('CREATOR_SHARE_PERCENT'))::NUMERIC / 100;
  margin_pct := (SELECT public.read_dna_lock('PLATFORM_MARGIN_PERCENT'))::NUMERIC / 100;

  -- Calculate
  calc_creator := ROUND(_gross_amount * creator_pct, 2);
  calc_margin := _gross_amount - calc_creator;
  calc_initiative := ROUND(calc_margin * 0.5, 2);  -- half of margin to initiatives

  -- Log the calculation
  INSERT INTO public.pricing_calculations (
    transaction_type, reference_id, gross_amount,
    creator_share, platform_margin, cost_basis, margin_amount, initiative_fund
  ) VALUES (
    _transaction_type, _reference_id, _gross_amount,
    calc_creator, calc_margin, calc_margin / (1 + margin_pct), calc_margin, calc_initiative
  );

  RETURN QUERY SELECT calc_creator, calc_margin, calc_initiative, true;
END;
$$;


ALTER FUNCTION "public"."calculate_cost_plus_20"("_gross_amount" numeric, "_transaction_type" "text", "_reference_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."calculate_experiment_net_score"("p_experiment_id" "uuid") RETURNS numeric
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_net_score numeric := 0;
  v_effect RECORD;
BEGIN
  FOR v_effect IN
    SELECT
      factor_weight,
      delta_percent,
      confidence
    FROM public.vector_change_effects
    WHERE experiment_id = p_experiment_id
      AND computed_at = (
        SELECT MAX(computed_at)
        FROM public.vector_change_effects
        WHERE experiment_id = p_experiment_id
      )
  LOOP
    -- Weighted contribution: delta * weight * confidence
    v_net_score := v_net_score + (
      COALESCE(v_effect.delta_percent, 0) *
      COALESCE(v_effect.factor_weight, 1) *
      COALESCE(v_effect.confidence, 0.5)
    );
  END LOOP;

  RETURN v_net_score;
END;
$$;


ALTER FUNCTION "public"."calculate_experiment_net_score"("p_experiment_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."calculate_innovation_velocity"("p_period" "text" DEFAULT 'day'::"text") RETURNS TABLE("period_start" timestamp with time zone, "period_end" timestamp with time zone, "innovations_count" integer, "velocity" numeric)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    date_trunc(p_period, logged_at) as period_start,
    date_trunc(p_period, logged_at) + ('1 ' || p_period)::interval as period_end,
    count(*)::integer as innovations_count,
    count(*)::numeric /
      CASE p_period
        WHEN 'day' THEN 1
        WHEN 'week' THEN 7
        WHEN 'month' THEN 30
      END as velocity
  FROM innovation_log
  GROUP BY date_trunc(p_period, logged_at)
  ORDER BY period_start DESC;
END;
$$;


ALTER FUNCTION "public"."calculate_innovation_velocity"("p_period" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."calculate_platform_metrics"() RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  new_id UUID;
  period_start_date DATE;
  period_end_date DATE;
BEGIN
  period_end_date := CURRENT_DATE;
  period_start_date := period_end_date - INTERVAL '30 days';

  INSERT INTO platform_metrics (
    period_start,
    period_end,
    period_type,
    newcomers_this_period,
    total_members,
    active_members_30_day,
    total_transactions,
    calculated_by
  )
  SELECT
    period_start_date,
    period_end_date,
    'monthly',
    -- Newcomers this period
    COALESCE((
      SELECT COUNT(*) FROM auth.users
      WHERE created_at >= period_start_date
    ), 0),
    -- Total members
    COALESCE((SELECT COUNT(*) FROM auth.users), 0),
    -- Active in last 30 days (users with any activity)
    COALESCE((
      SELECT COUNT(DISTINCT user_id) FROM user_credits
      WHERE updated_at >= period_start_date
    ), 0),
    -- Total transactions (votes cast)
    COALESCE((SELECT SUM(used_credits) FROM user_credits), 0),
    'auto_calculate'
  RETURNING id INTO new_id;

  RETURN new_id;
END;
$$;


ALTER FUNCTION "public"."calculate_platform_metrics"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."calculate_production_level"("total_credits" integer) RETURNS integer
    LANGUAGE "plpgsql" IMMUTABLE
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF total_credits >= 10000 THEN RETURN 5;
  ELSIF total_credits >= 5000 THEN RETURN 4;
  ELSIF total_credits >= 1000 THEN RETURN 3;
  ELSIF total_credits >= 100 THEN RETURN 2;
  ELSIF total_credits >= 0 THEN RETURN 1;
  ELSE RETURN 0;
  END IF;
END;
$$;


ALTER FUNCTION "public"."calculate_production_level"("total_credits" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."calculate_proposal_order"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  existing_count int;
BEGIN
  SELECT COUNT(*) INTO existing_count
  FROM public.pioneer_proposals
  WHERE (
    (NEW.proposed_email IS NOT NULL AND proposed_email = NEW.proposed_email)
    OR
    (NEW.proposed_url IS NOT NULL AND proposed_url = NEW.proposed_url)
  )
  AND id != NEW.id;

  NEW.proposal_order := existing_count + 1;
  RETURN NEW;
END;
$$;


