CREATE OR REPLACE FUNCTION "public"."calculate_roommate_score"("p_agreement_id" "uuid") RETURNS numeric
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_agreement roommate_agreements%ROWTYPE;
  v_commitment_avg NUMERIC;
  v_followthrough NUMERIC;
  v_peer_avg NUMERIC;
  v_tenure_score NUMERIC;
  v_total_score NUMERIC;
BEGIN
  SELECT * INTO v_agreement FROM roommate_agreements WHERE id = p_agreement_id;
  IF NOT FOUND THEN RETURN NULL; END IF;

  -- 20%: Commitment level (average of all 5 categories)
  v_commitment_avg := (
    roommate_commitment_score(v_agreement.dishwashing_commitment) +
    roommate_commitment_score(v_agreement.garbage_removal_commitment) +
    roommate_commitment_score(v_agreement.kitchen_hygiene_commitment) +
    roommate_commitment_score(v_agreement.bathroom_hygiene_commitment) +
    roommate_commitment_score(v_agreement.common_area_commitment)
  ) / 5.0;

  -- 40%: Follow-through rate (clean_weeks / total_weeks)
  IF v_agreement.total_weeks > 0 THEN
    v_followthrough := (v_agreement.clean_weeks::NUMERIC / v_agreement.total_weeks) * 5.0;
  ELSE
    v_followthrough := 5.0;
  END IF;

  -- 25%: Peer reputation ratings (roommate_living type)
  SELECT COALESCE(AVG(rating), 5.0) INTO v_peer_avg
  FROM reputation_ratings
  WHERE subject_id = v_agreement.member_id
    AND interaction_type = 'roommate_living';

  -- 15%: Tenure bonus (caps at 5.0 after 52 weeks)
  v_tenure_score := LEAST(v_agreement.total_weeks / 52.0 * 5.0, 5.0);

  v_total_score := (v_commitment_avg * 0.20) +
                   (v_followthrough * 0.40) +
                   (v_peer_avg * 0.25) +
                   (v_tenure_score * 0.15);

  -- Clamp to 0-5
  v_total_score := GREATEST(LEAST(v_total_score, 5.0), 0.0);

  UPDATE roommate_agreements SET roommate_score = v_total_score, updated_at = now()
  WHERE id = p_agreement_id;

  RETURN v_total_score;
END;
$$;


ALTER FUNCTION "public"."calculate_roommate_score"("p_agreement_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."calculate_taste_tester_reward"("p_order_number" integer) RETURNS TABLE("marks" integer, "reputation" integer)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF p_order_number <= 100 THEN
    RETURN QUERY SELECT 5, 10;
  ELSIF p_order_number <= 500 THEN
    RETURN QUERY SELECT 3, 5;
  ELSIF p_order_number <= 2000 THEN
    RETURN QUERY SELECT 2, 3;
  ELSIF p_order_number <= 5000 THEN
    RETURN QUERY SELECT 1, 1;
  ELSE
    RETURN QUERY SELECT 0, 0;
  END IF;
END;
$$;


ALTER FUNCTION "public"."calculate_taste_tester_reward"("p_order_number" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."calculate_transparency_metrics"("p_period_type" "text" DEFAULT 'monthly'::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_new_id UUID;
  v_period_start DATE;
  v_period_end DATE;
  v_newcomers INTEGER;
  v_avg_time_to_first_hours NUMERIC;
  v_retention_rate NUMERIC;
  v_churn_rate NUMERIC;
  v_total_members INTEGER;
  v_active_members INTEGER;
  v_total_transactions NUMERIC;
  v_gleaning_distributed INTEGER;
  v_gleaning_earned INTEGER;
  v_gleaning_conversion NUMERIC;
  v_ghost_stats RECORD;
BEGIN
  -- Set period based on type
  v_period_end := CURRENT_DATE;

  CASE p_period_type
    WHEN 'daily' THEN v_period_start := v_period_end - INTERVAL '1 day';
    WHEN 'weekly' THEN v_period_start := v_period_end - INTERVAL '7 days';
    WHEN 'monthly' THEN v_period_start := v_period_end - INTERVAL '30 days';
    WHEN 'quarterly' THEN v_period_start := v_period_end - INTERVAL '90 days';
    WHEN 'annual' THEN v_period_start := v_period_end - INTERVAL '365 days';
    ELSE v_period_start := v_period_end - INTERVAL '30 days';
  END CASE;

  -- Count newcomers in period
  SELECT COUNT(*) INTO v_newcomers
  FROM profiles
  WHERE created_at >= v_period_start AND created_at < v_period_end;

  -- Calculate average time to first transaction (in hours)
  SELECT
    COALESCE(
      AVG(EXTRACT(EPOCH FROM (uc.first_transaction_at - p.created_at)) / 3600),
      0
    ) INTO v_avg_time_to_first_hours
  FROM user_credits uc
  JOIN profiles p ON p.id = uc.user_id
  WHERE p.created_at >= v_period_start
    AND p.created_at < v_period_end
    AND uc.first_transaction_at IS NOT NULL;

  -- Calculate 30-day retention
  SELECT
    CASE
      WHEN COUNT(*) = 0 THEN 0
      ELSE (
        COUNT(*) FILTER (WHERE last_active_at >= v_period_end - INTERVAL '30 days')::NUMERIC
        / COUNT(*)::NUMERIC * 100
      )
    END INTO v_retention_rate
  FROM profiles
  WHERE created_at < v_period_end - INTERVAL '30 days';

  v_churn_rate := 100 - COALESCE(v_retention_rate, 0);

  -- Total members
  SELECT COUNT(*) INTO v_total_members FROM profiles;

  -- Active members
  SELECT COUNT(*) INTO v_active_members
  FROM profiles
  WHERE last_active_at >= v_period_end - INTERVAL '30 days';

  -- Total transactions
  SELECT COALESCE(SUM(used_credits), 0) INTO v_total_transactions
  FROM user_credits;

  -- Gleaning metrics
  SELECT
    COALESCE(SUM(gleaning_credits_received), 0),
    COALESCE(SUM(gleaning_credits_earned), 0)
  INTO v_gleaning_distributed, v_gleaning_earned
  FROM user_credits
  WHERE is_gleaner = TRUE OR gleaning_credits_received > 0;

  -- Gleaning conversion rate
  SELECT
    CASE
      WHEN COUNT(*) FILTER (WHERE is_gleaner = TRUE OR gleaning_credits_received > 0) = 0 THEN 0
      ELSE (
        COUNT(*) FILTER (WHERE graduated_from_gleaning_at IS NOT NULL)::NUMERIC
        / NULLIF(COUNT(*) FILTER (WHERE is_gleaner = TRUE OR gleaning_credits_received > 0), 0)::NUMERIC * 100
      )
    END INTO v_gleaning_conversion
  FROM user_credits;

  -- Get ghost credit stats
  SELECT * INTO v_ghost_stats FROM get_ghost_credit_stats();

  -- Insert the metrics
  INSERT INTO platform_metrics (
    period_start,
    period_end,
    period_type,
    newcomers_this_period,
    avg_time_to_first_transaction_hours,
    newcomer_30_day_retention,
    newcomer_churn_rate,
    gleaning_credits_distributed,
    gleaning_credits_earned_through_work,
    gleaning_conversion_rate,
    total_members,
    active_members_30_day,
    total_transactions,
    ghost_credits_total_distributed,
    ghost_credits_total_used,
    ghost_credits_conversion_rate,
    active_gleaners_count,
    calculated_by,
    is_published
  ) VALUES (
    v_period_start,
    v_period_end,
    p_period_type,
    v_newcomers,
    v_avg_time_to_first_hours,
    v_retention_rate,
    v_churn_rate,
    v_gleaning_distributed,
    v_gleaning_earned,
    v_gleaning_conversion,
    v_total_members,
    v_active_members,
    v_total_transactions,
    v_ghost_stats.total_distributed,
    v_ghost_stats.total_used,
    v_ghost_stats.avg_usage_rate,
    v_ghost_stats.active_gleaners,
    'auto_calculate',
    TRUE
  )
  RETURNING id INTO v_new_id;

  RETURN v_new_id;
END;
$$;


ALTER FUNCTION "public"."calculate_transparency_metrics"("p_period_type" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."calculate_transparency_metrics"("p_period_type" "text") IS 'Main function to calculate and store platform transparency metrics';



CREATE OR REPLACE FUNCTION "public"."calculate_vote_multiplier"("p_user_id" "uuid", "p_initiative_id" "text") RETURNS numeric
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_multiplier DECIMAL := 1.0;
  v_timing DECIMAL := 1.0;
  v_mark DECIMAL := 1.0;
  v_golden_key DECIMAL := 1.0;
  v_first_100 DECIMAL := 1.0;
BEGIN
  -- Get golden key multiplier
  SELECT COALESCE(current_multiplier, 1.0) INTO v_golden_key
  FROM golden_key_multipliers WHERE user_id = p_user_id;

  -- Check if first 100 voter on this initiative
  SELECT CASE WHEN COUNT(*) < 100 THEN 1.5 ELSE 1.0 END INTO v_first_100
  FROM initiative_votes WHERE initiative_id = p_initiative_id;

  -- TODO: Add timing multiplier based on production level
  -- TODO: Add mark level multiplier based on user mark

  -- Calculate compound multiplier (max 562.5x theoretical)
  v_multiplier := v_timing * v_mark * v_golden_key * v_first_100;

  RETURN LEAST(v_multiplier, 562.5);  -- Cap at theoretical max
END;
$$;


ALTER FUNCTION "public"."calculate_vote_multiplier"("p_user_id" "uuid", "p_initiative_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."can_sponsor"("p_user_id" "uuid", "p_amount" numeric) RETURNS boolean
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
    user_credits DECIMAL;
BEGIN
    -- Get user's available credits
    SELECT COALESCE(credits, 0) INTO user_credits
    FROM user_balances
    WHERE user_id = p_user_id;

    -- Must have at least 25 credits AND the amount they want to sponsor
    RETURN user_credits >= 25 AND user_credits >= p_amount;
END;
$$;


ALTER FUNCTION "public"."can_sponsor"("p_user_id" "uuid", "p_amount" numeric) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."cast_votes"("p_donor_vote_id" "uuid", "p_gift_request_id" "uuid", "p_votes" integer) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  available_votes INTEGER;
BEGIN
  SELECT votes_remaining INTO available_votes
  FROM donor_votes WHERE id = p_donor_vote_id;

  IF available_votes IS NULL OR available_votes < p_votes THEN
    RETURN FALSE;
  END IF;

  INSERT INTO vote_allocations (donor_vote_id, gift_request_id, votes_cast)
  VALUES (p_donor_vote_id, p_gift_request_id, p_votes)
  ON CONFLICT (donor_vote_id, gift_request_id)
  DO UPDATE SET votes_cast = vote_allocations.votes_cast + p_votes;

  UPDATE donor_votes
  SET votes_used = votes_used + p_votes
  WHERE id = p_donor_vote_id;

  UPDATE gift_requests
  SET votes_received = votes_received + p_votes,
      funding_progress = LEAST(100, ((votes_received + p_votes)::DECIMAL / votes_needed) * 100),
      status = CASE
        WHEN (votes_received + p_votes) >= votes_needed AND status = 'voting' THEN 'funded'
        WHEN status = 'approved' THEN 'voting'
        ELSE status
      END,
      funded_at = CASE
        WHEN (votes_received + p_votes) >= votes_needed AND funded_at IS NULL THEN NOW()
        ELSE funded_at
      END,
      updated_at = NOW()
  WHERE id = p_gift_request_id;

  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."cast_votes"("p_donor_vote_id" "uuid", "p_gift_request_id" "uuid", "p_votes" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_aggregation_threshold"("window_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_window RECORD;
BEGIN
  SELECT * INTO v_window
  FROM demand_aggregation_windows
  WHERE id = window_id;

  IF v_window.status != 'collecting' THEN
    RETURN false;
  END IF;

  -- Check thresholds
  IF v_window.participant_count >= v_window.min_participants
     AND v_window.total_estimated_value >= v_window.min_value THEN

    UPDATE demand_aggregation_windows SET
      status = 'threshold_met',
      threshold_met_at = now(),
      updated_at = now()
    WHERE id = window_id;

    -- Calculate volume discount
    UPDATE demand_aggregation_windows SET
      volume_discount_percent = CASE
        WHEN total_estimated_value >= 200 THEN 15
        WHEN total_estimated_value >= 100 THEN 10
        WHEN total_estimated_value >= 50 THEN 5
        ELSE 0
      END
    WHERE id = window_id;

    -- Generate aggregated shopping list
    PERFORM generate_aggregated_shopping_list(window_id);

    RETURN true;
  END IF;

  RETURN false;
END;
$$;


ALTER FUNCTION "public"."check_aggregation_threshold"("window_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."check_aggregation_threshold"("window_id" "uuid") IS 'Checks if window has met threshold for job creation';



CREATE OR REPLACE FUNCTION "public"."check_and_award_crow_feather"("p_user_id" "uuid", "p_username" "text", "p_category" "text", "p_time_bracket" "text", "p_record_value" numeric, "p_session_duration_minutes" integer) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_existing_record RECORD;
  v_feather_id INTEGER;
BEGIN
  -- Check if there's an existing record for this category/bracket
  SELECT * INTO v_existing_record
  FROM ghost_leaderboard
  WHERE category = p_category AND time_bracket = p_time_bracket;

  -- For labyrinth_speed, lower is better; for everything else, higher is better
  IF v_existing_record IS NULL OR
     (p_category = 'labyrinth_speed' AND p_record_value < v_existing_record.record_value) OR
     (p_category != 'labyrinth_speed' AND p_record_value > v_existing_record.record_value) THEN

    -- Award new crow feather
    INSERT INTO crow_feathers (user_id, category, record_value, session_duration_minutes, time_bracket)
    VALUES (p_user_id, p_category, p_record_value, p_session_duration_minutes, p_time_bracket)
    RETURNING id INTO v_feather_id;

    -- Mark old feather as superseded
    IF v_existing_record IS NOT NULL AND v_existing_record.crow_feather_id IS NOT NULL THEN
      UPDATE crow_feathers SET superseded_by = v_feather_id
      WHERE id = v_existing_record.crow_feather_id;
    END IF;

    -- Update or insert leaderboard entry
    INSERT INTO ghost_leaderboard (category, time_bracket, user_id, username, record_value, session_duration_minutes, crow_feather_id)
    VALUES (p_category, p_time_bracket, p_user_id, p_username, p_record_value, p_session_duration_minutes, v_feather_id)
    ON CONFLICT (category, time_bracket)
    DO UPDATE SET
      user_id = EXCLUDED.user_id,
      username = EXCLUDED.username,
      record_value = EXCLUDED.record_value,
      session_duration_minutes = EXCLUDED.session_duration_minutes,
      achieved_at = NOW(),
      crow_feather_id = EXCLUDED.crow_feather_id;

    RETURN v_feather_id;
  END IF;

  RETURN NULL;
END;
$$;


ALTER FUNCTION "public"."check_and_award_crow_feather"("p_user_id" "uuid", "p_username" "text", "p_category" "text", "p_time_bracket" "text", "p_record_value" numeric, "p_session_duration_minutes" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_arena_battle_trigger"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  approved_count INT;
  new_battle_id UUID;
BEGIN
  IF NEW.status = 'approved' AND (OLD IS NULL OR OLD.status != 'approved') THEN
    SELECT COUNT(*) INTO approved_count
    FROM arena_submissions
    WHERE category = NEW.category
      AND status = 'approved'
      AND battle_id IS NULL
      AND created_at > now() - INTERVAL '7 days';

    IF approved_count >= 2 THEN
      new_battle_id := gen_random_uuid();

      INSERT INTO design_battles (
        id, bounty_id, bounty_title, status, skill_tier, timeframe,
        starts_at, ends_at, total_pot, platform_cut, net_pot,
        winner_payout, participant_count, community_votes
      ) VALUES (
        new_battle_id,
        'arena_' || NEW.category,
        'Design Battle: ' || initcap(replace(NEW.category, '_', ' ')),
        'voting',
        'journeyman',
        '2weeks',
        now(),
        now() + INTERVAL '48 hours',
        0, 0, 0, 0, 0, 0
      );

      UPDATE arena_submissions
      SET battle_id = new_battle_id, status = 'in_battle'
      WHERE category = NEW.category
        AND status = 'approved'
        AND battle_id IS NULL
        AND created_at > now() - INTERVAL '7 days';
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


