CREATE OR REPLACE FUNCTION "public"."check_free_daily_access"("p_user_id" "uuid", "p_device_fingerprint" "text", "p_ip_hash" "text", "p_feature_type" "text") RETURNS TABLE("can_access" boolean, "is_member" boolean, "uses_today" integer, "daily_limit" integer, "remaining_uses" integer, "upgrade_message" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
DECLARE
    v_is_member BOOLEAN := FALSE;
    v_uses_today INTEGER := 0;
    v_daily_limit INTEGER := 1;
    v_member_limit INTEGER;
    v_cta_text TEXT;
BEGIN
    -- Check if user is a paid member
    IF p_user_id IS NOT NULL THEN
        SELECT EXISTS (
            SELECT 1 FROM public.profiles
            WHERE id = p_user_id
            AND is_active = TRUE
            AND (membership_expires_at IS NULL OR membership_expires_at > now())
        ) INTO v_is_member;
    END IF;

    -- Get limits for this feature
    SELECT
        l.free_daily_limit,
        l.member_daily_limit,
        l.cta_text
    INTO v_daily_limit, v_member_limit, v_cta_text
    FROM public.free_daily_limits l
    WHERE l.feature_type = p_feature_type
    AND l.is_active = TRUE;

    -- Default if not configured
    IF v_daily_limit IS NULL THEN
        v_daily_limit := 1;
    END IF;

    -- Members get unlimited (or member_limit if set)
    IF v_is_member THEN
        IF v_member_limit IS NULL THEN
            -- Unlimited
            RETURN QUERY SELECT
                TRUE::BOOLEAN,
                TRUE::BOOLEAN,
                0::INTEGER,
                -1::INTEGER, -- -1 indicates unlimited
                -1::INTEGER,
                NULL::TEXT;
            RETURN;
        ELSE
            v_daily_limit := v_member_limit;
        END IF;
    END IF;

    -- Count today's usage
    SELECT COALESCE(SUM(usage_count), 0)::INTEGER INTO v_uses_today
    FROM public.free_daily_usage
    WHERE usage_date = CURRENT_DATE
    AND feature_type = p_feature_type
    AND (
        (p_user_id IS NOT NULL AND user_id = p_user_id)
        OR (p_device_fingerprint IS NOT NULL AND device_fingerprint = p_device_fingerprint)
        OR (p_ip_hash IS NOT NULL AND ip_hash = p_ip_hash)
    );

    -- Return access status
    RETURN QUERY SELECT
        (v_uses_today < v_daily_limit)::BOOLEAN,
        v_is_member,
        v_uses_today,
        v_daily_limit,
        GREATEST(0, v_daily_limit - v_uses_today)::INTEGER,
        CASE WHEN v_uses_today >= v_daily_limit
             THEN COALESCE(v_cta_text, 'Get unlimited access for $5/year')
             ELSE NULL
        END;
END;
$_$;


ALTER FUNCTION "public"."check_free_daily_access"("p_user_id" "uuid", "p_device_fingerprint" "text", "p_ip_hash" "text", "p_feature_type" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."check_free_daily_access"("p_user_id" "uuid", "p_device_fingerprint" "text", "p_ip_hash" "text", "p_feature_type" "text") IS 'Check if a user can access a feature with free daily limits.
Returns can_access, is_member, uses_today, daily_limit, remaining_uses, upgrade_message.';



CREATE OR REPLACE FUNCTION "public"."check_harper_eligibility"("p_user_id" "uuid") RETURNS TABLE("eligible" boolean, "reason" "text", "has_builder" boolean, "tenure_months" integer, "reputation" numeric, "violations" integer)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_has_builder BOOLEAN;
  v_tenure INTEGER;
  v_reputation DECIMAL;
  v_violations INTEGER;
  v_eligible BOOLEAN;
  v_reason TEXT;
BEGIN
  -- Check builder status (from medallion collection)
  SELECT EXISTS(
    SELECT 1 FROM member_medallion_collection
    WHERE user_id = p_user_id
    AND chalk_one_type IN ('builder', 'prime')
  ) INTO v_has_builder;

  -- Calculate tenure (months since account creation)
  SELECT EXTRACT(MONTH FROM AGE(NOW(), created_at))::INTEGER
  FROM profiles WHERE id = p_user_id
  INTO v_tenure;

  -- Get reputation score (placeholder - would come from ratings system)
  v_reputation := 4.8; -- Default for now

  -- Count violations
  v_violations := 0; -- Would come from trust ladder system

  -- Determine eligibility
  IF NOT v_has_builder THEN
    v_eligible := false;
    v_reason := 'Must have Chalk One Builder status';
  ELSIF v_tenure < 6 THEN
    v_eligible := false;
    v_reason := 'Must have 6+ months tenure (current: ' || v_tenure || ')';
  ELSIF v_reputation < 4.5 THEN
    v_eligible := false;
    v_reason := 'Must have 4.5+ reputation (current: ' || v_reputation || ')';
  ELSIF v_violations > 0 THEN
    v_eligible := false;
    v_reason := 'Must have zero trust ladder violations';
  ELSE
    v_eligible := true;
    v_reason := 'Eligible for Harper credentialing';
  END IF;

  RETURN QUERY SELECT v_eligible, v_reason, v_has_builder, v_tenure, v_reputation, v_violations;
END;
$$;


ALTER FUNCTION "public"."check_harper_eligibility"("p_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_invite_approval"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    invite_record RECORD;
    total_votes INT;
    approve_votes INT;
BEGIN
    SELECT * INTO invite_record FROM family_invites WHERE id = NEW.invite_id;

    SELECT COUNT(*), COUNT(*) FILTER (WHERE vote = true)
    INTO total_votes, approve_votes FROM family_invite_votes WHERE invite_id = NEW.invite_id;

    UPDATE family_invites SET votes_received = approve_votes WHERE id = NEW.invite_id;

    IF NEW.vote = false THEN
        UPDATE family_invites SET status = 'rejected', resolved_at = NOW() WHERE id = NEW.invite_id;
    ELSIF approve_votes >= invite_record.votes_needed THEN
        UPDATE family_invites SET status = 'approved', resolved_at = NOW() WHERE id = NEW.invite_id;
    END IF;

    RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."check_invite_approval"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_master_taster_conversion"("p_user_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_successful_recipes INTEGER;
  v_marks_to_convert INTEGER;
BEGIN
  -- Count recipes that reached 5K that this user tested
  SELECT COUNT(*) INTO v_successful_recipes
  FROM taste_tester_records
  WHERE user_id = p_user_id
  AND recipe_reached_5k = true;

  -- If 10+ successful, convert marks to credits
  IF v_successful_recipes >= 10 THEN
    -- Get current marks balance
    SELECT current_marks_balance INTO v_marks_to_convert
    FROM user_taste_tester_stats
    WHERE user_id = p_user_id;

    IF v_marks_to_convert > 0 THEN
      -- Update stats
      UPDATE user_taste_tester_stats SET
        current_marks_balance = 0,
        total_marks_converted = total_marks_converted + v_marks_to_convert,
        total_credits_from_conversion = total_credits_from_conversion + v_marks_to_convert,
        is_master_taster = true,
        master_taster_achieved_at = COALESCE(master_taster_achieved_at, now()),
        updated_at = now()
      WHERE user_id = p_user_id;

      -- TODO: Add credits to user's account
      -- This would integrate with the credits system

      RETURN true;
    END IF;
  END IF;

  RETURN false;
END;
$$;


ALTER FUNCTION "public"."check_master_taster_conversion"("p_user_id" "uuid") OWNER TO "postgres";


