                SELECT EXISTS(SELECT 1 FROM vault_unlocks vu JOIN vault_family_mapping vfm ON vu.person = vfm.vault_person WHERE vfm.family_member_id = p_member_a AND vfm.family_id = p_family_id) INTO v_a_unlocked;
                SELECT EXISTS(SELECT 1 FROM vault_unlocks vu JOIN vault_family_mapping vfm ON vu.person = vfm.vault_person WHERE vfm.family_member_id = p_member_b AND vfm.family_id = p_family_id) INTO v_b_unlocked;
                RETURN v_a_unlocked AND v_b_unlocked;
            END IF;
            RETURN false;
        END;
        $$;


