CREATE OR REPLACE FUNCTION "public"."check_research_storage_quota"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_subscription RECORD;
  v_total_used INTEGER;
BEGIN
  -- Get subscription
  SELECT * INTO v_subscription
  FROM public.research_subscriptions
  WHERE id = NEW.subscription_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Subscription not found';
  END IF;

  -- Calculate total storage used
  SELECT COALESCE(SUM(size_bytes), 0) / (1024 * 1024) INTO v_total_used
  FROM public.research_reports
  WHERE subscription_id = NEW.subscription_id
    AND NOT is_archived;

  -- Check quota
  IF v_total_used + (NEW.size_bytes / (1024 * 1024)) > v_subscription.storage_quota_mb THEN
    RAISE EXCEPTION 'Storage quota exceeded. Used: % MB, Quota: % MB',
      v_total_used, v_subscription.storage_quota_mb;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."check_research_storage_quota"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_shadow_medallions"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  medallion RECORD;
  criteria_met boolean;
BEGIN
  FOR medallion IN SELECT * FROM shadow_medallions LOOP
    -- Check if already earned
    IF NOT EXISTS (
      SELECT 1 FROM ghost_medallion_awards
      WHERE ghost_id = NEW.id AND medallion_id = medallion.id
    ) THEN
      -- Check criteria (simplified - would need more complex logic in production)
      criteria_met := false;

      IF medallion.id = 'explorer' AND NEW.pages_visited >= 5 THEN criteria_met := true;
      ELSIF medallion.id = 'scholar' AND NEW.documents_read >= 3 THEN criteria_met := true;
      ELSIF medallion.id = 'pioneer' AND NEW.created_at < '2026-03-01' THEN criteria_met := true;
      ELSIF medallion.id = 'seeker' AND NEW.golden_keys_found >= 1 THEN criteria_met := true;
      ELSIF medallion.id = 'persistent' AND NEW.total_session_time_minutes >= 30 THEN criteria_met := true;
      END IF;

      IF criteria_met THEN
        INSERT INTO ghost_medallion_awards (ghost_id, medallion_id)
        VALUES (NEW.id, medallion.id)
        ON CONFLICT DO NOTHING;
      END IF;
    END IF;
  END LOOP;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."check_shadow_medallions"() OWNER TO "postgres";


