CREATE OR REPLACE FUNCTION "public"."check_sponsor_badge"("p_user_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
    total_sponsored DECIMAL;
    people_count INTEGER;
    max_depth INTEGER;
BEGIN
    -- Calculate total sponsored
    SELECT
        COALESCE(SUM(credit_amount), 0),
        COUNT(DISTINCT recipient_id)
    INTO total_sponsored, people_count
    FROM sponsorships
    WHERE sponsor_id = p_user_id
    AND status IN ('active', 'split');

    -- Calculate cascade depth
    SELECT COALESCE(MAX(depth), 0) INTO max_depth
    FROM sponsorship_cascade_view
    WHERE sponsor_id = p_user_id;

    -- Award badge if >= 5000
    IF total_sponsored >= 5000 THEN
        INSERT INTO sponsor_badges (user_id, total_sponsored, people_sponsored, cascade_depth)
        VALUES (p_user_id, total_sponsored, people_count, max_depth)
        ON CONFLICT (user_id) DO UPDATE
        SET total_sponsored = EXCLUDED.total_sponsored,
            people_sponsored = EXCLUDED.people_sponsored,
            cascade_depth = EXCLUDED.cascade_depth;
    END IF;
END;
$$;


ALTER FUNCTION "public"."check_sponsor_badge"("p_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_swoop_activation"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_initiative RECORD;
    v_new_total INTEGER;
BEGIN
    -- Get current initiative state
    SELECT * INTO v_initiative
    FROM swoop_initiatives
    WHERE id = NEW.initiative_id;

    -- Calculate new total
    v_new_total := v_initiative.current_votes + NEW.credit_amount;

    -- Update initiative total
    UPDATE swoop_initiatives
    SET
        current_votes = v_new_total,
        updated_at = NOW()
    WHERE id = NEW.initiative_id;

    -- Check if threshold reached
    IF v_new_total >= v_initiative.threshold AND v_initiative.status = 'waiting' THEN
        -- Activate the initiative
        UPDATE swoop_initiatives
        SET
            status = 'active',
            activation_date = NOW(),
            updated_at = NOW()
        WHERE id = NEW.initiative_id;

        -- Update all votes to 'activated'
        UPDATE swoop_votes
        SET vote_status = 'activated'
        WHERE initiative_id = NEW.initiative_id
        AND vote_status = 'pledged';

        -- Log activation
        INSERT INTO swoop_activation_log (
            initiative_id,
            action,
            triggered_by,
            vote_count_at_action,
            notes
        ) VALUES (
            NEW.initiative_id,
            'activated',
            NEW.user_id,
            v_new_total,
            'Threshold reached via vote'
        );

        RAISE NOTICE 'Initiative % activated with % votes', v_initiative.initiative_name, v_new_total;
    END IF;

    RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."check_swoop_activation"() OWNER TO "postgres";


