CREATE OR REPLACE FUNCTION "public"."check_treasure_milestones"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  winner_count INTEGER;
  milestones INTEGER[] := ARRAY[1, 10, 25, 50, 75, 90, 95, 99, 100];
  m INTEGER;
BEGIN
  SELECT COUNT(*) INTO winner_count FROM treasure_winners;

  FOREACH m IN ARRAY milestones LOOP
    IF winner_count >= m THEN
      -- Check if we already logged this milestone
      IF NOT EXISTS (SELECT 1 FROM treasure_milestones WHERE milestone = m) THEN
        INSERT INTO treasure_milestones (milestone) VALUES (m);

        INSERT INTO automation_log (action, details)
        VALUES ('milestone_reached', jsonb_build_object(
          'milestone', m,
          'total_winners', winner_count
        ));
      END IF;
    END IF;
  END LOOP;
END;
$$;


