CREATE OR REPLACE FUNCTION "public"."claim_from_general_pool"("claiming_user_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  pool_record RECORD;
  new_recipient_id UUID;
BEGIN
  -- Find an active pool with available medallions
  SELECT * INTO pool_record
  FROM sponsor_general_pool
  WHERE status = 'active' AND medallions_available > 0
  ORDER BY created_at
  LIMIT 1
  FOR UPDATE;

  IF pool_record IS NULL THEN
    RETURN NULL;
  END IF;

  -- Create recipient record
  INSERT INTO sponsored_recipients (sponsor_id, recipient_id, source_pool_id, distribution_mode)
  VALUES (pool_record.sponsor_id, claiming_user_id, pool_record.id, 'pool')
  RETURNING id INTO new_recipient_id;

  -- Update pool counts
  UPDATE sponsor_general_pool
  SET
    medallions_available = medallions_available - 1,
    medallions_claimed = medallions_claimed + 1,
    status = CASE WHEN medallions_available - 1 = 0 THEN 'exhausted' ELSE status END
  WHERE id = pool_record.id;

  RETURN new_recipient_id;
END;
$$;


ALTER FUNCTION "public"."claim_from_general_pool"("claiming_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."claim_gift_item"("p_item_id" "uuid", "p_member_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_item RECORD;
    v_list RECORD;
    v_is_owner BOOLEAN;
BEGIN
    -- Get the item
    SELECT * INTO v_item FROM gift_list_items WHERE id = p_item_id;
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'Item not found');
    END IF;

    -- Check if already claimed
    IF v_item.claimed_by IS NOT NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'Item already claimed');
    END IF;

    -- Get the list
    SELECT * INTO v_list FROM family_gift_lists WHERE id = v_item.list_id;

    -- Check if claimer is the owner (can't claim your own items!)
    SELECT EXISTS(
        SELECT 1 FROM family_members fm
        WHERE fm.id = p_member_id
        AND fm.id = v_list.owner_id
    ) INTO v_is_owner;

    IF v_is_owner THEN
        RETURN jsonb_build_object('success', false, 'error', 'Cannot claim your own items');
    END IF;

    -- Claim the item
    UPDATE gift_list_items
    SET claimed_by = p_member_id,
        claimed_at = NOW(),
        quantity_claimed = quantity_claimed + 1,
        updated_at = NOW()
    WHERE id = p_item_id;

    -- Record in history
    INSERT INTO gift_claim_history (item_id, member_id, action)
    VALUES (p_item_id, p_member_id, 'claim');

    RETURN jsonb_build_object('success', true, 'message', 'Item claimed successfully');
END;
$$;


ALTER FUNCTION "public"."claim_gift_item"("p_item_id" "uuid", "p_member_id" "uuid") OWNER TO "postgres";


