CREATE OR REPLACE FUNCTION "public"."cleanup_old_research_reports"("p_subscription_id" "uuid") RETURNS integer
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_subscription RECORD;
  v_deleted INTEGER := 0;
BEGIN
  SELECT * INTO v_subscription
  FROM public.research_subscriptions
  WHERE id = p_subscription_id;

  IF NOT FOUND THEN
    RETURN 0;
  END IF;

  -- Delete oldest reports beyond max_stored_reports
  WITH to_delete AS (
    SELECT id
    FROM public.research_reports
    WHERE subscription_id = p_subscription_id
      AND retain_until IS NULL -- Only auto-delete non-retained
    ORDER BY generated_at DESC
    OFFSET v_subscription.max_stored_reports
  )
  DELETE FROM public.research_reports
  WHERE id IN (SELECT id FROM to_delete);

  GET DIAGNOSTICS v_deleted = ROW_COUNT;
  RETURN v_deleted;
END;
$$;


ALTER FUNCTION "public"."cleanup_old_research_reports"("p_subscription_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."complete_delivery"("p_recipient_id" "uuid", "p_photo_url" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_job_id UUID;
  v_all_delivered BOOLEAN;
BEGIN
  -- Update recipient
  UPDATE grocery_delivery_recipients SET
    status = 'delivered',
    delivered_at = now(),
    delivery_photo_url = p_photo_url
  WHERE id = p_recipient_id
  RETURNING job_id INTO v_job_id;

  -- Check if all recipients delivered
  SELECT NOT EXISTS (
    SELECT 1 FROM grocery_delivery_recipients
    WHERE job_id = v_job_id AND status != 'delivered'
  ) INTO v_all_delivered;

  -- Update job if all done
  IF v_all_delivered THEN
    UPDATE grocery_delivery_jobs SET
      status = 'completed',
      completed_at = now(),
      updated_at = now()
    WHERE id = v_job_id;

    -- Update worker stats
    UPDATE delivery_worker_stats SET
      total_jobs_completed = total_jobs_completed + 1,
      last_job_at = now(),
      updated_at = now()
    WHERE user_id = (SELECT worker_id FROM grocery_delivery_jobs WHERE id = v_job_id);
  END IF;

  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."complete_delivery"("p_recipient_id" "uuid", "p_photo_url" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."complete_delivery"("p_recipient_id" "uuid", "p_photo_url" "text") IS 'Marks a delivery as complete and updates job status';



CREATE OR REPLACE FUNCTION "public"."complete_design_battle"("p_battle_id" "uuid") RETURNS TABLE("winner_user_id" "uuid", "winner_payout" numeric, "crow_feather_awarded" boolean)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_winner RECORD;
    v_total_ante DECIMAL;
    v_community_votes INTEGER;
    v_gross_pot DECIMAL;
    v_platform_cut DECIMAL;
    v_net_pot DECIMAL;
    v_winner_share DECIMAL;
    v_runner_up_share DECIMAL;
    v_participant_count INTEGER;
BEGIN
    -- Get winner (highest vote count)
    SELECT * INTO v_winner
    FROM design_battle_participants
    WHERE battle_id = p_battle_id
    ORDER BY vote_count DESC
    LIMIT 1;

    IF v_winner IS NULL THEN
        RETURN;
    END IF;

    -- Calculate pot
    SELECT
        COALESCE(SUM(ante_credit_equivalent), 0),
        COUNT(*)
    INTO v_total_ante, v_participant_count
    FROM design_battle_participants
    WHERE battle_id = p_battle_id;

    SELECT community_votes INTO v_community_votes
    FROM design_battles
    WHERE id = p_battle_id;

    v_gross_pot := v_total_ante + COALESCE(v_community_votes, 0);
    v_platform_cut := ROUND(v_gross_pot * 0.167, 2);
    v_net_pot := v_gross_pot - v_platform_cut;
    v_winner_share := ROUND(v_net_pot * 0.50, 2);
    v_runner_up_share := ROUND((v_net_pot - v_winner_share) / GREATEST(v_participant_count - 1, 1), 2);

    -- Update winner
    UPDATE design_battle_participants
    SET rank = 1, payout = v_winner_share, crow_feather_earned = TRUE
    WHERE id = v_winner.id;

    -- Update runner-ups
    UPDATE design_battle_participants
    SET rank = 2, payout = v_runner_up_share, crow_feather_earned = FALSE
    WHERE battle_id = p_battle_id AND id != v_winner.id;

    -- Update battle
    UPDATE design_battles
    SET
        status = 'completed',
        winner_id = v_winner.user_id,
        total_pot = v_gross_pot,
        platform_cut = v_platform_cut,
        net_pot = v_net_pot,
        winner_payout = v_winner_share,
        updated_at = NOW()
    WHERE id = p_battle_id;

    -- Award crow feather
    INSERT INTO crow_feathers (user_id, category, record_value, metadata)
    VALUES (
        v_winner.user_id,
        'design_battle',
        v_winner_share,
        jsonb_build_object('battle_id', p_battle_id)
    );

    RETURN QUERY SELECT v_winner.user_id, v_winner_share, TRUE;
END;
$$;


ALTER FUNCTION "public"."complete_design_battle"("p_battle_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."complete_design_battle"("p_battle_id" "uuid") IS 'Finalizes battle, calculates payouts, awards crow feathers';



CREATE OR REPLACE FUNCTION "public"."complete_harper_audit"("p_audit_id" "uuid", "p_result" "text", "p_grade" integer, "p_summary" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_auditor_id UUID;
  v_node_id UUID;
BEGIN
  -- Get audit details
  SELECT auditor_id, node_id INTO v_auditor_id, v_node_id
  FROM harper_audits WHERE id = p_audit_id;

  -- Update audit record
  UPDATE harper_audits SET
    status = 'completed',
    completed_at = NOW(),
    result = p_result,
    excellence_grade = p_grade,
    findings_summary = p_summary,
    audit_hash = encode(sha256(
      (p_audit_id::text || p_result || p_grade::text || NOW()::text)::bytea
    ), 'hex'),
    updated_at = NOW()
  WHERE id = p_audit_id;

  -- Update auditor stats
  UPDATE harper_auditors SET
    total_audits_completed = total_audits_completed + 1,
    audits_passed = CASE WHEN p_result = 'pass' THEN audits_passed + 1 ELSE audits_passed END,
    audits_failed = CASE WHEN p_result = 'fail' THEN audits_failed + 1 ELSE audits_failed END,
    last_audit_date = NOW(),
    last_audit_node_id = v_node_id,
    updated_at = NOW()
  WHERE id = v_auditor_id;

  -- Update node schedule based on result
  UPDATE harper_audit_schedules SET
    last_audit_id = p_audit_id,
    node_rating = CASE
      WHEN p_result = 'fail' THEN 'flagged'
      WHEN p_grade >= 4 AND node_rating = 'new' THEN 'verified'
      WHEN p_grade >= 4 AND node_rating = 'verified' THEN 'established'
      WHEN p_grade = 5 AND node_rating = 'established' THEN 'veteran'
      ELSE node_rating
    END,
    audit_frequency_days = CASE
      WHEN p_result = 'fail' THEN 30  -- Monthly for flagged
      WHEN node_rating = 'new' THEN 30
      WHEN node_rating = 'verified' THEN 90
      WHEN node_rating = 'established' THEN 180
      WHEN node_rating = 'veteran' THEN 365
      ELSE audit_frequency_days
    END,
    next_scheduled_audit = NOW() + (audit_frequency_days || ' days')::interval,
    updated_at = NOW()
  WHERE node_id = v_node_id;

  RETURN true;
END;
$$;


ALTER FUNCTION "public"."complete_harper_audit"("p_audit_id" "uuid", "p_result" "text", "p_grade" integer, "p_summary" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."complete_hexisle_quest"("p_user_id" "uuid", "p_quest_id" "uuid") RETURNS boolean
