CREATE OR REPLACE FUNCTION "public"."compute_outreach_letter_verdict"("p_letter_id" "uuid") RETURNS TABLE("total_votes" integer, "approve_count" integer, "veto_count" integer, "approval_pct" numeric, "veto_pct" numeric, "verdict" "text", "next_action" "text")
    LANGUAGE "plpgsql" STABLE
    AS $$
DECLARE
  v_letter outreach_letters%ROWTYPE;
  v_total INTEGER;
  v_approve INTEGER;
  v_veto INTEGER;
  v_approval_pct NUMERIC;
  v_veto_pct NUMERIC;
  v_verdict TEXT;
  v_next_action TEXT;
BEGIN
  SELECT * INTO v_letter FROM outreach_letters WHERE letter_id = p_letter_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'letter not found';
  END IF;

  SELECT COUNT(*),
         COUNT(*) FILTER (WHERE vote_type = 'approve'),
         COUNT(*) FILTER (WHERE vote_type = 'veto')
    INTO v_total, v_approve, v_veto
    FROM outreach_letter_votes
    WHERE letter_id = p_letter_id;

  IF v_total = 0 THEN
    v_approval_pct := 0;
    v_veto_pct := 0;
    v_verdict := 'no_votes';
    v_next_action := 'awaiting_votes';
  ELSE
    v_approval_pct := (v_approve::NUMERIC / v_total) * 100;
    v_veto_pct := (v_veto::NUMERIC / v_total) * 100;

    IF v_veto_pct >= v_letter.vote_threshold_veto_pct THEN
      v_verdict := 'vetoed';
      v_next_action := 'block_dispatch';
    ELSIF v_approval_pct >= v_letter.vote_threshold_approval_pct THEN
      v_verdict := 'approved';
      v_next_action := 'authorize_dispatch';
    ELSE
      v_verdict := 'pending';
      v_next_action := 'awaiting_more_votes';
    END IF;
  END IF;

  RETURN QUERY SELECT v_total, v_approve, v_veto, v_approval_pct, v_veto_pct, v_verdict, v_next_action;
END;
$$;


ALTER FUNCTION "public"."compute_outreach_letter_verdict"("p_letter_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."convert_ghost_to_member"("p_email" "text", "p_user_id" "uuid") RETURNS TABLE("credits_earned" integer, "marks_earned" integer, "shares_made" integer, "conversions_made" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_record RECORD;
BEGIN
  -- Find the ghost record
  SELECT * INTO v_record
  FROM public.ghost_share_tracking
  WHERE email = p_email AND status = 'active'
  ORDER BY created_at DESC
  LIMIT 1;

  IF v_record IS NULL THEN
    RETURN QUERY SELECT 0, 0, 0, 0;
    RETURN;
  END IF;

  -- Mark as converted
  UPDATE public.ghost_share_tracking
  SET
    status = 'converted',
    converted_user_id = p_user_id,
    converted_at = now(),
    updated_at = now()
  WHERE id = v_record.id;

  -- Return the rewards to apply
  RETURN QUERY SELECT
    v_record.pending_credits,
    v_record.pending_marks,
    v_record.share_count,
    v_record.conversion_count;
END;
$$;


