    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_order_id UUID;
  v_eoi RECORD;
BEGIN
  -- Get EOI details
  SELECT * INTO v_eoi FROM expressions_of_interest WHERE id = p_eoi_id;

  IF v_eoi IS NULL THEN
    RAISE EXCEPTION 'Expression of interest not found';
  END IF;

  -- Create order
  INSERT INTO orders (buyer_id, order_type, status)
  VALUES (v_eoi.user_id, 'product', 'pending')
  RETURNING id INTO v_order_id;

  -- Update EOI
  UPDATE expressions_of_interest SET
    converted = true,
    converted_at = NOW(),
    conversion_order_id = v_order_id
  WHERE id = p_eoi_id;

  RETURN v_order_id;
END;
$$;


