CREATE OR REPLACE FUNCTION "public"."create_delivery_job_from_window"("p_window_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_window RECORD;
  v_area RECORD;
  v_job_id UUID;
BEGIN
  -- Get window details
  SELECT * INTO v_window FROM delivery_aggregation_windows WHERE id = p_window_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Aggregation window not found';
  END IF;

  -- Get area details
  SELECT * INTO v_area FROM micro_local_areas WHERE id = v_window.micro_local_area_id;

  -- Create job
  INSERT INTO grocery_delivery_jobs (
    micro_local_area,
    pickup_location,
    shopping_list_ids,
    total_order_value,
    delivery_fee,
    status
  ) VALUES (
    v_area.area_code,
    v_area.name, -- Pickup location TBD
    v_window.shopping_list_ids,
    v_window.total_value,
    v_area.base_delivery_fee,
    'posted'
  ) RETURNING id INTO v_job_id;

  -- Update window
  UPDATE delivery_aggregation_windows SET
    job_id = v_job_id,
    job_created_at = now(),
    status = 'job_created'
  WHERE id = p_window_id;

  RETURN v_job_id;
END;
$$;


