CREATE OR REPLACE FUNCTION "public"."create_design_battle_on_overlap"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
    signup_count INTEGER;
    existing_battle UUID;
    new_battle_id UUID;
    bounty_record RECORD;
BEGIN
    -- Count active signups for this bounty
    SELECT COUNT(*) INTO signup_count
    FROM bounty_signups
    WHERE bounty_id = NEW.bounty_id
    AND status = 'active';

    -- If 2+ signups, check if battle already exists
    IF signup_count >= 2 THEN
        SELECT id INTO existing_battle
        FROM design_battles
        WHERE bounty_id = NEW.bounty_id
        AND status IN ('pending', 'active');

        -- If no battle exists, create one
        IF existing_battle IS NULL THEN
            -- Get bounty details (assumes bounties table exists)
            -- If not, use placeholder values
            BEGIN
                SELECT title, skill_tier, timeframe INTO bounty_record
                FROM bounties
                WHERE id = NEW.bounty_id;
            EXCEPTION WHEN OTHERS THEN
                bounty_record.title := 'Bounty ' || NEW.bounty_id::TEXT;
                bounty_record.skill_tier := 'journeyman';
                bounty_record.timeframe := '1week';
            END;

            -- Create the Design Battle
            INSERT INTO design_battles (
                bounty_id,
                bounty_title,
                status,
                skill_tier,
                timeframe,
                starts_at,
                ends_at
            ) VALUES (
                NEW.bounty_id,
                COALESCE(bounty_record.title, 'Bounty ' || NEW.bounty_id::TEXT),
                'pending',
                COALESCE(bounty_record.skill_tier, 'journeyman'),
                COALESCE(bounty_record.timeframe, '1week'),
                NOW(),
                NOW() + INTERVAL '1 week' -- Default, will be updated based on timeframe
            )
            RETURNING id INTO new_battle_id;

            -- Update all active signups to converted_to_battle
            UPDATE bounty_signups
            SET status = 'converted_to_battle'
            WHERE bounty_id = NEW.bounty_id
            AND status = 'active';

            -- Log the auto-creation
            RAISE NOTICE 'Design Battle % created for bounty % with % participants',
                new_battle_id, NEW.bounty_id, signup_count;
        END IF;
    END IF;

    RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."create_design_battle_on_overlap"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."create_design_battle_on_overlap"() IS 'Auto-creates Design Battle when 2+ people sign up for same bounty';



CREATE OR REPLACE FUNCTION "public"."create_donor_votes"("p_stripe_session_id" "text", "p_donor_email" "text", "p_donation_id" "uuid", "p_tier" "text", "p_amount" numeric) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  votes_earned INTEGER;
  donor_vote_id UUID;
BEGIN
  votes_earned := CASE p_tier
    WHEN 'spark' THEN 5
    WHEN 'kindle' THEN 10
    WHEN 'flame' THEN 25
    WHEN 'blaze' THEN 50
    WHEN 'inferno' THEN 100
    WHEN 'full_sponsor' THEN 350
    ELSE GREATEST(1, FLOOR(p_amount)::INTEGER)
  END;

  INSERT INTO donor_votes (stripe_session_id, donor_email, donation_id, total_votes)
  VALUES (p_stripe_session_id, p_donor_email, p_donation_id, votes_earned)
  ON CONFLICT DO NOTHING
  RETURNING id INTO donor_vote_id;

  RETURN donor_vote_id;
END;
$$;


