CREATE OR REPLACE FUNCTION "public"."create_experiment_snapshot"("p_experiment_id" "uuid", "p_notes" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_snapshot_id uuid;
  v_snapshot_number integer;
  v_net_score numeric;
  v_effects_summary jsonb;
BEGIN
  -- Get next snapshot number
  SELECT COALESCE(MAX(snapshot_number), 0) + 1 INTO v_snapshot_number
  FROM public.experiment_snapshots
  WHERE experiment_id = p_experiment_id;

  -- Calculate current net score
  v_net_score := public.calculate_experiment_net_score(p_experiment_id);

  -- Get effects summary
  SELECT jsonb_agg(
    jsonb_build_object(
      'factor', factor_name,
      'delta_percent', delta_percent,
      'direction', direction,
      'confidence', confidence
    )
  ) INTO v_effects_summary
  FROM public.vector_change_effects
  WHERE experiment_id = p_experiment_id
    AND computed_at = (
      SELECT MAX(computed_at)
      FROM public.vector_change_effects
      WHERE experiment_id = p_experiment_id
    );

  -- Create snapshot
  INSERT INTO public.experiment_snapshots (
    experiment_id,
    snapshot_number,
    net_score,
    vector_effects_summary,
    notes
  )
  VALUES (
    p_experiment_id,
    v_snapshot_number,
    v_net_score,
    COALESCE(v_effects_summary, '[]'::jsonb),
    p_notes
  )
  RETURNING id INTO v_snapshot_id;

  -- Update experiment current score
  UPDATE public.thought_experiments
  SET
    current_net_score = v_net_score,
    last_computed_at = now(),
    updated_at = now()
  WHERE id = p_experiment_id;

  RETURN v_snapshot_id;
END;
$$;


ALTER FUNCTION "public"."create_experiment_snapshot"("p_experiment_id" "uuid", "p_notes" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_gift_occasion_event"("p_gift_list_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_list RECORD;
    v_calendar_id UUID;
    v_event_id UUID;
    v_member_name TEXT;
BEGIN
    -- Get the gift list
    SELECT gl.*, fm.nickname INTO v_list
    FROM family_gift_lists gl
    JOIN family_members fm ON gl.owner_id = fm.id
    WHERE gl.id = p_gift_list_id;

    IF v_list.occasion_date IS NULL THEN
        RETURN NULL;
    END IF;

    -- Get default family calendar
    SELECT id INTO v_calendar_id
    FROM family_calendars
    WHERE family_id = v_list.family_id AND is_default = true
    LIMIT 1;

    IF v_calendar_id IS NULL THEN
        RETURN NULL;
    END IF;

    -- Create the event
    INSERT INTO family_events (
        calendar_id,
        title,
        event_type,
        start_time,
        all_day,
        source,
        source_id
    ) VALUES (
        v_calendar_id,
        v_list.nickname || '''s ' || COALESCE(v_list.occasion, 'Gift Day'),
        CASE v_list.occasion
            WHEN 'birthday' THEN 'birthday'
            WHEN 'anniversary' THEN 'anniversary'
            WHEN 'holiday' THEN 'holiday'
            ELSE 'custom'
        END,
        v_list.occasion_date::timestamp,
        true,
        'gift_occasion',
        p_gift_list_id
    ) RETURNING id INTO v_event_id;

    RETURN v_event_id;
END;
$$;


ALTER FUNCTION "public"."create_gift_occasion_event"("p_gift_list_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_gift_shopping_aggregation"("p_gift_item_id" "uuid", "p_family_member_id" "uuid", "p_shopping_date" "date", "p_shopping_time" time without time zone DEFAULT NULL::time without time zone) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_item RECORD;
    v_list RECORD;
    v_agg_id UUID;
BEGIN
    -- Get the gift item
    SELECT * INTO v_item FROM gift_list_items WHERE id = p_gift_item_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Gift item not found';
    END IF;

    -- Get the list for family_id
    SELECT * INTO v_list FROM family_gift_lists WHERE id = v_item.list_id;

    -- Create the aggregation
    INSERT INTO gift_shopping_aggregations (
        gift_item_id,
        family_id,
        product_name,
        product_url,
        product_price,
        quantity_needed,
        shopping_date,
        shopping_time,
        window_closes_at,
        created_by
    ) VALUES (
        p_gift_item_id,
        v_list.family_id,
        v_item.name,
        v_item.url,
        v_item.price_estimate,
        v_item.quantity_wanted,
        p_shopping_date,
        p_shopping_time,
        (p_shopping_date::timestamp + COALESCE(p_shopping_time, '12:00'::time) - INTERVAL '2 hours')::timestamptz,
        p_family_member_id
    ) RETURNING id INTO v_agg_id;

    -- Add creator as first participant
    INSERT INTO gift_shopping_participants (aggregation_id, family_member_id, for_gift_item_id)
    VALUES (v_agg_id, p_family_member_id, p_gift_item_id);

    -- Create calendar event
    PERFORM create_shopping_calendar_event(v_agg_id);

    RETURN v_agg_id;
END;
$$;


ALTER FUNCTION "public"."create_gift_shopping_aggregation"("p_gift_item_id" "uuid", "p_family_member_id" "uuid", "p_shopping_date" "date", "p_shopping_time" time without time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_job_from_aggregation"("window_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_window RECORD;
  v_job_id UUID;
BEGIN
  SELECT * INTO v_window
  FROM demand_aggregation_windows
  WHERE id = window_id;

  IF v_window.status != 'threshold_met' THEN
    RAISE EXCEPTION 'Window not ready for job creation';
  END IF;

  -- Create delivery job
  INSERT INTO grocery_delivery_jobs (
    status,
    pickup_store,
    total_items,
    estimated_total,
    recipient_count,
    estimated_duration_minutes,
    notes
  ) VALUES (
    'open',
    'TBD', -- Worker will choose store
    v_window.total_items,
    v_window.total_estimated_value,
    v_window.participant_count,
    30 + (v_window.participant_count * 10), -- Rough estimate
    'Aggregated order from ' || v_window.participant_count || ' households'
  )
  RETURNING id INTO v_job_id;

  -- Link window to job
  UPDATE demand_aggregation_windows SET
    status = 'job_created',
    delivery_job_id = v_job_id,
    updated_at = now()
  WHERE id = window_id;

  -- Notify participants (in production, would trigger notification)
  UPDATE aggregation_participants SET
    notified_of_aggregation = true,
    notified_at = now(),
    response_deadline = now() + interval '2 hours'
  WHERE aggregation_window_id = window_id
    AND status = 'auto_included';

  RETURN v_job_id;
END;
$$;


ALTER FUNCTION "public"."create_job_from_aggregation"("window_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_meal_plan_events"("p_family_id" "uuid", "p_meal_plan_id" "uuid", "p_meal_date" "date", "p_meal_slot" "text", "p_meal_title" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_calendar_id UUID;
    v_event_id UUID;
    v_start_time TIMESTAMPTZ;
BEGIN
    -- Get default family calendar
    SELECT id INTO v_calendar_id
    FROM family_calendars
    WHERE family_id = p_family_id AND is_default = true
    LIMIT 1;

    -- If no default, get first calendar
    IF v_calendar_id IS NULL THEN
        SELECT id INTO v_calendar_id
        FROM family_calendars
        WHERE family_id = p_family_id
        LIMIT 1;
    END IF;

    -- If still no calendar, can't create event
    IF v_calendar_id IS NULL THEN
        RETURN NULL;
    END IF;

    -- Determine start time based on slot
    v_start_time := p_meal_date::timestamp + CASE p_meal_slot
        WHEN 'breakfast' THEN INTERVAL '8 hours'
        WHEN 'lunch' THEN INTERVAL '12 hours'
        WHEN 'dinner' THEN INTERVAL '18 hours'
        ELSE INTERVAL '12 hours'
    END;

    -- Create the event
    INSERT INTO family_events (
        calendar_id, title, event_type, start_time, end_time,
        source, source_id
    ) VALUES (
        v_calendar_id,
        p_meal_title,
        'meal',
        v_start_time,
        v_start_time + INTERVAL '1 hour',
        'meal_plan',
        p_meal_plan_id
    ) RETURNING id INTO v_event_id;

    RETURN v_event_id;
END;
$$;


ALTER FUNCTION "public"."create_meal_plan_events"("p_family_id" "uuid", "p_meal_plan_id" "uuid", "p_meal_date" "date", "p_meal_slot" "text", "p_meal_title" "text") OWNER TO "postgres";


