CREATE OR REPLACE FUNCTION "public"."decay_shadow_marks"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  decayed_count INTEGER := 0;
BEGIN
  -- Decay marks that are past their decay start
  UPDATE shadow_marks
  SET current_amount = GREATEST(
        current_amount - FLOOR(initial_amount * decay_rate),
        crystallized_amount
      ),
      last_decay_at = NOW(),
      status = CASE
        WHEN current_amount - FLOOR(initial_amount * decay_rate) <= crystallized_amount
        THEN 'expired'
        ELSE status
      END
  WHERE status IN ('vesting', 'partial')
    AND created_at + (decay_start_days || ' days')::INTERVAL < NOW()
    AND (last_decay_at IS NULL OR
         last_decay_at + (decay_interval_days || ' days')::INTERVAL < NOW());

  GET DIAGNOSTICS decayed_count = ROW_COUNT;

  -- Expire fully decayed marks
  UPDATE shadow_marks
  SET status = 'expired'
  WHERE status IN ('vesting', 'partial')
    AND expires_at < NOW();

  RETURN decayed_count;
END;
$$;


ALTER FUNCTION "public"."decay_shadow_marks"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."detect_work_bursts"("p_session_id" "text", "p_gap_threshold_minutes" integer DEFAULT 30) RETURNS TABLE("burst_number" integer, "burst_start" timestamp with time zone, "burst_end" timestamp with time zone, "items_in_burst" integer, "burst_duration_minutes" integer)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  WITH ordered_versions AS (
    SELECT
      created_at,
      LAG(created_at) OVER (ORDER BY created_at) as prev_created_at
    FROM content_versions
    WHERE session_id = p_session_id
  ),
  burst_starts AS (
    SELECT
      created_at,
      CASE
        WHEN prev_created_at IS NULL
          OR created_at - prev_created_at > (p_gap_threshold_minutes || ' minutes')::interval
        THEN 1 ELSE 0
      END as is_burst_start
    FROM ordered_versions
  ),
  burst_groups AS (
    SELECT
      created_at,
      SUM(is_burst_start) OVER (ORDER BY created_at) as burst_group
    FROM burst_starts
  )
  SELECT
    burst_group::integer as burst_number,
    MIN(created_at) as burst_start,
    MAX(created_at) as burst_end,
    COUNT(*)::integer as items_in_burst,
    EXTRACT(EPOCH FROM (MAX(created_at) - MIN(created_at)) / 60)::integer as burst_duration_minutes
  FROM burst_groups
  GROUP BY burst_group
  ORDER BY burst_number;
END;
$$;


ALTER FUNCTION "public"."detect_work_bursts"("p_session_id" "text", "p_gap_threshold_minutes" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."draw_from_pool"("commitment_id" "uuid", "draw_amount" numeric) RETURNS boolean
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  commitment RECORD;
BEGIN
  SELECT * INTO commitment FROM donation_commitments WHERE id = commitment_id;

  IF commitment.status != 'active' OR commitment.type != 'pool' THEN
    RETURN FALSE;
  END IF;

  IF commitment.remaining_pool < draw_amount THEN
    RETURN FALSE;
  END IF;

  UPDATE donation_commitments
  SET remaining_pool = remaining_pool - draw_amount,
      total_donated = total_donated + draw_amount,
      donation_count = donation_count + 1,
      last_donation_date = NOW(),
      status = CASE WHEN remaining_pool - draw_amount <= 0 THEN 'exhausted' ELSE 'active' END,
      updated_at = NOW()
  WHERE id = commitment_id;

  RETURN TRUE;
END;
$$;


