CREATE OR REPLACE FUNCTION "public"."find_matching_locale_pool"("user_city" "text", "user_state" "text", "user_country" "text") RETURNS TABLE("pool_id" "uuid", "sponsor_id" "uuid", "medallions_available" integer)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    p.id AS pool_id,
    p.sponsor_id,
    p.medallions_available
  FROM sponsor_locale_pools p
  WHERE p.status = 'active'
    AND p.medallions_available > 0
    AND (
      p.target_country = user_country
      OR (p.target_state = user_state AND p.target_country = user_country)
      OR (p.target_city = user_city AND p.target_state = user_state AND p.target_country = user_country)
    )
  ORDER BY
    -- Most specific match first
    CASE
      WHEN p.target_city = user_city THEN 1
      WHEN p.target_state = user_state THEN 2
      ELSE 3
    END,
    p.created_at
  LIMIT 1;
END;
$$;


