CREATE OR REPLACE FUNCTION "public"."fn_onboarding_credit_order_tick"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Only fire when payment status transitions to 'paid'
  IF NEW.stripe_payment_status = 'paid'
     AND (OLD IS NULL OR OLD.stripe_payment_status IS DISTINCT FROM 'paid') THEN

    -- Set first_order_date if not yet set
    UPDATE onboarding_credits
    SET first_order_date = CURRENT_DATE
    WHERE storefront_id = NEW.storefront_id
      AND first_order_date IS NULL
      AND is_active = true;

    -- Increment orders_count
    UPDATE onboarding_credits
    SET orders_count = orders_count + 1
    WHERE storefront_id = NEW.storefront_id
      AND is_active = true
      AND is_qualified = false;

    -- Auto-qualify: 10+ orders AND 30+ days since first order
    UPDATE onboarding_credits
    SET is_qualified = true,
        qualification_date = CURRENT_DATE
    WHERE storefront_id = NEW.storefront_id
      AND is_active = true
      AND is_qualified = false
      AND orders_count >= 10
      AND first_order_date IS NOT NULL
      AND (CURRENT_DATE - first_order_date) >= 30;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_onboarding_credit_order_tick"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."force_release_escrow"("p_escrow_id" "uuid", "p_admin_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_owner UUID;
  v_project_title TEXT;
  v_amount INTEGER;
  v_project UUID;
BEGIN
  SELECT p.owner_id, p.title, pel.amount_cents, pel.project_id
  INTO v_owner, v_project_title, v_amount, v_project
  FROM project_escrow_ledger pel
  JOIN projects p ON p.id = pel.project_id
  WHERE pel.id = p_escrow_id AND pel.status = 'held';

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Escrow % not found or not held', p_escrow_id;
  END IF;

  UPDATE project_escrow_ledger
  SET status = 'released',
      released_at = now(),
      released_to = v_owner,
      notes = COALESCE(notes, '') || ' | Force-released by admin ' || p_admin_id::TEXT
  WHERE id = p_escrow_id;

  INSERT INTO notifications (user_id, type, title, body, metadata)
  VALUES (
    v_owner, 'escrow_released', 'Funds Released',
    'Escrow for ' || COALESCE(v_project_title, 'your project') || ' was manually released by admin',
    jsonb_build_object('project_id', v_project, 'amount_cents', v_amount, 'escrow_id', p_escrow_id)
  );
END;
$$;


