CREATE OR REPLACE FUNCTION "public"."get_ghost_credit_stats"() RETURNS TABLE("total_distributed" bigint, "total_used" bigint, "total_converted_to_real" bigint, "active_gleaners" integer, "graduated_gleaners" integer, "avg_usage_rate" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    COALESCE(SUM(gleaning_credits_received), 0)::BIGINT AS total_distributed,
    COALESCE(SUM(eoi_used_credits), 0)::BIGINT AS total_used,
    COALESCE(SUM(
      CASE WHEN graduated_from_gleaning_at IS NOT NULL
      THEN gleaning_credits_earned ELSE 0 END
    ), 0)::BIGINT AS total_converted_to_real,
    COUNT(*) FILTER (WHERE is_gleaner = true)::INTEGER AS active_gleaners,
    COUNT(*) FILTER (WHERE graduated_from_gleaning_at IS NOT NULL)::INTEGER AS graduated_gleaners,
    CASE
      WHEN SUM(gleaning_credits_received) > 0
      THEN (SUM(COALESCE(eoi_used_credits, 0))::NUMERIC / SUM(gleaning_credits_received)::NUMERIC * 100)
      ELSE 0
    END AS avg_usage_rate
  FROM user_credits
  WHERE gleaning_credits_received > 0 OR eoi_credits > 0;
END;
$$;


ALTER FUNCTION "public"."get_ghost_credit_stats"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_ghost_credit_stats"() IS 'Returns ghost credit usage statistics for transparency dashboard';



