      THEN (ha.audits_passed::decimal / ha.total_audits_completed * 100)
      ELSE 0
    END AS pass_rate,
    ha.expertise_domains
  FROM harper_auditors ha
  WHERE ha.user_id = p_user_id
    AND ha.credential_status = 'active';
END;
