CREATE OR REPLACE FUNCTION "public"."get_seedling_counter"("sponsor_id_param" "uuid") RETURNS TABLE("seeds_planted" integer, "seeds_sprouted" integer, "network_growth_percent" numeric, "total_projects_completed" integer, "total_earnings" numeric)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    COUNT(sr.id)::INTEGER AS seeds_planted,
    COUNT(sr.id) FILTER (WHERE sr.recipient_id IS NOT NULL)::INTEGER AS seeds_sprouted,
    CASE
      WHEN COUNT(sr.id) > 0
      THEN (COUNT(sr.id) FILTER (WHERE sr.recipient_id IS NOT NULL)::NUMERIC / COUNT(sr.id)::NUMERIC) * 100
      ELSE 0
    END AS network_growth_percent,
    COALESCE(SUM(
      (SELECT COUNT(*) FROM project_completions pc WHERE pc.user_id = sr.recipient_id)
    ), 0)::INTEGER AS total_projects_completed,
    COALESCE(SUM(
      (SELECT COALESCE(SUM(amount), 0) FROM medallion_payouts mp WHERE mp.user_id = sr.recipient_id)
    ), 0)::NUMERIC AS total_earnings
  FROM sponsored_recipients sr
  WHERE sr.sponsor_id = sponsor_id_param;
END;
$$;


