CREATE OR REPLACE FUNCTION "public"."get_shared_vault_content"("p_family_id" "uuid") RETURNS TABLE("content_id" "uuid", "content_type" "text", "title" "text", "description" "text", "file_url" "text", "thumbnail_url" "text", "content_text" "text", "photo_urls" "text"[], "original_date" timestamp with time zone, "location" "text", "tags" "text"[], "shared_by_member_id" "uuid", "shared_by_name" "text", "shared_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        vsc.id AS content_id,
        vsc.content_type,
        vsc.title,
        vsc.description,
        vsc.file_url,
        vsc.thumbnail_url,
        vsc.content_text,
        vsc.photo_urls,
        vsc.original_date,
        vsc.location,
        vsc.tags,
        vsa.granter_member_id AS shared_by_member_id,
        fm.nickname AS shared_by_name,
        vsa.authorized_at AS shared_at
    FROM vault_shared_content vsc
    JOIN vault_sharing_authorizations vsa ON vsc.authorization_id = vsa.id
    JOIN family_members fm ON vsa.granter_member_id = fm.id
    WHERE vsa.family_id = p_family_id
    AND vsa.is_active = true
    AND (
        -- Specific to this user
        vsa.shared_with_member_id IN (
            SELECT id FROM family_members WHERE user_id = auth.uid()
        )
        -- OR shared with all family
        OR vsa.shared_with_member_id IS NULL
    )
    ORDER BY vsc.created_at DESC;
END;
$$;


