CREATE OR REPLACE FUNCTION "public"."graduate_from_gleaning"("p_user_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  UPDATE user_credits
  SET
    is_gleaner = FALSE,
    graduated_from_gleaning_at = NOW()
  WHERE user_id = p_user_id AND is_gleaner = TRUE;

  -- Log the activity
  INSERT INTO user_activity_log (user_id, activity_type, activity_value, metadata)
  VALUES (
    p_user_id,
    'gleaning_graduated',
    0,
    jsonb_build_object('graduated_at', NOW())
  );

  RETURN TRUE;
END;
$$;


