CREATE OR REPLACE FUNCTION "public"."grant_battery_dispatch_from_row"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_source TEXT := COALESCE(TG_ARGV[0], '');
  v_payload JSONB := to_jsonb(NEW);
  v_user_id UUID;
  v_ref_id TEXT;
  v_status TEXT;
  v_bool_active BOOLEAN;
BEGIN
  v_user_id := COALESCE(
    NULLIF(v_payload->>'user_id', '')::UUID,
    NULLIF(v_payload->>'owner_id', '')::UUID,
    NULLIF(v_payload->>'holder_user_id', '')::UUID,
    NULLIF(v_payload->>'captain_user_id', '')::UUID
  );
  v_ref_id := COALESCE(
    v_payload->>'id',
    v_payload->>'project_id',
    v_payload->>'initiative_id'
  );
  v_status := lower(
    COALESCE(
      v_payload->>'status',
      v_payload->>'harper_status',
      v_payload->>'crown_status'
    )
  );
  v_bool_active := COALESCE((v_payload->>'is_active')::BOOLEAN, true);

  IF v_user_id IS NULL THEN
    RETURN NEW;
  END IF;

  IF v_source = 'project' THEN
    PERFORM public.upsert_battery_dispatch_grant(v_user_id, 'project', v_ref_id, 'active', 'Auto-granted from project path');
    RETURN NEW;
  END IF;

  IF v_source = 'crown' THEN
    IF v_status IS NULL OR v_status IN ('active', 'accepted', 'offered') THEN
      PERFORM public.upsert_battery_dispatch_grant(v_user_id, 'crown', v_ref_id, 'active', 'Auto-granted from crown path');
    END IF;
    RETURN NEW;
  END IF;

  IF v_source = 'captain' THEN
    IF v_status IS NULL OR v_status NOT IN ('revoked', 'resigned', 'inactive') THEN
      PERFORM public.upsert_battery_dispatch_grant(v_user_id, 'captain', v_ref_id, 'active', 'Auto-granted from captain path');
    END IF;
    RETURN NEW;
  END IF;

  IF v_source = 'harper' THEN
    IF v_status IN ('cub_harper', 'stamped_harper', 'harper', 'master_harper', 'active') THEN
      PERFORM public.upsert_battery_dispatch_grant(v_user_id, 'harper', v_ref_id, 'active', 'Auto-granted from Harper Guild path');
    END IF;
    RETURN NEW;
  END IF;

  IF v_source = 'jukebox_artist' THEN
    IF v_bool_active THEN
      PERFORM public.upsert_battery_dispatch_grant(v_user_id, 'jukebox_artist', v_ref_id, 'active', 'Auto-granted from Jukebox artist path');
    END IF;
    RETURN NEW;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."grant_battery_dispatch_from_row"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."grant_gleaning_credits"("p_user_id" "uuid", "p_credits" integer DEFAULT 100) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  UPDATE user_credits
  SET
    gleaning_credits_received = COALESCE(gleaning_credits_received, 0) + p_credits,
    total_credits = COALESCE(total_credits, 0) + p_credits,
    is_gleaner = TRUE,
    gleaning_period_start = COALESCE(gleaning_period_start, NOW()),
    gleaning_period_end = COALESCE(gleaning_period_end, NOW() + INTERVAL '30 days')
  WHERE user_id = p_user_id;

  -- Log the activity
  INSERT INTO user_activity_log (user_id, activity_type, activity_value, metadata)
  VALUES (
    p_user_id,
    'gleaning_granted',
    p_credits,
    jsonb_build_object('source', 'boaz_principle', 'period_days', 30)
  );

  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."grant_gleaning_credits"("p_user_id" "uuid", "p_credits" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."grant_gleaning_credits"("p_user_id" "uuid", "p_credits" integer) IS 'Grant newcomer credits under the Boaz Principle';



CREATE OR REPLACE FUNCTION "public"."handle_new_user"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Create profile
  INSERT INTO public.profiles (id, email, full_name)
  VALUES (
    NEW.id,
    NEW.email,
    COALESCE(NEW.raw_user_meta_data->>'full_name', split_part(NEW.email, '@', 1))
  )
  ON CONFLICT (id) DO NOTHING;

  -- Create credit entry with 5,000 GHOST CREDITS (Boaz Principle)
  INSERT INTO public.user_credits (
    user_id,
    total_credits,
    used_credits,
    earned_credits,
    contribution_credits,
    eoi_credits,                    -- Ghost credits for practice
    initial_credit_accepted,
    gleaning_credits_received,      -- Track as gleaning (Boaz Principle)
    is_gleaner,                     -- Mark as gleaner
    gleaning_period_start,          -- 30-day gleaning period
    gleaning_period_end
  )
  VALUES (
    NEW.id,
    0,                              -- Real credits start at 0
    0,
    0,
    0,
    5000,                           -- 5,000 GHOST CREDITS
    false,
    5000,                           -- Track as gleaning distribution
    true,                           -- Is currently a gleaner
    NOW(),                          -- Gleaning period starts now
    NOW() + INTERVAL '30 days'      -- 30-day gleaning period
  )
  ON CONFLICT (user_id) DO UPDATE SET
    eoi_credits = COALESCE(user_credits.eoi_credits, 0) + 5000,
    gleaning_credits_received = COALESCE(user_credits.gleaning_credits_received, 0) + 5000,
    is_gleaner = true,
    gleaning_period_start = COALESCE(user_credits.gleaning_period_start, NOW()),
    gleaning_period_end = COALESCE(user_credits.gleaning_period_end, NOW() + INTERVAL '30 days');

  -- Log the gleaning grant for transparency
  INSERT INTO public.user_activity_log (user_id, activity_type, activity_value, metadata)
  VALUES (
    NEW.id,
    'ghost_credits_granted',
    5000,
    jsonb_build_object(
      'source', 'boaz_principle',
      'type', 'new_user_gleaning',
      'period_days', 30,
      'message', 'Welcome! 5,000 Ghost Credits to practice and learn.'
    )
  );

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."handle_new_user"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."handle_new_user"() IS 'Creates profile and grants 5,000 Ghost Credits (Boaz Principle) to new users';



CREATE OR REPLACE FUNCTION "public"."handle_whatif_commission_accepted"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_template public.whatif_commission_templates;
  v_role_key TEXT;
  v_member_role_id UUID;
  v_guild_id UUID;
BEGIN
  IF NOT (NEW.status = 'accepted' AND COALESCE(OLD.status, '') <> 'accepted') THEN
    RETURN NEW;
  END IF;

  SELECT * INTO v_template
  FROM public.whatif_commission_templates
  WHERE id = NEW.template_id;

  v_role_key := COALESCE(v_template.commission_type, 'custom');

  IF NEW.recipient_user_id IS NOT NULL THEN
    INSERT INTO public.member_roles (
      user_id,
      role_key,
      source,
      source_ref_id,
      scope_metadata,
      created_by
    )
    VALUES (
      NEW.recipient_user_id,
      v_role_key,
      'whatif_commission',
      NEW.id,
      jsonb_build_object(
        'template_id', NEW.template_id,
        'domain_scope', v_template.domain_scope,
        'authority_description', v_template.authority_description,
        'commitment_scope_limit', NEW.commitment_scope_limit,
        'commitment_project_bounds', NEW.commitment_project_bounds,
        'commitment_decision_level', NEW.commitment_decision_level
      ),
      NEW.granted_by
    )
    ON CONFLICT (user_id, role_key, source, source_ref_id)
    DO UPDATE SET
      status = 'active',
      scope_metadata = EXCLUDED.scope_metadata
    RETURNING id INTO v_member_role_id;
  END IF;

  IF to_regclass('public.guild_memberships') IS NOT NULL AND NEW.recipient_user_id IS NOT NULL THEN
    FOREACH v_role_key IN ARRAY COALESCE(v_template.guild_memberships_granted, ARRAY[]::text[])
    LOOP
      BEGIN
        v_guild_id := v_role_key::uuid;
        INSERT INTO public.guild_memberships (guild_id, member_id, role, is_active)
        VALUES (v_guild_id, NEW.recipient_user_id, 'member', true)
        ON CONFLICT (guild_id, member_id)
        DO UPDATE SET is_active = true;
      EXCEPTION WHEN invalid_text_representation THEN
        -- Ignore non-UUID guild markers.
        CONTINUE;
      END;
    END LOOP;
  END IF;

  IF NEW.granted_in_conversation_id IS NOT NULL THEN
    UPDATE public.founder_contacts
    SET relationship_stage = 'commissioned',
        last_contacted_at = now(),
        updated_at = now()
    WHERE id = NEW.granted_in_conversation_id;
  END IF;

  IF to_regclass('public.notifications') IS NOT NULL THEN
    INSERT INTO public.notifications (user_id, type, title, body, link)
    VALUES (
      NEW.granted_by,
      'whatif_commission',
      'Commission accepted',
      format('%s accepted "%s".', NEW.recipient_name, COALESCE(v_template.title, 'Commission')),
      '/staff/founder-contacts'
    );

    IF NEW.recipient_user_id IS NOT NULL THEN
      INSERT INTO public.notifications (user_id, type, title, body, link)
      VALUES (
        NEW.recipient_user_id,
        'whatif_commission',
        format('Welcome aboard: %s', COALESCE(v_template.title, 'New commission')),
        'Your commission has been accepted. Start with your onboarding Treasure Map and Red Carpet materials.',
        '/treasure-maps'
      );
    END IF;
  END IF;

  IF to_regclass('public.calendar_events') IS NOT NULL THEN
    INSERT INTO public.calendar_events (
      owner_id,
      calendar_type,
      title,
      description,
      start_time,
      end_time,
      all_day,
      source_type,
      metadata
    )
    VALUES (
      NEW.granted_by,
      'business',
      format('Commission follow-up: %s', NEW.recipient_name),
      COALESCE(v_template.title, 'What-If Commission follow-up'),
      COALESCE(NEW.accepted_at, now()) + interval '3 days',
      COALESCE(NEW.accepted_at, now()) + interval '3 days 30 minutes',
      false,
      'manual',
      jsonb_build_object(
        'kind', 'whatif_commission_followup',
        'commission_id', NEW.id,
        'recipient_name', NEW.recipient_name
      )
    );
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."handle_whatif_commission_accepted"() OWNER TO "postgres";


