CREATE OR REPLACE FUNCTION "public"."invoke_cloth_pouch"("p_pouch_id" "uuid", "p_user_id" "uuid", "p_description" "text") RETURNS boolean
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
    pouch_record RECORD;
BEGIN
    -- Get and lock the pouch
    SELECT * INTO pouch_record
    FROM cloth_pouches
    WHERE id = p_pouch_id
    AND user_id = p_user_id
    AND status = 'active'
    FOR UPDATE;

    IF NOT FOUND THEN
        RETURN FALSE;
    END IF;

    -- Mark as invoked
    UPDATE cloth_pouches
    SET status = 'invoked',
        invoked_at = NOW(),
        invoked_for = p_description
    WHERE id = p_pouch_id;

    -- Add the service units to user's balance as Joules
    UPDATE user_balances
    SET joules = COALESCE(joules, 0) + pouch_record.service_units,
        updated_at = NOW()
    WHERE user_id = p_user_id;

    RETURN TRUE;
END;
$$;


