CREATE OR REPLACE FUNCTION "public"."is_valid_hemispheric_slot"("p_member_id" "uuid", "p_fire_at" timestamp with time zone) RETURNS TABLE("is_valid" boolean, "next_valid" timestamp with time zone)
    LANGUAGE "plpgsql" STABLE
    AS $$
DECLARE
  v_local_time TIMESTAMP;
  v_dow INT;
  v_hour INT;
  v_founder_id UUID;
BEGIN
  SELECT id INTO v_founder_id FROM auth.users WHERE email = 'jonathan@lianabanyan.com' LIMIT 1;

  IF p_member_id != v_founder_id THEN
    RETURN QUERY SELECT TRUE, p_fire_at;
    RETURN;
  END IF;

  v_local_time := p_fire_at AT TIME ZONE 'America/Chicago';
  v_dow := EXTRACT(DOW FROM v_local_time);   -- 0=Sun, 6=Sat
  v_hour := EXTRACT(HOUR FROM v_local_time);

  -- Saturday and Sunday = family time (HARD STOP)
  IF v_dow IN (0, 6) THEN
    RETURN QUERY SELECT FALSE,
      (date_trunc('day', v_local_time) + INTERVAL '1 day' + INTERVAL '8 hours') AT TIME ZONE 'America/Chicago';
    RETURN;
  END IF;

  -- Quiet hours: 10pm-6am local
  IF v_hour < 6 OR v_hour >= 22 THEN
    IF v_hour >= 22 THEN
      RETURN QUERY SELECT FALSE,
        (date_trunc('day', v_local_time) + INTERVAL '1 day' + INTERVAL '8 hours') AT TIME ZONE 'America/Chicago';
    ELSE
      RETURN QUERY SELECT FALSE,
        (date_trunc('day', v_local_time) + INTERVAL '8 hours') AT TIME ZONE 'America/Chicago';
    END IF;
    RETURN;
  END IF;

  RETURN QUERY SELECT TRUE, p_fire_at;
END;
$$;


ALTER FUNCTION "public"."is_valid_hemispheric_slot"("p_member_id" "uuid", "p_fire_at" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."join_candle_pair"("p_pair_code" "text", "p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_pair RECORD;
BEGIN
  SELECT * INTO v_pair FROM candle_burst_pairs WHERE pair_code = p_pair_code;

  IF v_pair IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Invalid pair code');
  END IF;

  IF v_pair.user_b_id IS NOT NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Pair code already used');
  END IF;

  IF v_pair.user_a_id = p_user_id THEN
    RETURN jsonb_build_object('success', false, 'error', 'Cannot pair with yourself');
  END IF;

  UPDATE candle_burst_pairs
  SET
    user_b_id = p_user_id,
    status = 'paired',
    paired_at = NOW()
  WHERE id = v_pair.id;

  RETURN jsonb_build_object(
    'success', true,
    'pair_id', v_pair.id,
    'user_a_id', v_pair.user_a_id,
    'candle_uses_each', 9
  );
END;
$$;


ALTER FUNCTION "public"."join_candle_pair"("p_pair_code" "text", "p_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."link_vault_to_family"("p_vault_person" "text", "p_family_id" "uuid", "p_family_member_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
        BEGIN
            INSERT INTO vault_family_mapping (vault_person, family_id, family_member_id)
            VALUES (p_vault_person, p_family_id, p_family_member_id)
            ON CONFLICT (vault_person, family_id) DO UPDATE SET family_member_id = p_family_member_id;

            IF EXISTS (SELECT 1 FROM information_schema.tables WHERE table_name = 'vault_unlocks') THEN
                EXECUTE format('UPDATE vault_unlocks SET family_id = %L, family_member_id = %L WHERE person = %L AND family_id IS NULL',
                    p_family_id, p_family_member_id, p_vault_person);
            END IF;

            RETURN jsonb_build_object('success', true, 'linked', true);
        END;
        $$;


