CREATE OR REPLACE FUNCTION "public"."log_credit_activity"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Log if credits were spent
  IF NEW.used_credits > COALESCE(OLD.used_credits, 0) THEN
    INSERT INTO user_activity_log (user_id, activity_type, activity_value, metadata)
    VALUES (
      NEW.user_id,
      'credits_spent',
      NEW.used_credits - COALESCE(OLD.used_credits, 0),
      jsonb_build_object(
        'new_total', NEW.used_credits,
        'old_total', COALESCE(OLD.used_credits, 0)
      )
    );
  END IF;

  -- Log if credits were earned
  IF NEW.earned_credits > COALESCE(OLD.earned_credits, 0) THEN
    INSERT INTO user_activity_log (user_id, activity_type, activity_value, metadata)
    VALUES (
      NEW.user_id,
      'credits_earned',
      NEW.earned_credits - COALESCE(OLD.earned_credits, 0),
      jsonb_build_object(
        'new_total', NEW.earned_credits,
        'old_total', COALESCE(OLD.earned_credits, 0)
      )
    );
  END IF;

  -- Update profile last_active_at
  UPDATE profiles
  SET last_active_at = NOW(),
      total_transactions = COALESCE(total_transactions, 0) + 1
  WHERE id = NEW.user_id;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."log_credit_activity"() OWNER TO "postgres";


