    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  UPDATE scheduled_posts
  SET
    status = CASE WHEN retry_count < 3 THEN 'scheduled' ELSE 'failed' END,
    error_message = p_error,
    retry_count = retry_count + 1,
    scheduled_for = CASE WHEN retry_count < 3 THEN scheduled_for + INTERVAL '15 minutes' ELSE scheduled_for END,
    updated_at = NOW()
  WHERE id = p_post_id;
END;
$$;


