CREATE OR REPLACE FUNCTION "public"."process_cue_card_click"("p_share_id" "text", "p_template_id" "uuid", "p_sharer_id" "uuid", "p_clicker_id" "uuid" DEFAULT NULL::"uuid", "p_clicker_ghost_id" "text" DEFAULT NULL::"text", "p_platform" "text" DEFAULT 'direct'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_click_id UUID;
  v_template RECORD;
  v_frame_lock RECORD;
  v_click_count INTEGER;
  v_locks_to_unlock INTEGER;
BEGIN
  -- Get template info
  SELECT * INTO v_template FROM cue_card_templates WHERE id = p_template_id;

  IF v_template IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Template not found');
  END IF;

  -- Insert the click
  INSERT INTO cue_card_share_clicks (share_id, template_id, sharer_id, clicker_id, clicker_ghost_id, platform)
  VALUES (p_share_id, p_template_id, p_sharer_id, p_clicker_id, p_clicker_ghost_id, p_platform)
  ON CONFLICT DO NOTHING
  RETURNING id INTO v_click_id;

  IF v_click_id IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Duplicate click');
  END IF;

  -- Count total clicks
  SELECT COUNT(*) INTO v_click_count
  FROM cue_card_share_clicks
  WHERE sharer_id = p_sharer_id AND template_id = p_template_id;

  -- Get or create frame lock record
  IF v_template.linked_deck_card_id IS NOT NULL THEN
    INSERT INTO social_frame_locks (deck_card_id, user_id, cue_card_template_id, clicks_per_lock)
    VALUES (v_template.linked_deck_card_id, p_sharer_id, p_template_id, COALESCE(v_template.clicks_per_frame_unlock, 5))
    ON CONFLICT DO NOTHING;

    SELECT * INTO v_frame_lock FROM social_frame_locks
    WHERE deck_card_id = v_template.linked_deck_card_id AND user_id = p_sharer_id;

    IF v_frame_lock IS NOT NULL THEN
      v_locks_to_unlock := LEAST(4, v_click_count / COALESCE(v_template.clicks_per_frame_unlock, 5));

      UPDATE social_frame_locks
      SET
        total_clicks = v_click_count,
        lock_top = CASE WHEN v_locks_to_unlock >= 1 THEN false ELSE lock_top END,
        lock_right = CASE WHEN v_locks_to_unlock >= 2 THEN false ELSE lock_right END,
        lock_bottom = CASE WHEN v_locks_to_unlock >= 3 THEN false ELSE lock_bottom END,
        lock_left = CASE WHEN v_locks_to_unlock >= 4 THEN false ELSE lock_left END,
        is_fully_unlocked = CASE WHEN v_locks_to_unlock >= 4 THEN true ELSE false END,
        unlocked_at = CASE WHEN v_locks_to_unlock >= 4 AND unlocked_at IS NULL THEN NOW() ELSE unlocked_at END,
        updated_at = NOW()
      WHERE id = v_frame_lock.id
      RETURNING * INTO v_frame_lock;
    END IF;
  ELSE
    v_locks_to_unlock := 0;
  END IF;

  -- Mark click as processed
  UPDATE cue_card_share_clicks
  SET frame_unlock_awarded = true, awarded_at = NOW()
  WHERE id = v_click_id;

  RETURN jsonb_build_object(
    'success', true,
    'click_id', v_click_id,
    'total_clicks', v_click_count,
    'locks_unlocked', v_locks_to_unlock,
    'is_fully_unlocked', COALESCE(v_frame_lock.is_fully_unlocked, false)
  );
END;
$$;


ALTER FUNCTION "public"."process_cue_card_click"("p_share_id" "text", "p_template_id" "uuid", "p_sharer_id" "uuid", "p_clicker_id" "uuid", "p_clicker_ghost_id" "text", "p_platform" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."process_pioneer_join"("p_proposed_email" "text" DEFAULT NULL::"text", "p_proposed_url" "text" DEFAULT NULL::"text", "p_joined_user_id" "uuid" DEFAULT NULL::"uuid", "p_base_reward" numeric DEFAULT 100) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  proposal RECORD;
  order_pct numeric;
  decay_pct numeric;
  final_pct numeric;
  reward_count int := 0;
BEGIN
  FOR proposal IN
    SELECT * FROM public.pioneer_proposals
    WHERE status = 'proposed'
    AND (
      (p_proposed_email IS NOT NULL AND proposed_email = p_proposed_email)
      OR
      (p_proposed_url IS NOT NULL AND proposed_url = p_proposed_url)
    )
    ORDER BY proposal_order ASC
  LOOP
    UPDATE public.pioneer_proposals
    SET status = 'joined',
        joined_at = now(),
        joined_user_id = p_joined_user_id
    WHERE id = proposal.id;

    order_pct := public.get_order_reward_percent(proposal.proposal_order);
    decay_pct := public.get_time_decay_percent(proposal.proposed_at);
    final_pct := LEAST(order_pct, decay_pct);

    INSERT INTO public.pioneer_rewards (
      proposal_id, proposer_id, reward_marks,
      reward_percent, time_decay_percent, final_percent,
      decay_applied
    ) VALUES (
      proposal.id, proposal.proposer_id,
      (p_base_reward * final_pct / 100),
      order_pct, decay_pct, final_pct,
      (decay_pct < 100)
    );

    reward_count := reward_count + 1;
  END LOOP;

  RETURN reward_count;
END;
$$;


ALTER FUNCTION "public"."process_pioneer_join"("p_proposed_email" "text", "p_proposed_url" "text", "p_joined_user_id" "uuid", "p_base_reward" numeric) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."process_recipe_vote"("p_recipe_id" "uuid", "p_user_id" "uuid", "p_marks_committed" integer) RETURNS TABLE("vote_recorded" boolean, "shadow_marks_crystallized" integer, "creator_id" "uuid")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_recipe RECORD;
  v_shadow RECORD;
  v_crystallize_amount INTEGER := 0;
  v_new_votes INTEGER;
  v_crystallize_ratio DECIMAL;
BEGIN
  -- Get recipe info
  SELECT * INTO v_recipe FROM pantry_recipes WHERE id = p_recipe_id;
  IF v_recipe IS NULL THEN
    RAISE EXCEPTION 'Recipe not found';
  END IF;

  -- Record the vote
  INSERT INTO pantry_recipe_votes (recipe_id, user_id, marks_committed)
  VALUES (p_recipe_id, p_user_id, p_marks_committed)
  ON CONFLICT (recipe_id, user_id)
  DO UPDATE SET marks_committed = pantry_recipe_votes.marks_committed + p_marks_committed;

  -- Update recipe vote count
  UPDATE pantry_recipes
  SET vote_count = vote_count + p_marks_committed
  WHERE id = p_recipe_id;

  -- Check for shadow marks to crystallize
  SELECT * INTO v_shadow
  FROM shadow_marks
  WHERE source_type = 'recipe_bounty'
    AND source_id = p_recipe_id
    AND status IN ('vesting', 'partial')
  FOR UPDATE;

  IF v_shadow IS NOT NULL THEN
    -- Update votes received
    v_new_votes := v_shadow.votes_received + p_marks_committed;

    -- Calculate crystallization
    v_crystallize_ratio := LEAST(v_new_votes::DECIMAL / v_shadow.votes_needed, 1.0);
    v_crystallize_amount := FLOOR(v_shadow.current_amount * v_crystallize_ratio) - v_shadow.crystallized_amount;

    IF v_crystallize_amount > 0 THEN
      -- Update shadow marks record
      UPDATE shadow_marks
      SET votes_received = v_new_votes,
          crystallized_amount = crystallized_amount + v_crystallize_amount,
          status = CASE
            WHEN v_new_votes >= votes_needed THEN 'crystallized'
            ELSE 'partial'
          END,
          crystallized_at = CASE
            WHEN v_new_votes >= votes_needed THEN NOW()
            ELSE crystallized_at
          END
      WHERE id = v_shadow.id;

      -- Award real marks to the recipe creator
      INSERT INTO marks_transactions (user_id, amount, reason, reason_type)
      VALUES (v_recipe.creator_id, v_crystallize_amount,
              'Shadow Marks crystallized from recipe votes', 'shadow_crystallize');

      -- Update user's total marks
      UPDATE user_marks
      SET total_marks = total_marks + v_crystallize_amount
      WHERE user_id = v_recipe.creator_id;
    ELSE
      -- Just update vote count
      UPDATE shadow_marks
      SET votes_received = v_new_votes
      WHERE id = v_shadow.id;
    END IF;
  END IF;

  RETURN QUERY SELECT TRUE, v_crystallize_amount, v_recipe.creator_id;
END;
$$;


ALTER FUNCTION "public"."process_recipe_vote"("p_recipe_id" "uuid", "p_user_id" "uuid", "p_marks_committed" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."process_recurring_commitment"("commitment_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  commitment RECORD;
BEGIN
  SELECT * INTO commitment FROM donation_commitments WHERE id = commitment_id;

  IF commitment.status != 'active' OR commitment.type != 'recurring' THEN
    RETURN FALSE;
  END IF;

  -- Update next charge date based on frequency
  UPDATE donation_commitments
  SET next_charge_date = CASE commitment.frequency
    WHEN 'weekly' THEN NOW() + INTERVAL '1 week'
    WHEN 'biweekly' THEN NOW() + INTERVAL '2 weeks'
    WHEN 'monthly' THEN NOW() + INTERVAL '1 month'
    WHEN 'quarterly' THEN NOW() + INTERVAL '3 months'
  END,
  total_donated = total_donated + commitment.amount,
  donation_count = donation_count + 1,
  last_donation_date = NOW(),
  updated_at = NOW()
  WHERE id = commitment_id;

  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."process_recurring_commitment"("commitment_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."process_roommate_escrow"() RETURNS TABLE("agreement_id" "uuid", "action" "text", "marks_amount" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_agreement RECORD;
  v_upheld_count INT;
  v_forfeit_amount INT;
  v_month_forfeited INT;
BEGIN
  FOR v_agreement IN
    SELECT * FROM roommate_agreements WHERE status IN ('active', 'probation')
  LOOP
    -- Count upheld stamps this week
    SELECT COUNT(*) INTO v_upheld_count
    FROM roommate_stamps
    WHERE roommate_stamps.agreement_id = v_agreement.id
      AND respondent_id = v_agreement.member_id
      AND status = 'upheld'
      AND created_at >= (now() - interval '7 days');

    -- Check monthly forfeit so far
    SELECT COALESCE(SUM(marks_forfeited), 0) INTO v_month_forfeited
    FROM roommate_stamps
    WHERE roommate_stamps.agreement_id = v_agreement.id
      AND respondent_id = v_agreement.member_id
      AND status = 'upheld'
      AND created_at >= date_trunc('month', now());

    -- Process forfeits (respect monthly cap of 30)
    IF v_upheld_count > 0 AND v_month_forfeited < v_agreement.monthly_forfeit_cap THEN
      v_forfeit_amount := LEAST(
        v_agreement.current_escrow,
        v_agreement.weekly_marks_pledge,
        v_agreement.monthly_forfeit_cap - v_month_forfeited
      );

      IF v_forfeit_amount > 0 THEN
        UPDATE roommate_agreements
        SET current_escrow = current_escrow - v_forfeit_amount,
            total_forfeited = total_forfeited + v_forfeit_amount,
            updated_at = now()
        WHERE id = v_agreement.id;

        -- Record as housing contribution (forfeited to cooperative fund)
        INSERT INTO housing_contributions (contributor_id, property_id, contribution_type, amount, currency, description, verified, verified_at)
        VALUES (v_agreement.member_id, v_agreement.property_id, 'mark_pledge', v_forfeit_amount, 'marks',
                'Roommate accountability forfeit — ' || v_upheld_count || ' upheld stamp(s)', true, now());

        agreement_id := v_agreement.id; action := 'forfeit'; marks_amount := v_forfeit_amount;
        RETURN NEXT;
      END IF;

      -- Update week as not clean
      UPDATE roommate_agreements
      SET total_weeks = total_weeks + 1, updated_at = now()
      WHERE id = v_agreement.id;
    ELSE
      -- Clean week
      UPDATE roommate_agreements
      SET total_weeks = total_weeks + 1, clean_weeks = clean_weeks + 1, updated_at = now()
      WHERE id = v_agreement.id;
    END IF;

    -- Refill escrow from pledge
    UPDATE roommate_agreements
    SET current_escrow = current_escrow + v_agreement.weekly_marks_pledge, updated_at = now()
    WHERE id = v_agreement.id;

    agreement_id := v_agreement.id; action := 'escrow_refill'; marks_amount := v_agreement.weekly_marks_pledge;
    RETURN NEXT;

    -- Recalculate roommate score
    PERFORM calculate_roommate_score(v_agreement.id);

    -- Trigger steward review if 3+ forfeits this month
    IF v_month_forfeited + COALESCE(v_forfeit_amount, 0) >= v_agreement.monthly_forfeit_cap THEN
      UPDATE roommate_agreements SET status = 'probation', updated_at = now()
      WHERE id = v_agreement.id AND status = 'active';

      agreement_id := v_agreement.id; action := 'probation_triggered'; marks_amount := 0;
      RETURN NEXT;
    END IF;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."process_roommate_escrow"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."read_dna_lock"("_key" "text") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  val TEXT;
BEGIN
  UPDATE public.dna_lock
  SET last_read_at = NOW(), read_count = read_count + 1
  WHERE parameter_key = _key;

  SELECT parameter_value INTO val FROM public.dna_lock WHERE parameter_key = _key;
  RETURN val;
END;
$$;


ALTER FUNCTION "public"."read_dna_lock"("_key" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."recalc_neighborhood_harper_score"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE avg_score NUMERIC;
BEGIN
  SELECT COALESCE(AVG(score), 0) INTO avg_score
    FROM neighborhood_harper_reviews
   WHERE neighborhood_id = COALESCE(NEW.neighborhood_id, OLD.neighborhood_id);

  UPDATE neighborhoods
     SET harper_score = avg_score,
         updated_at = now()
   WHERE id = COALESCE(NEW.neighborhood_id, OLD.neighborhood_id);

  RETURN COALESCE(NEW, OLD);
END;
$$;


ALTER FUNCTION "public"."recalc_neighborhood_harper_score"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."recalculate_xp_scores"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_total_xp INTEGER;
  v_bounty_xp INTEGER;
  v_product_xp INTEGER;
  v_production_xp INTEGER;
  v_bounties INTEGER;
  v_products INTEGER;
  v_productions INTEGER;
  v_avg_score NUMERIC;
  v_highest INTEGER;
BEGIN
  SELECT
    COALESCE(SUM(xp_earned), 0)::INTEGER,
    COALESCE(SUM(CASE WHEN xp_type = 'bounty' THEN xp_earned ELSE 0 END), 0)::INTEGER,
    COALESCE(SUM(CASE WHEN xp_type = 'product' THEN xp_earned ELSE 0 END), 0)::INTEGER,
    COALESCE(SUM(CASE WHEN xp_type = 'production' THEN xp_earned ELSE 0 END), 0)::INTEGER,
    COUNT(*) FILTER (WHERE xp_type = 'bounty')::INTEGER,
    COUNT(*) FILTER (WHERE xp_type = 'product')::INTEGER,
    COUNT(*) FILTER (WHERE xp_type = 'production')::INTEGER,
    COALESCE(AVG(accomplishment_score), 0),
    COALESCE(MAX(xp_earned), 0)::INTEGER
  INTO v_total_xp, v_bounty_xp, v_product_xp, v_production_xp,
       v_bounties, v_products, v_productions, v_avg_score, v_highest
  FROM public.xp_transactions
  WHERE user_id = NEW.user_id;

  INSERT INTO public.xp_scores (
    user_id, total_xp, bounty_xp, product_xp, production_xp,
    bounties_completed, products_completed, production_runs_completed,
    average_accomplishment_score, highest_single_xp, updated_at
  ) VALUES (
    NEW.user_id, v_total_xp, v_bounty_xp, v_product_xp, v_production_xp,
    v_bounties, v_products, v_productions,
    v_avg_score, v_highest, NOW()
  )
  ON CONFLICT (user_id) DO UPDATE SET
    total_xp = EXCLUDED.total_xp,
    bounty_xp = EXCLUDED.bounty_xp,
    product_xp = EXCLUDED.product_xp,
    production_xp = EXCLUDED.production_xp,
    bounties_completed = EXCLUDED.bounties_completed,
    products_completed = EXCLUDED.products_completed,
    production_runs_completed = EXCLUDED.production_runs_completed,
    average_accomplishment_score = EXCLUDED.average_accomplishment_score,
    highest_single_xp = EXCLUDED.highest_single_xp,
    updated_at = NOW();

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."recalculate_xp_scores"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."record_c20_margin_contribution"("p_anchor_id" "uuid", "p_product_config_id" "uuid", "p_units_sold" integer DEFAULT 1, "p_order_id" "uuid" DEFAULT NULL::"uuid") RETURNS numeric
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  v_margin_per_unit NUMERIC(10,2);
  v_total_margin NUMERIC(14,2);
  v_balance_before NUMERIC(14,2);
  v_balance_after NUMERIC(14,2);
  v_reciprocity_rate NUMERIC(10,6);
BEGIN
  -- Get margin sacrificed per unit
  SELECT margin_sacrificed_per_unit INTO v_margin_per_unit
  FROM public.c20_product_config
  WHERE id = p_product_config_id;

  IF v_margin_per_unit IS NULL THEN
    RAISE EXCEPTION 'Product config not found';
  END IF;

  -- Calculate total margin contributed
  v_total_margin := v_margin_per_unit * p_units_sold;

  -- Get reciprocity rate from DNA lock
  SELECT COALESCE(parameter_value::NUMERIC, 1.0) INTO v_reciprocity_rate
  FROM public.dna_lock WHERE parameter_key = 'c20_reciprocity_rate';

  -- Get current balance
  SELECT c20_reciprocity_balance INTO v_balance_before
  FROM public.anchors WHERE id = p_anchor_id;

  v_balance_after := v_balance_before + (v_total_margin * v_reciprocity_rate);

  -- Update anchor balances
  UPDATE public.anchors
  SET
    c20_reciprocity_balance = v_balance_after,
    c20_total_margin_contributed = c20_total_margin_contributed + v_total_margin,
    updated_at = NOW()
  WHERE id = p_anchor_id;

  -- Update product config units sold
  UPDATE public.c20_product_config
  SET
    c20_units_sold = c20_units_sold + p_units_sold,
    updated_at = NOW()
  WHERE id = p_product_config_id;

  -- Record in ledger
  INSERT INTO public.c20_reciprocity_ledger (
    anchor_id, transaction_type, amount,
    balance_before, balance_after,
    product_config_id, order_id, notes
  ) VALUES (
    p_anchor_id, 'MARGIN_CONTRIBUTION', v_total_margin * v_reciprocity_rate,
    v_balance_before, v_balance_after,
    p_product_config_id, p_order_id,
    format('Sold %s units, margin sacrificed: $%s each', p_units_sold, v_margin_per_unit)
  );

  RETURN v_total_margin * v_reciprocity_rate;
END;
$_$;


ALTER FUNCTION "public"."record_c20_margin_contribution"("p_anchor_id" "uuid", "p_product_config_id" "uuid", "p_units_sold" integer, "p_order_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."record_credit_transaction"("p_user_id" "uuid", "p_type" "text", "p_amount" numeric, "p_ref_type" "text" DEFAULT NULL::"text", "p_ref_id" "text" DEFAULT NULL::"text", "p_description" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_balance_before DECIMAL;
  v_balance_after DECIMAL;
  v_tx_id UUID;
BEGIN
  -- Get current balance
  SELECT COALESCE(available_credits, 0) INTO v_balance_before
  FROM user_credits WHERE user_id = p_user_id;

  v_balance_after := v_balance_before + p_amount;

  -- Insert transaction
  INSERT INTO credit_transactions (
    user_id, transaction_type, amount,
    balance_before, balance_after,
    reference_type, reference_id, description
  ) VALUES (
    p_user_id, p_type, p_amount,
    v_balance_before, v_balance_after,
    p_ref_type, p_ref_id, p_description
  ) RETURNING id INTO v_tx_id;

  RETURN v_tx_id;
END;
$$;


ALTER FUNCTION "public"."record_credit_transaction"("p_user_id" "uuid", "p_type" "text", "p_amount" numeric, "p_ref_type" "text", "p_ref_id" "text", "p_description" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."record_free_daily_usage"("p_user_id" "uuid", "p_device_fingerprint" "text", "p_ip_hash" "text", "p_feature_type" "text", "p_session_duration" integer DEFAULT NULL::integer) RETURNS TABLE("success" boolean, "uses_today" integer, "remaining_uses" integer, "upgrade_message" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_access_result RECORD;
    v_uses INTEGER;
    v_remaining INTEGER;
    v_message TEXT;
BEGIN
    -- Check access first
    SELECT * INTO v_access_result
    FROM public.check_free_daily_access(p_user_id, p_device_fingerprint, p_ip_hash, p_feature_type);

    -- If unlimited (member), just return success
    IF v_access_result.daily_limit = -1 THEN
        RETURN QUERY SELECT TRUE, 0, -1, NULL::TEXT;
        RETURN;
    END IF;

    -- If no access left, return failure
    IF NOT v_access_result.can_access THEN
        RETURN QUERY SELECT
            FALSE,
            v_access_result.uses_today,
            0,
            v_access_result.upgrade_message;
        RETURN;
    END IF;

    -- Record the usage (check if exists first, then insert or update)
    -- Using manual upsert since COALESCE in ON CONFLICT not supported
    IF EXISTS (
        SELECT 1 FROM public.free_daily_usage
        WHERE usage_date = CURRENT_DATE
        AND feature_type = p_feature_type
        AND (
            (p_user_id IS NOT NULL AND user_id = p_user_id)
            OR (p_user_id IS NULL AND p_device_fingerprint IS NOT NULL AND device_fingerprint = p_device_fingerprint)
            OR (p_user_id IS NULL AND p_device_fingerprint IS NULL AND ip_hash = p_ip_hash)
        )
    ) THEN
        -- Update existing record
        UPDATE public.free_daily_usage SET
            usage_count = usage_count + 1,
            last_used_at = now(),
            session_duration_seconds = COALESCE(session_duration_seconds, 0) + COALESCE(p_session_duration, 0)
        WHERE usage_date = CURRENT_DATE
        AND feature_type = p_feature_type
        AND (
            (p_user_id IS NOT NULL AND user_id = p_user_id)
            OR (p_user_id IS NULL AND p_device_fingerprint IS NOT NULL AND device_fingerprint = p_device_fingerprint)
            OR (p_user_id IS NULL AND p_device_fingerprint IS NULL AND ip_hash = p_ip_hash)
        );
    ELSE
        -- Insert new record
        INSERT INTO public.free_daily_usage (
            user_id,
            device_fingerprint,
            ip_hash,
            feature_type,
            usage_date,
            usage_count,
            session_duration_seconds
        ) VALUES (
            p_user_id,
            p_device_fingerprint,
            p_ip_hash,
            p_feature_type,
            CURRENT_DATE,
            1,
            p_session_duration
        );
    END IF;

    -- Get updated counts
    v_uses := v_access_result.uses_today + 1;
    v_remaining := GREATEST(0, v_access_result.daily_limit - v_uses);

    IF v_remaining = 0 THEN
        v_message := v_access_result.upgrade_message;
    ELSE
        v_message := NULL;
    END IF;

    RETURN QUERY SELECT TRUE, v_uses, v_remaining, v_message;
END;
$$;


ALTER FUNCTION "public"."record_free_daily_usage"("p_user_id" "uuid", "p_device_fingerprint" "text", "p_ip_hash" "text", "p_feature_type" "text", "p_session_duration" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."record_free_daily_usage"("p_user_id" "uuid", "p_device_fingerprint" "text", "p_ip_hash" "text", "p_feature_type" "text", "p_session_duration" integer) IS 'Record usage of a free daily feature. Returns success status and remaining uses.';



CREATE OR REPLACE FUNCTION "public"."record_pass_through"("p_cue_card_id" "uuid", "p_anchor_id" "uuid", "p_level" integer, "p_ip_hash" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_pass_through_id UUID;
  v_coupon_id UUID;
  v_marks INTEGER;
BEGIN
  -- Calculate marks based on level
  v_marks := p_level;  -- 1, 2, or 3 marks

  -- Insert pass-through record
  INSERT INTO public.slingshot_pass_throughs (
    cue_card_id, anchor_id, level, marks_earned, ip_hash
  ) VALUES (
    p_cue_card_id, p_anchor_id, p_level, v_marks, p_ip_hash
  ) RETURNING id INTO v_pass_through_id;

  -- Issue User Coupon if Level 2+
  IF p_level >= 2 THEN
    INSERT INTO public.user_coupons (
      coupon_code, pass_through_id, anchor_id, expires_at
    ) VALUES (
      'UC-' || substr(gen_random_uuid()::text, 1, 8),
      v_pass_through_id,
      p_anchor_id,
      NOW() + INTERVAL '7 days'
    ) RETURNING id INTO v_coupon_id;

    UPDATE public.slingshot_pass_throughs
    SET user_coupon_issued = true, user_coupon_id = v_coupon_id
    WHERE id = v_pass_through_id;
  END IF;

  -- Update anchor stats
  UPDATE public.anchors
  SET total_pass_throughs = total_pass_throughs + 1,
      updated_at = NOW()
  WHERE id = p_anchor_id;

  -- Update cue card stats
  UPDATE public.cue_card_registry
  SET total_scans = total_scans + 1,
      last_seen = NOW()
  WHERE id = p_cue_card_id;

  RETURN v_pass_through_id;
END;
$$;


ALTER FUNCTION "public"."record_pass_through"("p_cue_card_id" "uuid", "p_anchor_id" "uuid", "p_level" integer, "p_ip_hash" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."record_promotion_click"("p_promoter_id" "uuid", "p_project_id" "uuid", "p_destination_id" "uuid", "p_clicker_id" "uuid" DEFAULT NULL::"uuid", "p_clicker_ghost_id" "text" DEFAULT NULL::"text", "p_click_source" "text" DEFAULT 'qr_scan'::"text", "p_platform" "text" DEFAULT 'direct'::"text") RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_marks NUMERIC;
  v_attribution_id UUID;
BEGIN
  -- Get marks per click from DNA Lock
  SELECT COALESCE(param_value::NUMERIC, 1) INTO v_marks
  FROM dna_lock WHERE param_key = 'promotion_click_marks';

  -- Insert attribution
  INSERT INTO promotion_attributions (
    promoter_id, project_id, destination_id,
    clicker_id, clicker_ghost_id,
    click_source, platform, marks_awarded
  ) VALUES (
    p_promoter_id, p_project_id, p_destination_id,
    p_clicker_id, p_clicker_ghost_id,
    p_click_source, p_platform, v_marks
  )
  RETURNING id INTO v_attribution_id;

  -- Award marks to promoter
  UPDATE user_marks
  SET total_marks = total_marks + v_marks
  WHERE user_id = p_promoter_id;

  RETURN JSON_BUILD_OBJECT(
    'attribution_id', v_attribution_id,
    'marks_awarded', v_marks
  );
END;
$$;


ALTER FUNCTION "public"."record_promotion_click"("p_promoter_id" "uuid", "p_project_id" "uuid", "p_destination_id" "uuid", "p_clicker_id" "uuid", "p_clicker_ghost_id" "text", "p_click_source" "text", "p_platform" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."record_recipe_escape_velocity"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  threshold INTEGER;
  ledger_data TEXT;
  ledger_hash TEXT;
BEGIN
  -- Get threshold from DNA lock
  SELECT parameter_value::INTEGER INTO threshold
  FROM dna_lock WHERE parameter_key = 'recipe_escape_velocity_threshold';

  -- Check if we just crossed the threshold
  IF NEW.vote_count >= threshold AND OLD.vote_count < threshold THEN
    -- Generate IP Ledger stamp data
    ledger_data := json_build_object(
      'recipe_id', NEW.id,
      'creator_id', NEW.creator_id,
      'title', NEW.title,
      'vote_count_at_escape', NEW.vote_count,
      'escape_velocity_timestamp', NOW(),
      'cuisine', NEW.cuisine,
      'meal_type', NEW.meal_type
    )::TEXT;

    -- Create SHA-256 hash (using pgcrypto)
    ledger_hash := encode(digest(ledger_data, 'sha256'), 'hex');

    -- Update recipe with escape velocity status
    NEW.escape_velocity_reached := true;
    NEW.escape_velocity_reached_at := NOW();
    NEW.ip_ledger_hash := ledger_hash;

    -- Record to acknowledgment_stamps (IP Ledger)
    INSERT INTO acknowledgment_stamps (
      user_id,
      action_type,
      rules_version,
      stamp_hash,
      acknowledged_at
    ) VALUES (
      NEW.creator_id,
      'recipe_escape_velocity',
      '1.0',  -- Recipe escape velocity rules version
      ledger_hash,
      NOW()
    );

    -- Award bonus MARKS for reaching escape velocity (50 bonus)
    INSERT INTO marks_transactions (user_id, amount, reason, reason_type)
    VALUES (NEW.creator_id, 50,
            'Recipe reached escape velocity (100+ votes): ' || NEW.title,
            'escape_velocity_bonus');

    UPDATE user_marks
    SET total_marks = total_marks + 50
    WHERE user_id = NEW.creator_id;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."record_recipe_escape_velocity"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."refresh_battery_dispatch_access_status"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_90_days_ago TIMESTAMPTZ := now() - interval '90 days';
BEGIN
  -- Suspend stale grants (staff_override remains explicit until manually changed).
  UPDATE public.battery_dispatch_access
  SET status = 'suspended',
      updated_at = now()
  WHERE status = 'active'
    AND access_source <> 'staff_override'
    AND last_active_at < v_90_days_ago;

  -- Influencer reactivation: recent posted dispatch activity.
  IF to_regclass('public.member_scheduled_posts') IS NOT NULL THEN
    UPDATE public.battery_dispatch_access bda
    SET status = 'active',
        last_active_at = GREATEST(
          bda.last_active_at,
          COALESCE(
            (
              SELECT MAX(msp.posted_at)
              FROM public.member_scheduled_posts msp
              WHERE msp.user_id = bda.user_id
                AND msp.posted_at IS NOT NULL
                AND msp.posted_at > v_90_days_ago
            ),
            now()
          )
        ),
        updated_at = now()
    WHERE bda.access_source = 'influencer'
      AND bda.status = 'suspended'
      AND EXISTS (
        SELECT 1
        FROM public.member_scheduled_posts msp
        WHERE msp.user_id = bda.user_id
          AND msp.posted_at IS NOT NULL
          AND msp.posted_at > v_90_days_ago
      );
  END IF;

  -- Project-holder reactivation: project row updated recently.
  IF to_regclass('public.projects') IS NOT NULL THEN
    UPDATE public.battery_dispatch_access bda
    SET status = 'active',
        last_active_at = GREATEST(
          bda.last_active_at,
          COALESCE(
            (
              SELECT p.updated_at
              FROM public.projects p
              WHERE p.id::text = bda.source_ref_id
                AND p.updated_at > v_90_days_ago
              ORDER BY p.updated_at DESC
              LIMIT 1
            ),
            now()
          )
        ),
        updated_at = now()
    WHERE bda.access_source = 'project'
      AND bda.status = 'suspended'
      AND EXISTS (
        SELECT 1
        FROM public.projects p
        WHERE p.id::text = bda.source_ref_id
          AND p.updated_at > v_90_days_ago
      );
  END IF;

  -- Crown reactivation: active crown status.
  IF to_regclass('public.initiative_crowns') IS NOT NULL THEN
    UPDATE public.battery_dispatch_access bda
    SET status = 'active',
        last_active_at = now(),
        updated_at = now()
    WHERE bda.access_source = 'crown'
      AND bda.status = 'suspended'
      AND EXISTS (
        SELECT 1
        FROM public.initiative_crowns ic
        WHERE ic.id::text = bda.source_ref_id
          AND ic.crown_status = 'active'
      );
  END IF;

  -- Captain / Harper / Jukebox remain source-trigger driven and can be touched by
  -- source-specific events via touch_battery_dispatch_activity().
END;
$$;


ALTER FUNCTION "public"."refresh_battery_dispatch_access_status"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."refund_bounty_escrow"("p_sponsorship_id" "uuid", "p_reason" "text" DEFAULT 'Dispute or cancellation'::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_sponsorship RECORD;
  v_ledger_id UUID;
  v_amount_cents INTEGER;
BEGIN
  SELECT * INTO v_sponsorship
    FROM bounty_sponsorships
    WHERE id = p_sponsorship_id AND status = 'escrowed';

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Sponsorship % not in escrow', p_sponsorship_id;
  END IF;

  v_amount_cents := (v_sponsorship.amount_credits * 100)::INTEGER;

  -- Insert refund transaction (Credits return to sender)
  INSERT INTO transaction_ledger (
    ledger_category, amount_cents, currency, payee_id, project_id,
    status, description, metadata
  )
  VALUES (
    'escrow_refund', v_amount_cents, 'credits',
    v_sponsorship.sponsor_id, v_sponsorship.project_id,
    'refunded',
    'Escrow refunded — ' || p_reason,
    jsonb_build_object('sponsorship_id', p_sponsorship_id, 'action', 'refund', 'reason', p_reason)
  )
  RETURNING id INTO v_ledger_id;

  -- Update sponsorship
  UPDATE bounty_sponsorships
    SET status = 'refunded', completed_at = now()
    WHERE id = p_sponsorship_id;

  -- Update escrow ledger
  UPDATE project_escrow_ledger
    SET status = 'refunded', released_at = now(),
        released_to = v_sponsorship.sponsor_id,
        notes = 'Refund: ' || p_reason
    WHERE contribution_id IN (
      SELECT id FROM transaction_ledger
        WHERE metadata->>'sponsorship_id' = p_sponsorship_id::text
        AND ledger_category = 'escrow_hold'
    );

  RETURN v_ledger_id;
END;
$$;


ALTER FUNCTION "public"."refund_bounty_escrow"("p_sponsorship_id" "uuid", "p_reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."regenerate_candle"("p_user_id" "uuid") RETURNS numeric
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_candles RECORD;
  v_wait_minutes INTEGER;
  v_can_regenerate BOOLEAN;
  v_new_amount DECIMAL;
BEGIN
  SELECT * INTO v_candles FROM user_candles WHERE user_id = p_user_id;

  IF v_candles IS NULL THEN
    INSERT INTO user_candles (user_id, standard_amount) VALUES (p_user_id, 0.1)
    RETURNING standard_amount INTO v_new_amount;
    RETURN v_new_amount;
  END IF;

  CASE v_candles.regeneration_count
    WHEN 0 THEN v_wait_minutes := 1;
    WHEN 1 THEN v_wait_minutes := 3;
    WHEN 2 THEN v_wait_minutes := 10;
    WHEN 3 THEN v_wait_minutes := 30;
    WHEN 4 THEN v_wait_minutes := 60;
    ELSE v_wait_minutes := 180;
  END CASE;

  v_can_regenerate := v_candles.last_regeneration + (v_wait_minutes || ' minutes')::INTERVAL <= NOW();

  IF v_can_regenerate THEN
    UPDATE user_candles
    SET
      standard_amount = LEAST(standard_amount + 0.1, 10.0),
      last_regeneration = NOW(),
      regeneration_count = regeneration_count + 1
    WHERE user_id = p_user_id
    RETURNING standard_amount INTO v_new_amount;
    RETURN v_new_amount;
  END IF;

  RETURN v_candles.standard_amount;
END;
$$;


ALTER FUNCTION "public"."regenerate_candle"("p_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."release_bounty_escrow"("p_sponsorship_id" "uuid", "p_recipient_id" "uuid", "p_verifier_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_sponsorship RECORD;
  v_ledger_id UUID;
  v_amount_cents INTEGER;
BEGIN
  SELECT * INTO v_sponsorship
    FROM bounty_sponsorships
    WHERE id = p_sponsorship_id AND status = 'escrowed';

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Sponsorship % not in escrow', p_sponsorship_id;
  END IF;

  v_amount_cents := (v_sponsorship.amount_credits * 100)::INTEGER;

  -- Insert release transaction
  INSERT INTO transaction_ledger (
    ledger_category, amount_cents, currency, payer_id, payee_id, project_id,
    status, description, metadata
  )
  VALUES (
    'escrow_release', v_amount_cents, 'credits',
    v_sponsorship.sponsor_id, p_recipient_id, v_sponsorship.project_id,
    'completed',
    'Escrow released — deliverable approved',
    jsonb_build_object('sponsorship_id', p_sponsorship_id, 'action', 'release')
  )
  RETURNING id INTO v_ledger_id;

  -- Update sponsorship
  UPDATE bounty_sponsorships
    SET status = 'released', completed_at = now()
    WHERE id = p_sponsorship_id;

  -- Update escrow ledger
  UPDATE project_escrow_ledger
    SET status = 'released', released_at = now(),
        released_to = p_recipient_id, verified_by = p_verifier_id
    WHERE contribution_id IN (
      SELECT id FROM transaction_ledger
        WHERE metadata->>'sponsorship_id' = p_sponsorship_id::text
        AND ledger_category = 'escrow_hold'
    );

  RETURN v_ledger_id;
END;
$$;


ALTER FUNCTION "public"."release_bounty_escrow"("p_sponsorship_id" "uuid", "p_recipient_id" "uuid", "p_verifier_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."request_cost_plus_certification"("p_anchor_id" "uuid", "p_evidence_url" "text" DEFAULT NULL::"text", "p_evidence_notes" "text" DEFAULT NULL::"text", "p_cost_breakdown" "jsonb" DEFAULT NULL::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_audit_id UUID;
  v_owner_id UUID;
BEGIN
  -- Verify caller owns the anchor
  SELECT owner_id INTO v_owner_id FROM public.anchors WHERE id = p_anchor_id;
  IF v_owner_id != auth.uid() THEN
    RAISE EXCEPTION 'You do not own this anchor';
  END IF;

  -- Check for existing pending request
  IF EXISTS (
    SELECT 1 FROM public.cost_plus_audits
    WHERE anchor_id = p_anchor_id AND status = 'pending'
  ) THEN
    RAISE EXCEPTION 'A pending certification request already exists for this anchor';
  END IF;

  -- Create audit request
  INSERT INTO public.cost_plus_audits (
    anchor_id,
    requested_by,
    request_type,
    evidence_url,
    evidence_notes,
    cost_breakdown
  ) VALUES (
    p_anchor_id,
    auth.uid(),
    'certification',
    p_evidence_url,
    p_evidence_notes,
    p_cost_breakdown
  ) RETURNING id INTO v_audit_id;

  -- Update anchor to show pending
  UPDATE public.anchors
  SET pricing_policy = 'C_PLUS_20',
      updated_at = NOW()
  WHERE id = p_anchor_id;

  RETURN v_audit_id;
END;
$$;


ALTER FUNCTION "public"."request_cost_plus_certification"("p_anchor_id" "uuid", "p_evidence_url" "text", "p_evidence_notes" "text", "p_cost_breakdown" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."request_cost_plus_certification"("p_anchor_id" "uuid", "p_evidence_url" "text", "p_evidence_notes" "text", "p_cost_breakdown" "jsonb") IS 'Request C+20 certification for an anchor';



CREATE OR REPLACE FUNCTION "public"."resolve_dead_letter"("p_dead_letter_id" "uuid", "p_action" "text" DEFAULT 'dismiss'::"text", "p_notes" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'Admin only';
  END IF;

  IF p_action = 'retry' THEN
    UPDATE public.member_scheduled_posts
    SET status = 'scheduled',
        retry_count = 0,
        error_message = NULL,
        scheduled_for = now() + INTERVAL '5 minutes',
        updated_at = now()
    WHERE id = (SELECT original_post_id FROM public.dispatch_dead_letters WHERE id = p_dead_letter_id);

    UPDATE public.scheduled_posts
    SET status = 'scheduled',
        retry_count = 0,
        error_message = NULL,
        scheduled_for = now() + INTERVAL '5 minutes',
        updated_at = now()
    WHERE id = (SELECT original_post_id FROM public.dispatch_dead_letters WHERE id = p_dead_letter_id);
  END IF;

  UPDATE public.dispatch_dead_letters
  SET resolved_at = now(),
      resolved_by = auth.uid(),
      resolution_notes = COALESCE(p_notes, p_action)
  WHERE id = p_dead_letter_id;
END;
$$;


ALTER FUNCTION "public"."resolve_dead_letter"("p_dead_letter_id" "uuid", "p_action" "text", "p_notes" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."return_swoop_pledges"("p_initiative_id" "uuid") RETURNS integer
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_returned_count INTEGER := 0;
    v_vote RECORD;
BEGIN
    -- Update all pledged votes to returned
    FOR v_vote IN
        SELECT * FROM swoop_votes
        WHERE initiative_id = p_initiative_id
        AND vote_status = 'pledged'
    LOOP
        -- Return credits to user (would integrate with user_balances)
        -- For now, just mark as returned
        UPDATE swoop_votes
        SET vote_status = 'returned'
        WHERE id = v_vote.id;

        v_returned_count := v_returned_count + 1;
    END LOOP;

    -- Update initiative status
    UPDATE swoop_initiatives
    SET
        status = 'cancelled',
        updated_at = NOW()
    WHERE id = p_initiative_id;

    -- Log cancellation
    INSERT INTO swoop_activation_log (
        initiative_id,
        action,
        vote_count_at_action,
        notes
    ) VALUES (
        p_initiative_id,
        'cancelled',
        (SELECT current_votes FROM swoop_initiatives WHERE id = p_initiative_id),
        'Initiative cancelled, pledges returned'
    );

    RETURN v_returned_count;
END;
$$;


ALTER FUNCTION "public"."return_swoop_pledges"("p_initiative_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."return_swoop_pledges"("p_initiative_id" "uuid") IS 'Returns pledged credits when initiative is cancelled';



CREATE OR REPLACE FUNCTION "public"."review_trunk_mirror_submission"("p_submission_id" "uuid", "p_action" "text", "p_notes" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_current_status TEXT;
  v_new_status TEXT;
  v_reviewer UUID := auth.uid();
BEGIN
  SELECT status INTO v_current_status
  FROM trunk_mirror_submissions
  WHERE id = p_submission_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Submission % not found', p_submission_id;
  END IF;

  CASE p_action
    WHEN 'start_review' THEN
      IF v_current_status NOT IN ('submitted') THEN
        RAISE EXCEPTION 'Can only start review on submitted items (current: %)', v_current_status;
      END IF;
      v_new_status := 'under_review';

    WHEN 'approve' THEN
      IF v_current_status NOT IN ('submitted', 'under_review') THEN
        RAISE EXCEPTION 'Can only approve submitted/under_review items (current: %)', v_current_status;
      END IF;
      v_new_status := 'approved';

    WHEN 'reject' THEN
      IF v_current_status NOT IN ('submitted', 'under_review') THEN
        RAISE EXCEPTION 'Can only reject submitted/under_review items (current: %)', v_current_status;
      END IF;
      v_new_status := 'rejected';

    WHEN 'deploy' THEN
      IF v_current_status NOT IN ('approved') THEN
        RAISE EXCEPTION 'Can only deploy approved items (current: %)', v_current_status;
      END IF;
      v_new_status := 'deployed';

    ELSE
      RAISE EXCEPTION 'Unknown action: %. Use start_review, approve, reject, or deploy', p_action;
  END CASE;

  UPDATE trunk_mirror_submissions
  SET status = v_new_status,
      reviewer_id = v_reviewer,
      reviewer_notes = COALESCE(p_notes, reviewer_notes),
      reviewed_at = CASE WHEN p_action IN ('approve', 'reject') THEN now() ELSE reviewed_at END,
      updated_at = now()
  WHERE id = p_submission_id;

  -- If approved, apply theme/CSS to the neighborhood
  IF v_new_status = 'deployed' THEN
    UPDATE neighborhoods n
    SET theme_config = COALESCE(tms.theme_config_draft, n.theme_config),
        custom_css = COALESCE(tms.custom_css_draft, n.custom_css)
    FROM trunk_mirror_submissions tms
    WHERE tms.id = p_submission_id AND n.id = tms.neighborhood_id;
  END IF;
END;
$$;


ALTER FUNCTION "public"."review_trunk_mirror_submission"("p_submission_id" "uuid", "p_action" "text", "p_notes" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."revoke_cost_plus_certification"("p_anchor_id" "uuid", "p_reason" "text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Update anchor
  UPDATE public.anchors
  SET verified_cost_plus = false,
      cost_plus_revoked_at = NOW(),
      cost_plus_revoked_reason = p_reason,
      updated_at = NOW()
  WHERE id = p_anchor_id;

  -- Create revocation audit record
  INSERT INTO public.cost_plus_audits (
    anchor_id,
    requested_by,
    request_type,
    status,
    reviewed_by,
    review_notes,
    reviewed_at
  ) VALUES (
    p_anchor_id,
    auth.uid(),
    'certification',
    'revoked',
    auth.uid(),
    p_reason,
    NOW()
  );

  RETURN true;
END;
$$;


ALTER FUNCTION "public"."revoke_cost_plus_certification"("p_anchor_id" "uuid", "p_reason" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."revoke_cost_plus_certification"("p_anchor_id" "uuid", "p_reason" "text") IS 'Revoke C+20 certification from an anchor (admin only)';



CREATE OR REPLACE FUNCTION "public"."revoke_vault_sharing"("p_authorization_id" "uuid", "p_reason" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
    UPDATE vault_sharing_authorizations
    SET
        is_active = false,
        revoked_at = NOW(),
        revoked_reason = p_reason,
        updated_at = NOW()
    WHERE id = p_authorization_id
    AND granter_user_id = auth.uid();

    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'Authorization not found or not yours');
    END IF;

    RETURN jsonb_build_object('success', true, 'revoked', true);
END;
$$;


