CREATE OR REPLACE FUNCTION "public"."touch_engagement_ingestion_worker"("p_worker_name" "text", "p_success" boolean, "p_error_message" "text" DEFAULT NULL::"text", "p_stats" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  INSERT INTO public.engagement_ingestion_worker_status (
    worker_name,
    last_run_at,
    last_success_at,
    last_error_at,
    error_count,
    last_error_message,
    last_stats,
    updated_at
  )
  VALUES (
    p_worker_name,
    now(),
    CASE WHEN p_success THEN now() ELSE NULL END,
    CASE WHEN p_success THEN NULL ELSE now() END,
    CASE WHEN p_success THEN 0 ELSE 1 END,
    CASE WHEN p_success THEN NULL ELSE p_error_message END,
    COALESCE(p_stats, '{}'::jsonb),
    now()
  )
  ON CONFLICT (worker_name)
  DO UPDATE SET
    last_run_at = now(),
    last_success_at = CASE
      WHEN p_success THEN now()
      ELSE public.engagement_ingestion_worker_status.last_success_at
    END,
    last_error_at = CASE
      WHEN p_success THEN public.engagement_ingestion_worker_status.last_error_at
      ELSE now()
    END,
    error_count = CASE
      WHEN p_success THEN 0
      ELSE public.engagement_ingestion_worker_status.error_count + 1
    END,
    last_error_message = CASE
      WHEN p_success THEN NULL
      ELSE p_error_message
    END,
    last_stats = COALESCE(p_stats, '{}'::jsonb),
    updated_at = now();
END;
$$;


ALTER FUNCTION "public"."touch_engagement_ingestion_worker"("p_worker_name" "text", "p_success" boolean, "p_error_message" "text", "p_stats" "jsonb") OWNER TO "postgres";


