CREATE OR REPLACE FUNCTION "public"."track_first_transaction"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- If this is a credit-spending activity and first_transaction_at is null
  IF NEW.used_credits > OLD.used_credits AND OLD.first_transaction_at IS NULL THEN
    NEW.first_transaction_at := NOW();
  END IF;

  -- Always update last_activity_at
  NEW.last_activity_at := NOW();

  RETURN NEW;
END;
