CREATE OR REPLACE FUNCTION "public"."update_aggregation_window_stats"("window_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_stats RECORD;
BEGIN
  SELECT
    COUNT(DISTINCT user_id) as participant_count,
    COUNT(*) as total_items,
    SUM(COALESCE(max_price_per_unit * quantity, 5.00)) as total_value,
    COUNT(DISTINCT ingredient_normalized) as unique_ingredients
  INTO v_stats
  FROM ingredient_demand_entries
  WHERE aggregation_window_id = window_id
    AND aggregation_status = 'aggregated';

  UPDATE demand_aggregation_windows SET
    participant_count = COALESCE(v_stats.participant_count, 0),
    total_items = COALESCE(v_stats.total_items, 0),
    total_estimated_value = COALESCE(v_stats.total_value, 0),
    unique_ingredients = COALESCE(v_stats.unique_ingredients, 0),
    updated_at = now()
  WHERE id = window_id;

  -- Check if threshold is met
  PERFORM check_aggregation_threshold(window_id);
END;
$$;


ALTER FUNCTION "public"."update_aggregation_window_stats"("window_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."update_beacon_run_stats"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.status = 'completed' AND OLD.status = 'in_progress' THEN
    -- Update run stats
    UPDATE beacon_runs
    SET
      times_completed = times_completed + 1,
      best_time_seconds = CASE
        WHEN best_time_seconds IS NULL OR NEW.elapsed_seconds < best_time_seconds
        THEN NEW.elapsed_seconds
        ELSE best_time_seconds
      END,
      best_time_user_id = CASE
        WHEN best_time_seconds IS NULL OR NEW.elapsed_seconds < best_time_seconds
        THEN NEW.user_id
        ELSE best_time_user_id
      END
    WHERE id = NEW.run_id;

    -- Insert leaderboard entry
    INSERT INTO beacon_run_leaderboard (run_id, user_id, completion_time_seconds)
    VALUES (NEW.run_id, NEW.user_id, NEW.elapsed_seconds);
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."update_beacon_run_stats"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."update_bond_account_totals"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Update the bond account totals
  UPDATE bond_accounts
  SET
    locked_joules = COALESCE((
      SELECT SUM(joules_locked)
      FROM bond_allocations
      WHERE bond_account_id = NEW.bond_account_id
      AND status = 'locked'
    ), 0),
    available_joules = total_joules - COALESCE((
      SELECT SUM(joules_locked)
      FROM bond_allocations
      WHERE bond_account_id = NEW.bond_account_id
      AND status = 'locked'
    ), 0),
    updated_at = NOW()
  WHERE id = NEW.bond_account_id;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."update_bond_account_totals"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."update_buying_coalition_stats"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  member_count INT;
  new_discount NUMERIC(4,2);
BEGIN
  SELECT COUNT(*) INTO member_count
  FROM buying_coalition_members
  WHERE coalition_id = COALESCE(NEW.coalition_id, OLD.coalition_id);

  IF member_count >= 50 THEN new_discount := 20.00;
  ELSIF member_count >= 25 THEN new_discount := 15.00;
  ELSIF member_count >= 10 THEN new_discount := 10.00;
  ELSIF member_count >= 5 THEN new_discount := 5.00;
  ELSE new_discount := 0;
  END IF;

  UPDATE buying_coalitions SET
    current_members = member_count,
    discount_tier = new_discount,
    status = CASE
      WHEN member_count >= (SELECT min_members FROM buying_coalitions WHERE id = COALESCE(NEW.coalition_id, OLD.coalition_id))
      THEN 'active' ELSE 'forming' END
  WHERE id = COALESCE(NEW.coalition_id, OLD.coalition_id);

  RETURN COALESCE(NEW, OLD);
END;
$$;


ALTER FUNCTION "public"."update_buying_coalition_stats"() OWNER TO "postgres";


