CREATE OR REPLACE FUNCTION "public"."update_channel_subscriber_count"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  IF TG_OP = 'INSERT' AND NEW.status = 'active' THEN
    UPDATE subscription_channels
    SET current_subscribers = current_subscribers + 1, updated_at = now()
    WHERE id = NEW.channel_id;
  ELSIF TG_OP = 'UPDATE' THEN
    IF OLD.status = 'active' AND NEW.status != 'active' THEN
      UPDATE subscription_channels
      SET current_subscribers = GREATEST(0, current_subscribers - 1), updated_at = now()
      WHERE id = NEW.channel_id;
    ELSIF OLD.status != 'active' AND NEW.status = 'active' THEN
      UPDATE subscription_channels
      SET current_subscribers = current_subscribers + 1, updated_at = now()
      WHERE id = NEW.channel_id;
    END IF;
  ELSIF TG_OP = 'DELETE' AND OLD.status = 'active' THEN
    UPDATE subscription_channels
    SET current_subscribers = GREATEST(0, current_subscribers - 1), updated_at = now()
    WHERE id = OLD.channel_id;
  END IF;
  RETURN COALESCE(NEW, OLD);
END;
$$;


ALTER FUNCTION "public"."update_channel_subscriber_count"() OWNER TO "postgres";


