CREATE OR REPLACE FUNCTION "public"."update_gift_amount"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.payment_status = 'completed' AND (OLD.payment_status IS NULL OR OLD.payment_status != 'completed') THEN
    UPDATE public.santa_gifts
    SET current_amount = current_amount + NEW.amount,
        updated_at = now(),
        status = CASE
          WHEN current_amount + NEW.amount >= goal_amount THEN 'funded'
          ELSE status
        END,
        funded_at = CASE
          WHEN current_amount + NEW.amount >= goal_amount THEN now()
          ELSE funded_at
        END
    WHERE id = NEW.gift_id;

    UPDATE public.santas
    SET total_contributed = total_contributed + NEW.amount,
        gifts_backed = gifts_backed + 1,
        current_level = CASE
          WHEN total_contributed + NEW.amount >= 350 THEN 'full_sponsor'
          WHEN total_contributed + NEW.amount >= 100 THEN 'inferno'
          WHEN total_contributed + NEW.amount >= 50 THEN 'blaze'
          WHEN total_contributed + NEW.amount >= 25 THEN 'flame'
          WHEN total_contributed + NEW.amount >= 10 THEN 'kindle'
          ELSE 'spark'
        END,
        updated_at = now()
    WHERE id = NEW.santa_id;

    UPDATE public.santa_stats
    SET total_pledged = total_pledged + NEW.amount,
        updated_at = now();
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."update_gift_amount"() OWNER TO "postgres";


