CREATE OR REPLACE FUNCTION "public"."update_hexisle_resources"("p_user_id" "uuid", "p_water" integer DEFAULT 0, "p_credits" integer DEFAULT 0, "p_materials" integer DEFAULT 0, "p_food" integer DEFAULT 0) RETURNS "public"."hexisle_player_state"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  result hexisle_player_state;
BEGIN
  UPDATE hexisle_player_state
  SET
    water = GREATEST(0, water + p_water),
    credits = GREATEST(0, credits + p_credits),
    materials = GREATEST(0, materials + p_materials),
    food = GREATEST(0, food + p_food),
    updated_at = NOW()
  WHERE user_id = p_user_id
  RETURNING * INTO result;

  RETURN result;
END;
$$;


