CREATE OR REPLACE FUNCTION "public"."update_shopping_participant_count"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
    IF TG_OP = 'INSERT' THEN
        UPDATE gift_shopping_aggregations
        SET current_participants = current_participants + 1,
            discount_tier = CASE
                WHEN current_participants + 1 >= 10 THEN 3
                WHEN current_participants + 1 >= 5 THEN 2
                WHEN current_participants + 1 >= 2 THEN 1
                ELSE 0
            END,
            updated_at = NOW()
        WHERE id = NEW.aggregation_id;
        RETURN NEW;
    ELSIF TG_OP = 'DELETE' THEN
        UPDATE gift_shopping_aggregations
        SET current_participants = GREATEST(0, current_participants - 1),
            discount_tier = CASE
                WHEN current_participants - 1 >= 10 THEN 3
                WHEN current_participants - 1 >= 5 THEN 2
                WHEN current_participants - 1 >= 2 THEN 1
                ELSE 0
            END,
            updated_at = NOW()
        WHERE id = OLD.aggregation_id;
        RETURN OLD;
    END IF;
    RETURN NULL;
END;
$$;


ALTER FUNCTION "public"."update_shopping_participant_count"() OWNER TO "postgres";


