CREATE OR REPLACE FUNCTION "public"."upsert_battery_dispatch_grant"("p_user_id" "uuid", "p_access_source" "text", "p_source_ref_id" "text" DEFAULT NULL::"text", "p_status" "text" DEFAULT 'active'::"text", "p_notes" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF p_access_source NOT IN ('influencer', 'project', 'harper', 'jukebox_artist', 'crown', 'captain', 'staff_override') THEN
    RAISE EXCEPTION 'Invalid access source: %', p_access_source;
  END IF;

  IF p_status NOT IN ('active', 'suspended', 'revoked') THEN
    RAISE EXCEPTION 'Invalid status: %', p_status;
  END IF;

  INSERT INTO public.battery_dispatch_access (
    user_id, access_source, source_ref_id, status, notes, granted_at, last_active_at, created_at, updated_at
  )
  VALUES (
    p_user_id, p_access_source, p_source_ref_id, p_status, p_notes, now(), now(), now(), now()
  )
  ON CONFLICT (user_id, access_source, source_ref_id)
  DO UPDATE
    SET status = EXCLUDED.status,
        notes = COALESCE(EXCLUDED.notes, public.battery_dispatch_access.notes),
        last_active_at = now(),
        updated_at = now();
END;
$$;


ALTER FUNCTION "public"."upsert_battery_dispatch_grant"("p_user_id" "uuid", "p_access_source" "text", "p_source_ref_id" "text", "p_status" "text", "p_notes" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."use_candle"("p_user_id" "uuid", "p_amount" numeric, "p_is_babylon" boolean DEFAULT false) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_candles RECORD;
BEGIN
  SELECT * INTO v_candles FROM user_candles WHERE user_id = p_user_id;

  IF v_candles IS NULL THEN
    RETURN FALSE;
  END IF;

  IF p_is_babylon THEN
    IF v_candles.babylon_amount < p_amount THEN
      RETURN FALSE;
    END IF;
    UPDATE user_candles SET babylon_amount = babylon_amount - p_amount WHERE user_id = p_user_id;
  ELSE
    IF v_candles.standard_amount < p_amount THEN
      RETURN FALSE;
    END IF;
    UPDATE user_candles SET standard_amount = standard_amount - p_amount WHERE user_id = p_user_id;
  END IF;

  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."use_candle"("p_user_id" "uuid", "p_amount" numeric, "p_is_babylon" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."user_is_battery_dispatch_staff"() RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF auth.role() = 'service_role' THEN
    RETURN true;
  END IF;

  IF to_regclass('public.staff_members') IS NOT NULL THEN
    IF EXISTS (
      SELECT 1
      FROM public.staff_members sm
      WHERE sm.user_id = auth.uid()
    ) THEN
      RETURN true;
    END IF;
  END IF;

  IF to_regclass('public.user_roles') IS NOT NULL THEN
    IF EXISTS (
      SELECT 1
      FROM public.user_roles ur
      WHERE ur.user_id = auth.uid()
        AND ur.role IN ('admin', 'staff')
    ) THEN
      RETURN true;
    END IF;
  END IF;

  IF to_regclass('public.crown_positions') IS NOT NULL THEN
    IF EXISTS (
      SELECT 1
      FROM public.crown_positions cp
      WHERE cp.holder_user_id = auth.uid()
    ) THEN
      RETURN true;
    END IF;
  END IF;

  IF to_regclass('public.guilds') IS NOT NULL THEN
    IF EXISTS (
      SELECT 1
      FROM public.guilds g
      WHERE g.guild_master_id = auth.uid()
    ) THEN
      RETURN true;
    END IF;
  END IF;

  RETURN false;
END;
$$;


ALTER FUNCTION "public"."user_is_battery_dispatch_staff"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."user_is_founder_for_contacts"() RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF auth.role() = 'service_role' THEN
    RETURN true;
  END IF;

  IF EXISTS (
    SELECT 1
    FROM public.user_roles ur
    WHERE ur.user_id = auth.uid()
      AND ur.role IN ('founder', 'owner', 'admin')
  ) THEN
    RETURN true;
  END IF;

  IF to_regclass('public.staff_members') IS NOT NULL THEN
    IF EXISTS (
      SELECT 1
      FROM public.staff_members sm
      WHERE sm.user_id = auth.uid()
        AND lower(coalesce(sm.role, '')) IN ('founder', 'owner', 'admin')
    ) THEN
      RETURN true;
    END IF;
  END IF;

  RETURN false;
END;
$$;


ALTER FUNCTION "public"."user_is_founder_for_contacts"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."validate_neighborhood_content"("p_description" "text" DEFAULT NULL::"text", "p_welcome_message" "text" DEFAULT NULL::"text", "p_custom_css" "text" DEFAULT NULL::"text", "p_theme_config" "jsonb" DEFAULT NULL::"jsonb", "p_hero_image_url" "text" DEFAULT NULL::"text") RETURNS TABLE("field_name" "text", "category" "text", "severity" "text", "pattern_id" "uuid", "description" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    f.field_name,
    npp.category,
    npp.severity,
    npp.id AS pattern_id,
    npp.description
  FROM neighborhood_prohibited_patterns npp
  CROSS JOIN LATERAL (
    VALUES
      ('description', p_description),
      ('welcome_message', p_welcome_message),
      ('custom_css', p_custom_css),
      ('theme_config', p_theme_config::text),
      ('hero_image_url', p_hero_image_url)
  ) AS f(field_name, field_value)
  WHERE npp.is_active = true
    AND f.field_name = ANY(npp.applies_to)
    AND f.field_value IS NOT NULL
    AND f.field_value ~ npp.pattern;
END;
$$;


ALTER FUNCTION "public"."validate_neighborhood_content"("p_description" "text", "p_welcome_message" "text", "p_custom_css" "text", "p_theme_config" "jsonb", "p_hero_image_url" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."verify_cue_card"("p_payload_hash" "text") RETURNS TABLE("is_valid" boolean, "trust_score" integer, "business_name" "text", "anchor_url" "text", "charitable_tier" "text", "charitable_icon" "text", "first_seen" timestamp with time zone, "total_scans" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    (ccr.security_state = 'valid') AS is_valid,
    ccr.trust_score,
    a.display_name AS business_name,
    a.destination_url AS anchor_url,
    cbt.display_name AS charitable_tier,
    cbt.icon AS charitable_icon,
    ccr.first_seen,
    ccr.total_scans
  FROM public.cue_card_registry ccr
  LEFT JOIN public.anchors a ON ccr.anchor_id = a.id
  LEFT JOIN public.charitable_business_tiers cbt ON a.charitable_tier_id = cbt.id
  WHERE ccr.payload_hash = p_payload_hash;
END;
$$;


ALTER FUNCTION "public"."verify_cue_card"("p_payload_hash" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."verify_cue_card"("p_herald_id" "uuid", "p_context_id" "uuid") RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_destination RECORD;
  v_leviathan RECORD;
  v_owner RECORD;
  v_projects JSON;
BEGIN
  -- Fetch destination
  SELECT * INTO v_destination
  FROM cue_card_destinations
  WHERE id = p_context_id AND user_id = p_herald_id;

  IF NOT FOUND THEN
    RETURN JSON_BUILD_OBJECT(
      'valid', false,
      'error', 'Destination not found or does not belong to herald'
    );
  END IF;

  -- Fetch Leviathan record
  SELECT * INTO v_leviathan
  FROM leviathan_cue_cards
  WHERE destination_id = p_context_id;

  -- Fetch owner info
  SELECT display_name, full_name INTO v_owner
  FROM profiles
  WHERE id = p_herald_id;

  -- Fetch bound projects
  IF v_destination.destination_type IN ('single_project', 'multi_project') THEN
    SELECT JSON_AGG(JSON_BUILD_OBJECT('id', p.id, 'name', p.name))
    INTO v_projects
    FROM projects p
    WHERE p.id = ANY(v_destination.project_ids);
  END IF;

  -- Increment scan count
  UPDATE leviathan_cue_cards
  SET total_scans = total_scans + 1, last_scan_at = NOW()
  WHERE destination_id = p_context_id;

  RETURN JSON_BUILD_OBJECT(
    'valid', true,
    'verification_status', COALESCE(v_leviathan.verification_status, 'verified'),
    'trust_score', COALESCE(v_leviathan.trust_score, 100),
    'card_code', v_leviathan.card_code,
    'stamp_owner', COALESCE(v_owner.display_name, v_owner.full_name, 'Unknown'),
    'destination_type', v_destination.destination_type,
    'bound_projects', v_projects,
    'category_slug', v_destination.category_slug,
    'is_own_project', v_destination.is_own_project,
    'total_scans', COALESCE(v_leviathan.total_scans, 0) + 1,
    'created_at', v_destination.created_at
  );
END;
$$;


ALTER FUNCTION "public"."verify_cue_card"("p_herald_id" "uuid", "p_context_id" "uuid") OWNER TO "postgres";


