    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "member_scribes_adjacents_max_12" CHECK (("jsonb_array_length"("adjacents") <= 12)),
    CONSTRAINT "member_scribes_name_not_empty" CHECK (("length"(TRIM(BOTH FROM "name")) > 0)),
    CONSTRAINT "member_scribes_share_target_consistency" CHECK (((("share_level" = ANY (ARRAY['guild'::"cathedral"."share_level_enum", 'tribe'::"cathedral"."share_level_enum"])) AND ("share_target_id" IS NOT NULL)) OR (("share_level" = ANY (ARRAY['private'::"cathedral"."share_level_enum", 'commons'::"cathedral"."share_level_enum"])) AND ("share_target_id" IS NULL))))
);


