COMMENT ON TABLE "cathedral"."scribe_entries" IS '#2270 Claim 1(b): append-only Scribe tablet entries. NO UPDATE, NO DELETE policies (RLS deny by default). shared_level is materialized at INSERT time from the parent Scribe and is IMMUTABLE per #2268 semantics.';



CREATE OR REPLACE VIEW "cathedral"."member_cathedral_health" WITH ("security_invoker"='true') AS
 SELECT "mc"."member_id",
    "mc"."tier",
    "mc"."created_at" AS "cathedral_created_at",
    "mc"."last_sync_at",
    "mc"."export_count",
    "mc"."export_last_at",
    "mc"."professional_domain",
    COALESCE("s"."scribe_count", (0)::bigint) AS "scribe_count",
    COALESCE("s"."active_scribe_count", (0)::bigint) AS "active_scribe_count",
    COALESCE("e"."entry_count", (0)::bigint) AS "entry_count",
    "e"."last_entry_at"
   FROM (("cathedral"."member_cathedrals" "mc"
     LEFT JOIN ( SELECT "member_scribes"."member_id",
            "count"(*) AS "scribe_count",
            "count"(*) FILTER (WHERE "member_scribes"."active") AS "active_scribe_count"
           FROM "cathedral"."member_scribes"
          GROUP BY "member_scribes"."member_id") "s" ON (("s"."member_id" = "mc"."member_id")))
     LEFT JOIN ( SELECT "scribe_entries"."member_id",
            "count"(*) AS "entry_count",
            "max"("scribe_entries"."ts") AS "last_entry_at"
           FROM "cathedral"."scribe_entries"
          GROUP BY "scribe_entries"."member_id") "e" ON (("e"."member_id" = "mc"."member_id")));


ALTER VIEW "cathedral"."member_cathedral_health" OWNER TO "postgres";


COMMENT ON VIEW "cathedral"."member_cathedral_health" IS 'Aggregated health card for /my/cathedral landing. security_invoker=true so the underlying member_cathedrals RLS policy filters to the caller.';



