CREATE OR REPLACE VIEW "public"."all_cephas_content" AS
 SELECT 'pudding'::"text" AS "content_type",
    ("p"."id")::"text" AS "content_id",
    "p"."title",
    "left"(COALESCE("p"."pudding_text", "p"."not_pudding_summary", ''::"text"), 150) AS "excerpt",
    "p"."primary_spice",
    ARRAY( SELECT "unnest"(COALESCE("p"."secondary_spices", '{}'::"text"[])) AS "unnest") AS "secondary_spices",
    "p"."created_at" AS "publish_date",
    GREATEST(1, ("ceil"(((GREATEST(1, "array_length"("regexp_split_to_array"(COALESCE("p"."pudding_text", ''::"text"), '\s+'::"text"), 1)))::numeric / 200.0)))::integer) AS "estimated_reading_minutes",
    COALESCE("p"."pepper_rating_avg", (0)::numeric) AS "pepper_rating_avg",
    COALESCE("p"."view_count", 0) AS "view_count",
    "p"."source_paper",
    "p"."pudding_text"
   FROM "public"."cephas_puddings" "p"
  WHERE ("p"."status" = ANY (ARRAY['draft'::"text", 'published'::"text"]))
UNION ALL
 SELECT
        CASE
            WHEN ("e"."channel" = 'bst'::"text") THEN 'bst_episode'::"text"
            WHEN ("e"."channel" = 'spoonfuls'::"text") THEN 'spoonful'::"text"
            WHEN ("e"."channel" = 'skipping_stones'::"text") THEN 'skipping_stone'::"text"
            ELSE 'bst_episode'::"text"
        END AS "content_type",
    ("e"."id")::"text" AS "content_id",
        CASE
            WHEN ("e"."channel" = 'bst'::"text") THEN 'BST Episode'::"text"
            WHEN ("e"."channel" = 'spoonfuls'::"text") THEN 'Spoonful'::"text"
            WHEN ("e"."channel" = 'skipping_stones'::"text") THEN 'Skipping Stone'::"text"
            ELSE 'Episode'::"text"
        END AS "title",
    "left"("e"."content", 150) AS "excerpt",
    ("e"."primary_spice")::"text" AS "primary_spice",
    ARRAY( SELECT ("unnest"(COALESCE("e"."secondary_spices", '{}'::"public"."spice_type"[])))::"text" AS "unnest") AS "secondary_spices",
    COALESCE("e"."scheduled_for", "e"."created_at") AS "publish_date",
    GREATEST(1, ("ceil"(((GREATEST(1, "array_length"("regexp_split_to_array"(COALESCE("e"."content", ''::"text"), '\s+'::"text"), 1)))::numeric / 200.0)))::integer) AS "estimated_reading_minutes",
    (0)::numeric AS "pepper_rating_avg",
    0 AS "view_count",
    NULL::"text" AS "source_paper",
    "e"."content" AS "pudding_text"
   FROM "public"."crewman_episodes" "e"
  WHERE ("e"."channel" = ANY (ARRAY['bst'::"text", 'spoonfuls'::"text", 'skipping_stones'::"text"]))
UNION ALL
 SELECT 'news_slot'::"text" AS "content_type",
    ("n"."id")::"text" AS "content_id",
    'News Slot'::"text" AS "title",
    "left"("n"."content", 150) AS "excerpt",
    NULL::"text" AS "primary_spice",
    '{}'::"text"[] AS "secondary_spices",
    COALESCE((((("n"."scheduled_date")::"text" || ' '::"text") || ("n"."slot_time")::"text"))::timestamp with time zone, "n"."created_at") AS "publish_date",
    2 AS "estimated_reading_minutes",
    (0)::numeric AS "pepper_rating_avg",
    0 AS "view_count",
    NULL::"text" AS "source_paper",
    "n"."content" AS "pudding_text"
   FROM "public"."distribution_news_slots" "n"
  WHERE ("n"."status" = ANY (ARRAY['scheduled'::"text", 'dispatched'::"text"]));


ALTER VIEW "public"."all_cephas_content" OWNER TO "postgres";


