CREATE OR REPLACE VIEW "public"."analytics_daily_summary" AS
 SELECT "date"("created_at") AS "event_date",
    "event_type",
    "count"(*) AS "event_count",
    "count"(DISTINCT "user_id") AS "unique_users",
    "count"(DISTINCT "session_id") AS "unique_sessions"
   FROM "public"."analytics_events"
  GROUP BY ("date"("created_at")), "event_type"
  ORDER BY ("date"("created_at")) DESC, ("count"(*)) DESC;


ALTER VIEW "public"."analytics_daily_summary" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."analytics_page_views" AS
 SELECT "date"("created_at") AS "view_date",
    "page_path",
    "count"(*) AS "view_count",
    "count"(DISTINCT "user_id") AS "unique_viewers",
    "count"(DISTINCT "session_id") AS "unique_sessions"
   FROM "public"."analytics_events"
  WHERE ("event_type" = 'page_view'::"text")
  GROUP BY ("date"("created_at")), "page_path"
  ORDER BY ("date"("created_at")) DESC, ("count"(*)) DESC;


ALTER VIEW "public"."analytics_page_views" OWNER TO "postgres";


