CREATE OR REPLACE VIEW "public"."battery_dispatch_access_status" AS
 SELECT "user_id",
    "bool_or"(("status" = 'active'::"text")) AS "has_access",
    COALESCE("array_agg"(DISTINCT "access_source") FILTER (WHERE ("status" = 'active'::"text")), ARRAY[]::"text"[]) AS "active_sources",
    "max"("last_active_at") AS "most_recent_activity",
    "count"(*) FILTER (WHERE ("status" = 'active'::"text")) AS "active_grant_count"
   FROM "public"."battery_dispatch_access" "bda"
  GROUP BY "user_id";


