    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "entity_type" "text" NOT NULL,
    "entity_id" "uuid" NOT NULL,
    "label" "text" NOT NULL,
    "current_value" numeric DEFAULT 0 NOT NULL,
    "target_value" numeric DEFAULT 1 NOT NULL,
    "cp_score" numeric GENERATED ALWAYS AS (
CASE
    WHEN ("target_value" > (0)::numeric) THEN LEAST((("current_value" / "target_value") * (100)::numeric), (100)::numeric)
    ELSE (0)::numeric
END) STORED,
    "launched_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "catapult_metrics_entity_type_check" CHECK (("entity_type" = ANY (ARRAY['project'::"text", 'petition'::"text", 'vote'::"text", 'campaign'::"text", 'initiative'::"text", 'submission'::"text", 'deck_card_print'::"text"])))
