CREATE OR REPLACE VIEW "public"."city_neighborhood_stats" AS
 SELECT "city",
    "state",
    "region",
    "count"(*) FILTER (WHERE ("status" = 'active'::"text")) AS "active_neighborhoods",
    "count"(*) AS "total_neighborhoods",
    COALESCE("sum"("storefront_count"), (0)::bigint) AS "total_storefronts",
    COALESCE("sum"("visitor_count"), (0)::bigint) AS "total_visitors",
    COALESCE("avg"("harper_score") FILTER (WHERE ("harper_score" > (0)::numeric)), (0)::numeric) AS "avg_harper_score",
    COALESCE("avg"("rating_avg") FILTER (WHERE ("rating_count" > 0)), (0)::numeric) AS "avg_rating",
    "max"("created_at") AS "newest_neighborhood"
   FROM "public"."neighborhoods"
  GROUP BY "city", "state", "region"
  ORDER BY ("count"(*) FILTER (WHERE ("status" = 'active'::"text"))) DESC, COALESCE("sum"("visitor_count"), (0)::bigint) DESC;


ALTER VIEW "public"."city_neighborhood_stats" OWNER TO "postgres";


