CREATE TABLE IF NOT EXISTS "public"."cooperative_purchases" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tip_id" "uuid",
    "initiator_id" "uuid" NOT NULL,
    "title" "text" NOT NULL,
    "description" "text",
    "store_name" "text",
    "store_location" "text",
    "unit_price_retail" numeric,
    "unit_price_cooperative" numeric,
    "savings_percentage" numeric GENERATED ALWAYS AS (
CASE
    WHEN ("unit_price_retail" > (0)::numeric) THEN "round"((((1)::numeric - ("unit_price_cooperative" / "unit_price_retail")) * (100)::numeric), 1)
    ELSE (0)::numeric
END) STORED,
    "target_quantity" integer NOT NULL,
    "threshold_quantity" integer DEFAULT 5 NOT NULL,
    "current_quantity" integer DEFAULT 0,
    "status" "text" DEFAULT 'gathering'::"text",
    "participants" "jsonb" DEFAULT '[]'::"jsonb",
    "expires_at" timestamp with time zone DEFAULT ("now"() + '72:00:00'::interval) NOT NULL,
