    "expires_at" timestamp with time zone DEFAULT ("now"() + '30 days'::interval),
    CONSTRAINT "defense_klaus_referrals_slot_number_check" CHECK (("slot_number" = ANY (ARRAY[1, 2]))),
    CONSTRAINT "defense_klaus_referrals_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'accepted'::"text", 'expired'::"text"])))
);


