CREATE OR REPLACE VIEW "public"."defense_klaus_daisy_chain_stats" AS
 SELECT "count"(*) AS "total_referrals",
    "count"(*) FILTER (WHERE ("status" = 'pending'::"text")) AS "pending_referrals",
    "count"(*) FILTER (WHERE ("status" = 'accepted'::"text")) AS "accepted_referrals",
    "count"(DISTINCT "referrer_proxy_id") AS "unique_referrers",
    "round"(((("count"(*) FILTER (WHERE ("status" = 'accepted'::"text")))::numeric / (NULLIF("count"(*), 0))::numeric) * (100)::numeric), 2) AS "acceptance_rate"
   FROM "public"."defense_klaus_referrals";


