CREATE OR REPLACE VIEW "public"."engagement_events_per_platform_hour" AS
 SELECT "platform",
    "date_trunc"('hour'::"text", "recorded_at") AS "hour_bucket",
    "count"(*) AS "rows_inserted",
    COALESCE("sum"("event_count"), (0)::bigint) AS "events_recorded"
   FROM "public"."chapter_engagement_events"
  GROUP BY "platform", ("date_trunc"('hour'::"text", "recorded_at"));


ALTER VIEW "public"."engagement_events_per_platform_hour" OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."social_post_mapping" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "platform" "text" NOT NULL,
    "external_post_id" "text" NOT NULL,
    "chapter_id" "text" NOT NULL,
    "episode_number" integer,
    "posted_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL
);


ALTER TABLE "public"."social_post_mapping" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."engagement_ingestion_coverage_gaps" AS
 SELECT "spm"."platform",
    "spm"."external_post_id" AS "platform_post_id",
    "spm"."chapter_id",
    "spm"."episode_number",
    "spm"."posted_at",
    "count"("cee"."id") AS "engagement_rows",
    COALESCE("sum"("cee"."event_count"), (0)::bigint) AS "engagement_total",
    "max"("cee"."recorded_at") AS "last_event_at"
   FROM ("public"."social_post_mapping" "spm"
     LEFT JOIN "public"."chapter_engagement_events" "cee" ON ((("cee"."platform" = "spm"."platform") AND ("cee"."platform_post_id" = "spm"."external_post_id"))))
  WHERE ("spm"."posted_at" >= ("now"() - '72:00:00'::interval))
  GROUP BY "spm"."platform", "spm"."external_post_id", "spm"."chapter_id", "spm"."episode_number", "spm"."posted_at"
 HAVING ("count"("cee"."id") = 0);


ALTER VIEW "public"."engagement_ingestion_coverage_gaps" OWNER TO "postgres";


