COMMENT ON TABLE "public"."pantry_recipes" IS 'Recipe repository - The Pantry. Creators earn fractional credits per use with diminishing returns and $500 cap.';



COMMENT ON COLUMN "public"."pantry_recipes"."is_credit_capped" IS 'True when recipe has earned $500 lifetime cap - after which Cooking Spoon badges are awarded instead';



COMMENT ON COLUMN "public"."pantry_recipes"."escape_velocity_reached" IS 'True when recipe hits 100+ votes, earning IP Ledger protection';



COMMENT ON COLUMN "public"."pantry_recipes"."ip_ledger_hash" IS 'SHA-256 hash recorded to acknowledgment_stamps for permanent attribution';



CREATE OR REPLACE VIEW "public"."family_shopping_aggregation" WITH ("security_invoker"='true') AS
 SELECT "fmp"."user_id",
    "fmp"."tribe_id",
    "fmp"."meal_date",
    "pri"."ingredient_name",
    "pri"."normalized_name",
    "pri"."unit",
    "sum"((("pri"."quantity" * (COALESCE("fmp"."servings", 1))::numeric) / (NULLIF("pr"."servings", 0))::numeric)) AS "total_quantity",
    "pri"."category",
    "array_agg"(DISTINCT "pr"."id") AS "recipe_ids",
    "array_agg"(DISTINCT "fmp"."id") AS "meal_plan_ids"
   FROM (("public"."family_meal_plans" "fmp"
     JOIN "public"."pantry_recipes" "pr" ON (("fmp"."recipe_id" = "pr"."id")))
     JOIN "public"."pantry_recipe_ingredients" "pri" ON (("pr"."id" = "pri"."recipe_id")))
  WHERE (("fmp"."include_in_shopping" = true) AND ("fmp"."status" = ANY (ARRAY['planned'::"text", 'shopping'::"text"])))
  GROUP BY "fmp"."user_id", "fmp"."tribe_id", "fmp"."meal_date", "pri"."ingredient_name", "pri"."normalized_name", "pri"."unit", "pri"."category";


ALTER VIEW "public"."family_shopping_aggregation" OWNER TO "postgres";


