    "feature_type" "text" NOT NULL,
    "usage_date" "date" DEFAULT CURRENT_DATE NOT NULL,
    "first_used_at" timestamp with time zone DEFAULT "now"(),
    "last_used_at" timestamp with time zone DEFAULT "now"(),
    "usage_count" integer DEFAULT 1,
    "session_duration_seconds" integer,
    "converted_to_member" boolean DEFAULT false,
    "conversion_date" "date",
    "created_at" timestamp with time zone DEFAULT "now"(),
    CONSTRAINT "free_daily_usage_feature_type_check" CHECK (("feature_type" = ANY (ARRAY['hexisle_simulation'::"text", 'business_simulator'::"text", 'thought_experiment'::"text", 'recipe_simulation'::"text", 'marketplace_preview'::"text", 'guild_preview'::"text", 'position_preview'::"text"])))
);


ALTER TABLE "public"."free_daily_usage" OWNER TO "postgres";


COMMENT ON TABLE "public"."free_daily_usage" IS 'Tracks free daily feature usage. Non-members get limited throws; $5 members get unlimited.
Philosophy: "Rich kids get unlimited throws. We give everyone at least one free throw per day."';



CREATE OR REPLACE VIEW "public"."free_daily_analytics" WITH ("security_invoker"='true') AS
 SELECT "usage_date",
    "feature_type",
    "count"(DISTINCT COALESCE(("user_id")::"text", "device_fingerprint", "ip_hash")) AS "unique_users",
    "sum"("usage_count") AS "total_uses",
    "count"(DISTINCT "user_id") AS "logged_in_users",
    "count"(*) FILTER (WHERE (("device_fingerprint" IS NOT NULL) AND ("user_id" IS NULL))) AS "anonymous_users",
    "sum"(
        CASE
            WHEN "converted_to_member" THEN 1
            ELSE 0
        END) AS "conversions",
    "round"(((100.0 * ("sum"(
        CASE
            WHEN "converted_to_member" THEN 1
            ELSE 0
        END))::numeric) / (NULLIF("count"(*), 0))::numeric), 2) AS "conversion_rate"
   FROM "public"."free_daily_usage"
  GROUP BY "usage_date", "feature_type"
  ORDER BY "usage_date" DESC, "feature_type";


ALTER VIEW "public"."free_daily_analytics" OWNER TO "postgres";


