CREATE OR REPLACE VIEW "public"."geographic_cold_start_progress" AS
 SELECT "initiative_id",
    "zip_code",
    "city",
    "state",
    "country",
    "count"(DISTINCT "user_id") AS "interested_families",
    "count"(DISTINCT
        CASE
            WHEN ("signal_type" = 'hard_pledge'::"text") THEN "user_id"
            ELSE NULL::"uuid"
        END) AS "committed_families",
    COALESCE("sum"("pledge_amount"), (0)::numeric) AS "total_pledged",
    ( SELECT "count"(*) AS "count"
           FROM "public"."stewardship_applications" "sa"
          WHERE (("sa"."initiative_id" = "gds"."initiative_id") AND ("sa"."city" = "gds"."city") AND ("sa"."state" = "gds"."state") AND ("sa"."status" = 'approved'::"text") AND ("sa"."region_type" = 'city'::"text"))) AS "active_captains",
        CASE
            WHEN ("count"(DISTINCT "user_id") >= 500) THEN 'WILDFIRE'::"text"
            WHEN ("count"(DISTINCT "user_id") >= 250) THEN 'INFERNO'::"text"
            WHEN ("count"(DISTINCT "user_id") >= 150) THEN 'BLAZE'::"text"
            WHEN ("count"(DISTINCT "user_id") >= 100) THEN 'FIRE'::"text"
            WHEN ("count"(DISTINCT "user_id") >= 75) THEN 'FLAME'::"text"
            WHEN ("count"(DISTINCT "user_id") >= 50) THEN 'EMBER'::"text"
            ELSE 'SPARK'::"text"
        END AS "current_tier"
   FROM "public"."geographic_demand_signals" "gds"
  GROUP BY "initiative_id", "zip_code", "city", "state", "country";


ALTER VIEW "public"."geographic_cold_start_progress" OWNER TO "postgres";


COMMENT ON VIEW "public"."geographic_cold_start_progress" IS 'Cold Start Milestone 2: Aggregated progress by city for all initiatives';



