CREATE OR REPLACE VIEW "public"."gift_list_items_for_family" WITH ("security_invoker"='on') AS
 SELECT "gi"."id",
    "gi"."list_id",
    "gi"."name",
    "gi"."description",
    "gi"."url",
    "gi"."image_url",
    "gi"."price_estimate",
    "gi"."price_currency",
    "gi"."priority",
    "gi"."quantity_wanted",
    "gi"."quantity_claimed",
    "gi"."claimed_by",
    "gi"."claimed_at",
    "gi"."purchased",
    "gi"."purchased_by",
    "gi"."purchased_at",
    "gi"."notion_block_id",
    "gi"."notes",
    "gi"."created_at",
    "gi"."updated_at",
    "fm_claimer"."nickname" AS "claimed_by_name",
    "fm_claimer"."symbol" AS "claimed_by_symbol"
   FROM ((("public"."gift_list_items" "gi"
     JOIN "public"."family_gift_lists" "gl" ON (("gi"."list_id" = "gl"."id")))
     JOIN "public"."family_members" "fm" ON (("gl"."family_id" = "fm"."family_id")))
     LEFT JOIN "public"."family_members" "fm_claimer" ON (("gi"."claimed_by" = "fm_claimer"."id")))
  WHERE (("fm"."user_id" = "auth"."uid"()) AND ("fm"."is_active" = true) AND (NOT ("gl"."owner_id" IN ( SELECT "family_members"."id"
           FROM "public"."family_members"
          WHERE ("family_members"."user_id" = "auth"."uid"())))));


ALTER VIEW "public"."gift_list_items_for_family" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."gift_list_items_for_owner" WITH ("security_invoker"='on') AS
 SELECT "gi"."id",
    "gi"."list_id",
    "gi"."name",
    "gi"."description",
    "gi"."url",
    "gi"."image_url",
    "gi"."price_estimate",
    "gi"."price_currency",
    "gi"."priority",
    "gi"."quantity_wanted",
    "gi"."quantity_claimed",
        CASE
            WHEN ("gi"."claimed_by" IS NOT NULL) THEN true
            ELSE false
        END AS "is_claimed",
        CASE
            WHEN "gi"."purchased" THEN true
            ELSE false
        END AS "is_purchased",
    "gi"."notion_block_id",
    "gi"."created_at",
    "gi"."updated_at"
   FROM (("public"."gift_list_items" "gi"
     JOIN "public"."family_gift_lists" "gl" ON (("gi"."list_id" = "gl"."id")))
     JOIN "public"."family_members" "fm" ON (("gl"."owner_id" = "fm"."id")))
  WHERE ("fm"."user_id" = "auth"."uid"());


ALTER VIEW "public"."gift_list_items_for_owner" OWNER TO "postgres";


