CREATE OR REPLACE VIEW "public"."hexisle_vote_tallies" AS
 SELECT "candidate_id",
    "count"(DISTINCT "user_id") AS "voter_count",
    "sum"(
        CASE
            WHEN ("vote_direction" = 'for'::"text") THEN "marks_pledged"
            ELSE (0)::numeric
        END) AS "marks_for",
    "sum"(
        CASE
            WHEN ("vote_direction" = 'against'::"text") THEN "marks_pledged"
            ELSE (0)::numeric
        END) AS "marks_against",
    "sum"("marks_pledged") AS "total_pledged"
   FROM "public"."pledged_mark_votes"
  WHERE ("status" = 'active'::"text")
  GROUP BY "candidate_id";


ALTER VIEW "public"."hexisle_vote_tallies" OWNER TO "postgres";


