    "volume_increase" numeric GENERATED ALWAYS AS (GREATEST((0)::numeric, ("current_period_volume" - "previous_period_volume"))) STORED,
    "lb_margin_rate" numeric DEFAULT 0.167,
    "icing_rate" numeric DEFAULT 0.20,
    "margin_from_increase" numeric GENERATED ALWAYS AS ((GREATEST((0)::numeric, ("current_period_volume" - "previous_period_volume")) * 0.167)) STORED,
    "total_icing_pool" numeric GENERATED ALWAYS AS (((GREATEST((0)::numeric, ("current_period_volume" - "previous_period_volume")) * 0.167) * 0.20)) STORED,
    "status" "text" DEFAULT 'accumulating'::"text",
    "calculated_at" timestamp with time zone,
    "distributed_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"(),
    "user_id" "uuid",
    CONSTRAINT "icing_pool_period_type_check" CHECK (("period_type" = ANY (ARRAY['weekly'::"text", 'monthly'::"text", 'quarterly'::"text"]))),
    CONSTRAINT "icing_pool_status_check" CHECK (("status" = ANY (ARRAY['accumulating'::"text", 'calculated'::"text", 'distributed'::"text"])))
);


