CREATE OR REPLACE VIEW "public"."implementation_summary" WITH ("security_invoker"='true') AS
 SELECT "category",
    "count"(*) AS "total_tasks",
    "count"(*) FILTER (WHERE (("status")::"text" = 'complete'::"text")) AS "completed",
    "count"(*) FILTER (WHERE (("status")::"text" = 'partial'::"text")) AS "partial",
    "count"(*) FILTER (WHERE (("status")::"text" = 'not_started'::"text")) AS "not_started",
    "count"(*) FILTER (WHERE (("status")::"text" = 'documentation_only'::"text")) AS "documentation_only",
    "count"(*) FILTER (WHERE (("priority")::"text" = 'critical'::"text")) AS "critical_tasks",
    "count"(*) FILTER (WHERE ((("priority")::"text" = 'critical'::"text") AND (("status")::"text" <> 'complete'::"text"))) AS "critical_incomplete"
   FROM "public"."implementation_tasks"
  GROUP BY "category"
  ORDER BY ("count"(*) FILTER (WHERE ((("priority")::"text" = 'critical'::"text") AND (("status")::"text" <> 'complete'::"text")))) DESC, ("count"(*)) DESC;


ALTER VIEW "public"."implementation_summary" OWNER TO "postgres";


