CREATE OR REPLACE VIEW "public"."initiatives_with_all_crowns" AS
 SELECT "i"."id",
    "i"."initiative_number",
    "i"."name",
    "i"."initiative_slug",
    "i"."category",
    "i"."tagline",
    COALESCE("json_agg"("json_build_object"('name', "ic"."crown_name", 'title', "ic"."crown_title", 'status', "ic"."crown_status", 'order', "ic"."crown_order") ORDER BY "ic"."crown_order", "ic"."created_at") FILTER (WHERE ("ic"."id" IS NOT NULL)), '[]'::json) AS "crowns"
   FROM ("public"."initiatives" "i"
     LEFT JOIN "public"."initiative_crowns" "ic" ON (("ic"."initiative_id" = "i"."id")))
  WHERE ("i"."initiative_number" IS NOT NULL)
  GROUP BY "i"."id", "i"."initiative_number", "i"."name", "i"."initiative_slug", "i"."category", "i"."tagline"
  ORDER BY "i"."initiative_number";


