CREATE OR REPLACE VIEW "public"."ledger_patronage_summary" AS
 SELECT EXTRACT(year FROM "created_at") AS "fiscal_year",
    "is_patronage",
    "ledger_category",
    "count"(*) AS "transaction_count",
    "sum"("amount_cents") AS "total_cents",
    (("sum"("amount_cents"))::numeric / 100.0) AS "total_dollars"
   FROM "public"."transaction_ledger"
  WHERE ("status" = 'completed'::"text")
  GROUP BY (EXTRACT(year FROM "created_at")), "is_patronage", "ledger_category"
  ORDER BY (EXTRACT(year FROM "created_at")) DESC, "is_patronage" DESC, ("sum"("amount_cents")) DESC;


