CREATE OR REPLACE VIEW "public"."lmd_demand_summary" AS
 SELECT "meal_name",
    "pantry_recipe_id",
    "postal_code",
    "count"(*) AS "request_count",
    "sum"("marks_committed") AS "total_marks",
    "min"("expires_at") AS "earliest_expiry",
    "max"("expires_at") AS "latest_expiry",
    "array_agg"(DISTINCT "specific_date") FILTER (WHERE ("specific_date" IS NOT NULL)) AS "specific_dates"
   FROM "public"."lmd_meal_requests"
  WHERE ("status" = 'active'::"text")
  GROUP BY "meal_name", "pantry_recipe_id", "postal_code"
  ORDER BY ("sum"("marks_committed")) DESC;


ALTER VIEW "public"."lmd_demand_summary" OWNER TO "postgres";


