CREATE TABLE IF NOT EXISTS "public"."user_marks" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "user_id" "uuid" NOT NULL,
    "total_marks" numeric DEFAULT 0 NOT NULL,
    "mark_level" "text" GENERATED ALWAYS AS (
CASE
    WHEN ("total_marks" >= (10000)::numeric) THEN 'forest'::"text"
    WHEN ("total_marks" >= (5000)::numeric) THEN 'grove'::"text"
    WHEN ("total_marks" >= (1000)::numeric) THEN 'tree'::"text"
    WHEN ("total_marks" >= (500)::numeric) THEN 'sapling'::"text"
    WHEN ("total_marks" >= (100)::numeric) THEN 'sprout'::"text"
    ELSE 'seedling'::"text"
END) STORED,
    "voting_multiplier" numeric GENERATED ALWAYS AS (
CASE
    WHEN ("total_marks" >= (10000)::numeric) THEN 3.0
    WHEN ("total_marks" >= (5000)::numeric) THEN 2.0
    WHEN ("total_marks" >= (1000)::numeric) THEN 1.5
    ELSE 1.0
END) STORED,
    "crown_eligible" boolean GENERATED ALWAYS AS (("total_marks" >= (10000)::numeric)) STORED,
    "created_at" timestamp with time zone DEFAULT "now"(),
    "updated_at" timestamp with time zone DEFAULT "now"(),
    CONSTRAINT "user_marks_total_marks_check" CHECK (("total_marks" >= (0)::numeric))
);


ALTER TABLE "public"."user_marks" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."member_currency_dashboard" WITH ("security_invoker"='true') AS
 SELECT "m2"."user_id",
    COALESCE(("c"."eoi_credits" - "c"."eoi_used_credits"), 0) AS "credits",
    COALESCE("c"."gleaning_credits_received", 0) AS "gleaning_received",
    COALESCE("c"."gleaning_credits_earned", 0) AS "gleaning_earned",
    COALESCE("m2"."total_marks", (0)::numeric) AS "marks",
    COALESCE("m2"."mark_level", 'seedling'::"text") AS "mark_level",
    COALESCE("m2"."voting_multiplier", 1.0) AS "voting_multiplier",
    COALESCE("m2"."crown_eligible", false) AS "crown_eligible",
    COALESCE("j"."total_joules", (0)::numeric) AS "joules",
    COALESCE("j"."total_locked_value", (0)::numeric) AS "joules_locked_value"
   FROM (("public"."user_marks" "m2"
     LEFT JOIN "public"."user_credits" "c" ON (("c"."user_id" = "m2"."user_id")))
     LEFT JOIN "public"."user_joules" "j" ON (("j"."user_id" = "m2"."user_id")));


