CREATE OR REPLACE VIEW "public"."member_patronage_summary" AS
 SELECT COALESCE("payer_id", "payee_id") AS "member_id",
    EXTRACT(year FROM "created_at") AS "fiscal_year",
    "patronage_type",
    "count"(*) AS "transaction_count",
    "sum"("amount_cents") AS "total_cents",
    (("sum"("amount_cents"))::numeric / 100.0) AS "total_dollars"
   FROM "public"."transaction_ledger"
  WHERE (("status" = 'completed'::"text") AND ("is_patronage" = true))
  GROUP BY COALESCE("payer_id", "payee_id"), (EXTRACT(year FROM "created_at")), "patronage_type";


