CREATE OR REPLACE VIEW "public"."member_reputation_stability" WITH ("security_invoker"='on') AS
 SELECT "id",
    "full_name" AS "display_name",
    "created_at" AS "member_since",
    (EXTRACT(day FROM ("now"() - "created_at")))::integer AS "account_age_days",
    COALESCE("fresh_start_count", 0) AS "total_resets",
        CASE
            WHEN ((EXTRACT(day FROM ("now"() - "created_at")) > (365)::numeric) AND (COALESCE("fresh_start_count", 0) = 0)) THEN 'Bedrock'::"text"
            WHEN ((EXTRACT(day FROM ("now"() - "created_at")) > (365)::numeric) AND (COALESCE("fresh_start_count", 0) <= 3)) THEN 'Established'::"text"
            WHEN (EXTRACT(day FROM ("now"() - "created_at")) > (180)::numeric) THEN 'Growing'::"text"
            WHEN (COALESCE("fresh_start_count", 0) > 10) THEN 'Wanderer'::"text"
            ELSE 'Newcomer'::"text"
        END AS "reputation_tier",
    "round"((EXTRACT(day FROM ("now"() - "created_at")) / ((COALESCE("fresh_start_count", 0) + 1))::numeric), 2) AS "stability_score"
   FROM "public"."profiles" "p";


ALTER VIEW "public"."member_reputation_stability" OWNER TO "postgres";


COMMENT ON VIEW "public"."member_reputation_stability" IS 'Shows the value of consistent reputation vs frequent resets. High stability_score = trustworthy long-term member.';



