CREATE OR REPLACE VIEW "public"."node_status_dashboard" AS
 SELECT "sn"."id",
    "sn"."name",
    "sn"."zip_code",
    "sn"."city",
    "sn"."state",
    "sn"."infrastructure_type",
    "sn"."weekly_capacity",
    "sn"."activation_threshold",
    "sn"."status",
    "snt"."name" AS "node_type_name",
    "snt"."capacity_unit",
    ( SELECT "count"(*) AS "count"
           FROM "public"."demand_signals" "ds"
          WHERE (("ds"."zip_code" = "sn"."zip_code") AND (NOT "ds"."is_aggregated"))) AS "pending_demand_signals",
    ( SELECT "count"(*) AS "count"
           FROM "public"."node_preorders" "np"
          WHERE (("np"."node_id" = "sn"."id") AND ("np"."phase" = 'ghost'::"text"))) AS "ghost_interest",
    ( SELECT "count"(*) AS "count"
           FROM "public"."node_preorders" "np"
          WHERE (("np"."node_id" = "sn"."id") AND ("np"."phase" = 'soft_pledge'::"text"))) AS "soft_pledges",
    ( SELECT "count"(*) AS "count"
           FROM "public"."node_preorders" "np"
          WHERE (("np"."node_id" = "sn"."id") AND ("np"."phase" = 'hard_order'::"text"))) AS "hard_orders",
        CASE
            WHEN ("sn"."activation_threshold" > 0) THEN "round"(((( SELECT ("count"(*))::numeric AS "count"
               FROM "public"."node_preorders" "np"
              WHERE (("np"."node_id" = "sn"."id") AND ("np"."phase" = 'hard_order'::"text"))) / ("sn"."activation_threshold")::numeric) * (100)::numeric), 1)
            ELSE (0)::numeric
        END AS "activation_progress_percent",
    ( SELECT COALESCE("sum"("np"."upfront_amount"), (0)::numeric) AS "coalesce"
           FROM "public"."node_preorders" "np"
          WHERE (("np"."node_id" = "sn"."id") AND ("np"."upfront_paid" = true))) AS "collected_upfront",
    ( SELECT "p"."display_name"
           FROM ("public"."profiles" "p"
             JOIN "public"."node_leadership" "nl" ON (("nl"."user_id" = "p"."id")))
          WHERE (("nl"."node_id" = "sn"."id") AND ("nl"."role" = 'captain'::"text") AND ("nl"."is_active" = true))
         LIMIT 1) AS "captain_name"
   FROM ("public"."service_nodes" "sn"
     LEFT JOIN "public"."service_node_types" "snt" ON (("sn"."node_type_id" = "snt"."id")));


