CREATE OR REPLACE VIEW "public"."pantry_bounty_opportunities" WITH ("security_invoker"='true') AS
 SELECT "id",
    "cuisine",
    "meal_type",
    "style",
    "display_name",
    "description",
    "icon",
    "recipe_count",
    "public"."calculate_category_bounty"("recipe_count") AS "shadow_marks_available",
        CASE
            WHEN ("recipe_count" = 0) THEN 'Be the FIRST! 🏆'::"text"
            WHEN ("recipe_count" < 5) THEN 'Help fill the shelf'::"text"
            WHEN ("recipe_count" < 10) THEN 'Add variety'::"text"
            WHEN ("recipe_count" < 20) THEN 'Standard contribution'::"text"
            ELSE 'Shelf is full'::"text"
        END AS "bounty_message",
        CASE
            WHEN ("recipe_count" = 0) THEN 'empty'::"text"
            WHEN ("recipe_count" < 5) THEN 'sparse'::"text"
            WHEN ("recipe_count" < 10) THEN 'growing'::"text"
            WHEN ("recipe_count" < 20) THEN 'established'::"text"
            ELSE 'full'::"text"
        END AS "shelf_status"
   FROM "public"."pantry_categories" "c"
  ORDER BY ("public"."calculate_category_bounty"("recipe_count")) DESC, "display_name";


ALTER VIEW "public"."pantry_bounty_opportunities" OWNER TO "postgres";


COMMENT ON VIEW "public"."pantry_bounty_opportunities" IS 'Shows which categories need recipes and their bounty rewards';



