CREATE OR REPLACE VIEW "public"."pantry_early_program_status" WITH ("security_invoker"='true') AS
 SELECT "m"."total_makers",
    "m"."early_rewards_remaining" AS "maker_slots_remaining",
    (100 - "m"."early_rewards_remaining") AS "makers_claimed",
    "t"."total_tasters",
    "t"."early_rewards_remaining" AS "taster_slots_remaining",
    (1000 - "t"."early_rewards_remaining") AS "tasters_claimed",
        CASE
            WHEN (("m"."early_rewards_remaining" > 0) OR ("t"."early_rewards_remaining" > 0)) THEN 'OPEN'::"text"
            ELSE 'CLOSED'::"text"
        END AS "program_status"
   FROM "public"."pantry_maker_counter" "m",
    "public"."pantry_taster_counter" "t"
