    "gross_amount" numeric NOT NULL,
    "creator_share" numeric NOT NULL,
    "platform_margin" numeric NOT NULL,
    "cost_basis" numeric DEFAULT 0 NOT NULL,
    "margin_amount" numeric NOT NULL,
    "initiative_fund" numeric DEFAULT 0 NOT NULL,
    "creator_percent_actual" numeric GENERATED ALWAYS AS (
CASE
    WHEN ("gross_amount" > (0)::numeric) THEN (("creator_share" / "gross_amount") * (100)::numeric)
    ELSE (0)::numeric
END) STORED,
    "dna_compliant" boolean GENERATED ALWAYS AS (
CASE
    WHEN ("gross_amount" > (0)::numeric) THEN ((("creator_share" / "gross_amount") * (100)::numeric) >= 83.3)
    ELSE true
END) STORED,
    "created_at" timestamp with time zone DEFAULT "now"(),
    "user_id" "uuid"
);


