CREATE OR REPLACE VIEW "public"."project_cap_status" AS
 SELECT "pcd"."project_id",
    "p"."name" AS "project_name",
    "pcd"."declared_cost_cents",
    (("pcd"."declared_cost_cents")::numeric / 100.0) AS "declared_cost_dollars",
    "pcd"."cap_amount_cents",
    (("pcd"."cap_amount_cents")::numeric / 100.0) AS "cap_dollars",
    "pcd"."cumulative_lb_revenue_cents",
    (("pcd"."cumulative_lb_revenue_cents")::numeric / 100.0) AS "cumulative_lb_revenue_dollars",
    "pcd"."cap_reached",
    "pcd"."cap_reached_date",
        CASE
            WHEN "pcd"."cap_reached" THEN 0
            ELSE ("pcd"."cap_amount_cents" - "pcd"."cumulative_lb_revenue_cents")
        END AS "remaining_cap_cents"
   FROM ("public"."project_cost_declarations" "pcd"
     JOIN "public"."projects" "p" ON (("p"."id" = "pcd"."project_id")))
  ORDER BY "pcd"."created_at" DESC;


ALTER VIEW "public"."project_cap_status" OWNER TO "postgres";


