CREATE OR REPLACE VIEW "public"."project_funding_summary" AS
 SELECT "p"."id" AS "project_id",
    "p"."name" AS "project_name",
    "p"."funding_goal",
    COALESCE("sum"("pp"."amount_credits") FILTER (WHERE ("pp"."status" = 'active'::"text")), (0)::numeric) AS "total_pledged",
    "count"(DISTINCT "pp"."user_id") FILTER (WHERE ("pp"."status" = 'active'::"text")) AS "unique_backers",
        CASE
            WHEN ("p"."funding_goal" > (0)::numeric) THEN "round"(((COALESCE("sum"("pp"."amount_credits") FILTER (WHERE ("pp"."status" = 'active'::"text")), (0)::numeric) / "p"."funding_goal") * (100)::numeric), 1)
            ELSE (0)::numeric
        END AS "funding_percentage",
    "p"."funding_deadline",
    "p"."status" AS "project_status"
   FROM ("public"."projects" "p"
     LEFT JOIN "public"."project_pledges" "pp" ON (("pp"."project_id" = "p"."id")))
  GROUP BY "p"."id", "p"."name", "p"."funding_goal", "p"."funding_deadline", "p"."status";


