CREATE OR REPLACE VIEW "public"."prow_stats" WITH ("security_invoker"='true') AS
 SELECT "p"."user_id",
    (0)::numeric AS "credits",
    COALESCE("b"."total_joules", (0)::numeric) AS "joules",
    COALESCE("b"."locked_joules", (0)::numeric) AS "locked_joules",
    COALESCE("active_bounties"."count", (0)::bigint) AS "active_bounties",
    COALESCE("completed_bounties"."count", (0)::bigint) AS "completed_bounties",
    COALESCE("active_contracts"."count", (0)::bigint) AS "active_contracts"
   FROM (((("public"."prow_settings" "p"
     LEFT JOIN "public"."bond_accounts" "b" ON (("b"."user_id" = "p"."user_id")))
     LEFT JOIN LATERAL ( SELECT "count"(*) AS "count"
           FROM "public"."bounty_claims"
          WHERE (("bounty_claims"."user_id" = "p"."user_id") AND (("bounty_claims"."status")::"text" = 'in_progress'::"text"))) "active_bounties" ON (true))
     LEFT JOIN LATERAL ( SELECT "count"(*) AS "count"
           FROM "public"."bounty_claims"
          WHERE (("bounty_claims"."user_id" = "p"."user_id") AND (("bounty_claims"."status")::"text" = 'completed'::"text"))) "completed_bounties" ON (true))
     LEFT JOIN LATERAL ( SELECT "count"(*) AS "count"
           FROM "public"."user_contracts"
          WHERE (("user_contracts"."user_id" = "p"."user_id") AND (("user_contracts"."status")::"text" = 'active'::"text"))) "active_contracts" ON (true));


ALTER VIEW "public"."prow_stats" OWNER TO "postgres";


