CREATE TABLE IF NOT EXISTS "public"."reviewers" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "user_id" "uuid" NOT NULL,
    "tier" "text" DEFAULT 'content'::"text" NOT NULL,
    "reviews_completed" integer DEFAULT 0 NOT NULL,
    "reviews_overturned" integer DEFAULT 0 NOT NULL,
    "accuracy_rate" numeric(5,2) GENERATED ALWAYS AS (
CASE
    WHEN ("reviews_completed" > 0) THEN (((("reviews_completed" - "reviews_overturned"))::numeric / ("reviews_completed")::numeric) * (100)::numeric)
    ELSE 100.0
END) STORED,
    "promoted_at" timestamp with time zone,
    "suspended_until" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "reviewers_tier_check" CHECK (("tier" = ANY (ARRAY['content'::"text", 'stat'::"text", 'harper'::"text"])))
);


