CREATE OR REPLACE VIEW "public"."seeding_pool_summary" AS
 SELECT "date_trunc"('month'::"text", "created_at") AS "month",
    "count"(*) AS "contribution_count",
    "sum"("amount_cents") AS "total_pool_cents",
    (("sum"("amount_cents"))::numeric / 100.0) AS "total_pool_dollars",
    "sum"(
        CASE
            WHEN ("allocated_to_project" IS NOT NULL) THEN "amount_cents"
            ELSE 0
        END) AS "allocated_cents",
    "sum"(
        CASE
            WHEN ("allocated_to_project" IS NULL) THEN "amount_cents"
            ELSE 0
        END) AS "unallocated_cents",
    "count"(DISTINCT "allocated_to_project") FILTER (WHERE ("allocated_to_project" IS NOT NULL)) AS "projects_funded"
   FROM "public"."seeding_pool" "sp"
  GROUP BY ("date_trunc"('month'::"text", "created_at"))
  ORDER BY ("date_trunc"('month'::"text", "created_at")) DESC;


ALTER VIEW "public"."seeding_pool_summary" OWNER TO "postgres";


