CREATE OR REPLACE VIEW "public"."social_media_status" WITH ("security_invoker"='true') AS
 SELECT "platform",
    "count"(*) FILTER (WHERE ("status" = 'scheduled'::"text")) AS "scheduled",
    "count"(*) FILTER (WHERE ("status" = 'posted'::"text")) AS "posted",
    "count"(*) FILTER (WHERE ("status" = 'failed'::"text")) AS "failed",
    "min"("scheduled_at") FILTER (WHERE ("status" = 'scheduled'::"text")) AS "next_post"
   FROM "public"."social_posts"
  GROUP BY "platform";


