CREATE OR REPLACE VIEW "public"."sponsorship_cascade_view" WITH ("security_invoker"='on') AS
 WITH RECURSIVE "cascade" AS (
         SELECT "s"."id",
            "s"."sponsor_id",
            "s"."recipient_id",
            "s"."credit_amount",
            "s"."status",
            1 AS "depth",
            ARRAY["s"."id"] AS "path"
           FROM "public"."sponsorships" "s"
          WHERE ("s"."source_sponsorship_id" IS NULL)
        UNION ALL
         SELECT "s"."id",
            "s"."sponsor_id",
            "s"."recipient_id",
            "s"."credit_amount",
            "s"."status",
            ("c_1"."depth" + 1),
            ("c_1"."path" || "s"."id")
           FROM ("public"."sponsorships" "s"
             JOIN "cascade" "c_1" ON (("s"."source_sponsorship_id" = "c_1"."id")))
          WHERE (NOT ("s"."id" = ANY ("c_1"."path")))
        )
 SELECT "c"."id",
    "c"."sponsor_id",
    "c"."recipient_id",
    "c"."credit_amount",
    "c"."status",
    "c"."depth",
    "c"."path",
    "p_sponsor"."display_name" AS "sponsor_name",
    "p_recipient"."display_name" AS "recipient_name"
   FROM (("cascade" "c"
     LEFT JOIN "public"."profiles" "p_sponsor" ON (("c"."sponsor_id" = "p_sponsor"."id")))
     LEFT JOIN "public"."profiles" "p_recipient" ON (("c"."recipient_id" = "p_recipient"."id")));


