CREATE TABLE IF NOT EXISTS "public"."swoop_projects" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"(),
    "updated_at" timestamp with time zone DEFAULT "now"(),
    "title" "text" NOT NULL,
    "slug" "text" NOT NULL,
    "description" "text" NOT NULL,
    "short_description" "text",
    "recipient_name" "text" NOT NULL,
    "recipient_relationship" "text",
    "recipient_location" "text",
    "medical_situation" "text" NOT NULL,
    "monthly_needs" "jsonb" DEFAULT '{}'::"jsonb",
    "verification_status" "text" DEFAULT 'pending'::"text",
    "verification_date" timestamp with time zone,
    "verified_by" "uuid",
    "verification_notes" "text",
    "verification_contact_name" "text",
    "verification_contact_relationship" "text",
    "verification_contact_reached" boolean DEFAULT false,
    "project_lead_id" "uuid" NOT NULL,
    "project_lead_name" "text" NOT NULL,
    "project_lead_email" "text",
    "nominator_id" "uuid" NOT NULL,
    "nominator_name" "text" NOT NULL,
    "goal_amount" numeric(10,2) NOT NULL,
    "current_amount" numeric(10,2) DEFAULT 0,
    "disbursed_amount" numeric(10,2) DEFAULT 0,
    "stripe_account_id" "text",
    "stripe_account_status" "text" DEFAULT 'pending'::"text",
    "stripe_account_created_at" timestamp with time zone,
    "status" "text" DEFAULT 'nomination'::"text",
    "vote_count" integer DEFAULT 0,
    "vote_threshold" integer DEFAULT 500,
    "voting_started_at" timestamp with time zone,
    "activation_date" timestamp with time zone,
    "funded_date" timestamp with time zone,
    "closed_date" timestamp with time zone,
    "closed_reason" "text",
    "public_updates" "jsonb" DEFAULT '[]'::"jsonb",
    "last_update" timestamp with time zone,
    "share_image_url" "text",
    "featured" boolean DEFAULT false,
    "featured_order" integer,
    "category" "text" DEFAULT 'medical'::"text",
    "user_id" "uuid",
    CONSTRAINT "swoop_projects_category_check" CHECK (("category" = ANY (ARRAY['medical'::"text", 'housing'::"text", 'utilities'::"text", 'food'::"text", 'transportation'::"text", 'other'::"text"]))),
    CONSTRAINT "swoop_projects_status_check" CHECK (("status" = ANY (ARRAY['nomination'::"text", 'voting'::"text", 'pending_verification'::"text", 'active'::"text", 'funded'::"text", 'closed'::"text", 'cancelled'::"text"]))),
    CONSTRAINT "swoop_projects_stripe_account_status_check" CHECK (("stripe_account_status" = ANY (ARRAY['pending'::"text", 'onboarding'::"text", 'active'::"text", 'restricted'::"text", 'closed'::"text"]))),
    CONSTRAINT "swoop_projects_verification_status_check" CHECK (("verification_status" = ANY (ARRAY['pending'::"text", 'in_review'::"text", 'verified'::"text", 'rejected'::"text"])))
);


ALTER TABLE "public"."swoop_projects" OWNER TO "postgres";


COMMENT ON TABLE "public"."swoop_projects" IS 'Do The Swoop crisis support projects. LB acts as payment processor only.';



COMMENT ON COLUMN "public"."swoop_projects"."verification_status" IS 'Must be verified before funds can be disbursed';



COMMENT ON COLUMN "public"."swoop_projects"."project_lead_id" IS 'CRITICAL: Project lead controls funds, NOT Liana Banyan';



CREATE TABLE IF NOT EXISTS "public"."swoop_transactions" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "project_id" "uuid" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"(),
    "type" "text" NOT NULL,
    "from_type" "text" NOT NULL,
    "from_id" "uuid",
    "from_name" "text" NOT NULL,
    "from_anonymous" boolean DEFAULT false,
    "to_type" "text" NOT NULL,
    "to_name" "text" NOT NULL,
    "to_account_info" "text",
    "amount" numeric(10,2) NOT NULL,
    "purpose" "text" NOT NULL,
    "notes" "text",
    "processed_at" timestamp with time zone,
    "status" "text" DEFAULT 'pending'::"text",
    "stripe_payment_intent_id" "text",
    "stripe_transfer_id" "text",
    "stripe_payout_id" "text",
    "stripe_fee" numeric(10,2),
    "receipt_url" "text",
    "receipt_uploaded_at" timestamp with time zone,
    "user_id" "uuid",
    CONSTRAINT "swoop_transactions_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'processing'::"text", 'completed'::"text", 'failed'::"text", 'refunded'::"text"]))),
    CONSTRAINT "swoop_transactions_type_check" CHECK (("type" = ANY (ARRAY['donation'::"text", 'disbursement'::"text", 'refund'::"text", 'transfer_in'::"text", 'transfer_out'::"text"])))
);


ALTER TABLE "public"."swoop_transactions" OWNER TO "postgres";


COMMENT ON TABLE "public"."swoop_transactions" IS 'Full transparency: FROM, TO, WHEN, HOW MUCH, WHAT FOR';



