CREATE OR REPLACE VIEW "public"."treasure_automation_status" WITH ("security_invoker"='true') AS
 SELECT ( SELECT "count"(*) AS "count"
           FROM "public"."treasure_winners") AS "total_winners",
    ( SELECT (100 - "count"(*))
           FROM "public"."treasure_winners") AS "remaining_keys",
    ( SELECT "max"("treasure_milestones"."milestone") AS "max"
           FROM "public"."treasure_milestones") AS "last_milestone",
    ( SELECT "max"("automation_log"."created_at") AS "max"
           FROM "public"."automation_log"
          WHERE ("automation_log"."action" = 'milestone_reached'::"text")) AS "last_milestone_at",
    ( SELECT "count"(*) AS "count"
           FROM "public"."automation_log"
          WHERE ("automation_log"."action" = 'winner_email'::"text")) AS "emails_sent",
    ( SELECT "count"(*) AS "count"
           FROM "public"."automation_log"
          WHERE ("automation_log"."action" = 'milestone_post'::"text")) AS "social_posts";


ALTER VIEW "public"."treasure_automation_status" OWNER TO "postgres";


COMMENT ON VIEW "public"."treasure_automation_status" IS 'Quick view of treasure hunt automation status';



