CREATE OR REPLACE VIEW "public"."user_shadow_marks_summary" WITH ("security_invoker"='true') AS
 SELECT "user_id",
    "count"(*) FILTER (WHERE ("status" = 'vesting'::"text")) AS "milestone_completion_count",
    "sum"("current_amount") FILTER (WHERE ("status" = ANY (ARRAY['vesting'::"text", 'partial'::"text"]))) AS "total_shadow",
    "sum"("crystallized_amount") AS "total_crystallized",
    "sum"(("initial_amount" - "crystallized_amount")) FILTER (WHERE ("status" = 'expired'::"text")) AS "total_expired"
   FROM "public"."shadow_marks"
  GROUP BY "user_id";


ALTER VIEW "public"."user_shadow_marks_summary" OWNER TO "postgres";


