CREATE OR REPLACE VIEW "public"."v_current_transparency_metrics" AS
 SELECT ( SELECT "count"(*) AS "count"
           FROM "public"."innovation_log") AS "total_innovations",
    ( SELECT "count"(*) AS "count"
           FROM "public"."proposals"
          WHERE ("proposals"."status" = 'active'::"text")) AS "active_proposals",
    ( SELECT "count"(*) AS "count"
           FROM "public"."profiles"
          WHERE ("profiles"."is_active" = true)) AS "active_members",
    ( SELECT "count"(*) AS "count"
           FROM "public"."orders"
          WHERE ("orders"."status" = 'completed'::"text")) AS "completed_orders",
    ( SELECT COALESCE("sum"("orders"."total_credits"), (0)::numeric) AS "coalesce"
           FROM "public"."orders"
          WHERE ("orders"."status" = 'completed'::"text")) AS "total_transaction_volume",
    "now"() AS "snapshot_at";


ALTER VIEW "public"."v_current_transparency_metrics" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_donation_commitments_summary" WITH ("security_invoker"='true') AS
