    "target_type",
    "target_name",
    "category",
    "status",
    "total_donated",
    "remaining_pool",
    "next_charge_date",
    "created_at",
    ( SELECT "count"(*) AS "count"
           FROM "public"."donation_commitment_transactions"
          WHERE ("donation_commitment_transactions"."commitment_id" = "dc"."id")) AS "transaction_count"
   FROM "public"."donation_commitments" "dc"
  WHERE ("status" <> 'cancelled'::"text");


ALTER VIEW "public"."v_donation_commitments_summary" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_msa_account_summary" WITH ("security_invoker"='true') AS
 SELECT "id",
