    "total_withdrawn",
    "total_platform_match",
    "auto_contribute_percent",
    ( SELECT "count"(*) AS "count"
           FROM "public"."msa_transactions"
          WHERE ("msa_transactions"."account_id" = "a"."id")) AS "transaction_count",
    ( SELECT "max"("msa_transactions"."created_at") AS "max"
           FROM "public"."msa_transactions"
          WHERE ("msa_transactions"."account_id" = "a"."id")) AS "last_transaction"
   FROM "public"."msa_accounts" "a"
  WHERE ("status" = 'active'::"text");


ALTER VIEW "public"."v_msa_account_summary" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_promotion_leaderboard" WITH ("security_invoker"='true') AS
 SELECT "promoter_id",
    "count"(*) AS "total_clicks",
    "sum"("marks_awarded") AS "total_marks_earned",
    "count"(DISTINCT "project_id") AS "projects_promoted",
    "sum"(
        CASE
            WHEN "converted_to_signup" THEN 1
            ELSE 0
        END) AS "signups_generated",
    "sum"(
        CASE
            WHEN "converted_to_backer" THEN 1
            ELSE 0
        END) AS "backers_generated"
   FROM "public"."promotion_attributions"
  GROUP BY "promoter_id"
  ORDER BY ("sum"("marks_awarded")) DESC;


ALTER VIEW "public"."v_promotion_leaderboard" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_swoop_active_projects" WITH ("security_invoker"='true') AS
 SELECT "id",
    "created_at",
    "updated_at",
    "title",
    "slug",
    "description",
    "short_description",
    "recipient_name",
    "recipient_relationship",
    "recipient_location",
    "medical_situation",
    "monthly_needs",
    "verification_status",
    "verification_date",
    "verified_by",
    "verification_notes",
    "verification_contact_name",
    "verification_contact_relationship",
    "verification_contact_reached",
    "project_lead_id",
    "project_lead_name",
    "project_lead_email",
    "nominator_id",
    "nominator_name",
    "goal_amount",
    "current_amount",
    "disbursed_amount",
    "stripe_account_id",
    "stripe_account_status",
    "stripe_account_created_at",
    "status",
    "vote_count",
    "vote_threshold",
    "voting_started_at",
    "activation_date",
    "funded_date",
    "closed_date",
    "closed_reason",
    "public_updates",
    "last_update",
    "share_image_url",
    "featured",
    "featured_order",
    "category",
    ( SELECT "count"(*) AS "count"
           FROM "public"."swoop_project_votes"
          WHERE ("swoop_project_votes"."project_id" = "p"."id")) AS "supporter_count",
    ( SELECT "count"(*) AS "count"
           FROM "public"."swoop_transactions"
          WHERE (("swoop_transactions"."project_id" = "p"."id") AND ("swoop_transactions"."type" = 'donation'::"text") AND ("swoop_transactions"."status" = 'completed'::"text"))) AS "donation_count",
    (("current_amount" / NULLIF("goal_amount", (0)::numeric)) * (100)::numeric) AS "percent_funded"
   FROM "public"."swoop_projects" "p"
  WHERE ("status" = ANY (ARRAY['voting'::"text", 'active'::"text", 'funded'::"text"]))
  ORDER BY "featured" DESC, "vote_count" DESC;


ALTER VIEW "public"."v_swoop_active_projects" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_swoop_project_transparency" WITH ("security_invoker"='true') AS
 SELECT "t"."id",
    "t"."project_id",
    "t"."created_at",
    "t"."type",
    "t"."from_name",
    "t"."from_anonymous",
    "t"."to_name",
    "t"."to_type",
    "t"."amount",
    "t"."purpose",
    "t"."status",
    "t"."processed_at",
    "p"."title" AS "project_title",
    "p"."project_lead_name"
   FROM ("public"."swoop_transactions" "t"
     JOIN "public"."swoop_projects" "p" ON (("t"."project_id" = "p"."id")))
  WHERE ("t"."status" = 'completed'::"text")
  ORDER BY "t"."created_at" DESC;


ALTER VIEW "public"."v_swoop_project_transparency" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_user_cue_card_destinations" WITH ("security_invoker"='true') AS
 SELECT "d"."id",
    "d"."user_id",
    "d"."cue_card_template_id",
    "d"."destination_type",
    "d"."project_ids",
    "d"."category_slug",
    "d"."include_owned_only",
    "d"."portfolio_filter",
    "d"."is_own_project",
    "d"."promotion_credit_rate",
    "d"."display_name",
    "d"."created_at",
    "d"."updated_at",
    "t"."title" AS "template_title",
    ( SELECT "json_agg"("json_build_object"('id', "p"."id", 'name', "p"."name")) AS "json_agg"
           FROM "public"."projects" "p"
          WHERE ("p"."id" = ANY ("d"."project_ids"))) AS "bound_projects_detail"
   FROM ("public"."cue_card_destinations" "d"
     LEFT JOIN "public"."cue_card_templates" "t" ON (("t"."id" = "d"."cue_card_template_id")));


ALTER VIEW "public"."v_user_cue_card_destinations" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_user_giving_summary" WITH ("security_invoker"='true') AS
 SELECT "user_id",
    "count"(*) FILTER (WHERE ("status" = 'active'::"text")) AS "active_commitments",
    "count"(*) FILTER (WHERE (("type" = 'recurring'::"text") AND ("status" = 'active'::"text"))) AS "active_recurring",
    "sum"("total_donated") AS "lifetime_donated",
    "sum"("remaining_pool") FILTER (WHERE (("type" = 'pool'::"text") AND ("status" = 'active'::"text"))) AS "available_pool",
    "max"("last_donation_date") AS "last_donation"
   FROM "public"."donation_commitments"
  GROUP BY "user_id";


ALTER VIEW "public"."v_user_giving_summary" OWNER TO "postgres";


