CREATE OR REPLACE VIEW "public"."vault_family_sharing_status" WITH ("security_invoker"='true') AS
 SELECT "vsa"."family_id",
    "vsa"."granter_member_id",
    "fm"."nickname" AS "granter_name",
    "fm"."symbol" AS "loteria_symbol",
    "vsa"."content_scope",
    "vsa"."shared_with_member_id",
        CASE
            WHEN ("vsa"."shared_with_member_id" IS NULL) THEN 'All Family'::"text"
            ELSE ( SELECT "family_members"."nickname"
               FROM "public"."family_members"
              WHERE ("family_members"."id" = "vsa"."shared_with_member_id"))
        END AS "shared_with_name",
    "vsa"."authorized_at",
    "vsa"."is_active",
    ( SELECT "count"(*) AS "count"
           FROM "public"."vault_shared_content"
          WHERE ("vault_shared_content"."authorization_id" = "vsa"."id")) AS "content_count"
   FROM ("public"."vault_sharing_authorizations" "vsa"
     JOIN "public"."family_members" "fm" ON (("vsa"."granter_member_id" = "fm"."id")))
  WHERE ("vsa"."is_active" = true);


