CREATE OR REPLACE VIEW "public"."war_chest_summary" AS
 SELECT "user_id",
    "sum"("marks_earned") AS "total_marks_earned",
    "sum"(
        CASE
            WHEN "is_funded" THEN "eligible_amount"
            ELSE (0)::numeric
        END) AS "total_eligible",
    "sum"("allocated_amount") AS "total_allocated",
    "sum"(
        CASE
            WHEN "is_funded" THEN ("eligible_amount" - "allocated_amount")
            ELSE (0)::numeric
        END) AS "available_eligible"
   FROM "public"."mark_work_records"
  GROUP BY "user_id";


