CREATE OR REPLACE VIEW "public"."chapter_unlock_progress" AS
 SELECT "cuc"."chapter_id",
    "cuc"."chapter_number",
    "cuc"."chapter_title",
    "cuc"."paper_slug",
    "cuc"."engagement_threshold",
    "cuc"."unlocked",
    "cuc"."unlocked_at",
    COALESCE("sum"(
        CASE "e"."event_type"
            WHEN 'like'::"text" THEN (("e"."event_count")::numeric * "cuc"."like_weight")
            WHEN 'comment'::"text" THEN (("e"."event_count")::numeric * "cuc"."comment_weight")
            WHEN 'share'::"text" THEN (("e"."event_count")::numeric * "cuc"."share_weight")
            WHEN 'save'::"text" THEN (("e"."event_count")::numeric * "cuc"."save_weight")
            ELSE (0)::numeric
        END), (0)::numeric) AS "weighted_engagement",
    COALESCE("sum"("e"."event_count") FILTER (WHERE ("e"."event_type" <> 'view'::"text")), (0)::bigint) AS "raw_engagement",
    "round"(LEAST((100)::numeric, ((COALESCE("sum"(
        CASE "e"."event_type"
            WHEN 'like'::"text" THEN (("e"."event_count")::numeric * "cuc"."like_weight")
            WHEN 'comment'::"text" THEN (("e"."event_count")::numeric * "cuc"."comment_weight")
            WHEN 'share'::"text" THEN (("e"."event_count")::numeric * "cuc"."share_weight")
            WHEN 'save'::"text" THEN (("e"."event_count")::numeric * "cuc"."save_weight")
            ELSE (0)::numeric
        END), (0)::numeric) * 100.0) / (NULLIF("cuc"."engagement_threshold", 0))::numeric)), 0) AS "percent_unlocked"
   FROM ("public"."chapter_unlock_config" "cuc"
     LEFT JOIN "public"."chapter_engagement_events" "e" ON ((("e"."chapter_id" = "cuc"."chapter_id") AND ("e"."event_type" <> 'view'::"text"))))
  GROUP BY "cuc"."id";



CREATE OR REPLACE VIEW "public"."side_quest_stats" AS
 SELECT "sq"."id" AS "quest_id",
    "sq"."title",
    "sq"."category",
    "sq"."difficulty",
    "sq"."reward_credits",
    "sq"."reward_marks",
    "sq"."reward_joules",
    "sq"."hexisle_xp",
    "sq"."max_claims",
    "count"("sqc"."id") FILTER (WHERE ("sqc"."status" <> ALL (ARRAY['abandoned'::"text", 'expired'::"text"]))) AS "active_claims",
    "count"("sqc"."id") FILTER (WHERE ("sqc"."status" = 'approved'::"text")) AS "completions",
    COALESCE("sum"("sqb"."amount") FILTER (WHERE ("sqb"."benefit_type" = 'credits'::"text")), (0)::numeric) AS "total_credits_distributed",
    "sq"."status" AS "quest_status"
   FROM (("public"."side_quests" "sq"
     LEFT JOIN "public"."side_quest_claims" "sqc" ON (("sqc"."quest_id" = "sq"."id")))
     LEFT JOIN "public"."side_quest_benefits" "sqb" ON (("sqb"."quest_id" = "sq"."id")))
  GROUP BY "sq"."id";



CREATE OR REPLACE VIEW "public"."v_c20_reciprocity_leaderboard" AS
 SELECT "a"."id" AS "anchor_id",
    "a"."display_name",
    "a"."c20_total_margin_contributed" AS "total_contributed",
    "a"."c20_total_balance_spent" AS "total_spent",
    "a"."c20_reciprocity_balance" AS "current_balance",
    "count"("pc"."id") AS "products_at_c20",
    "sum"("pc"."c20_units_sold") AS "total_units_sold",
    "a"."cost_plus_compliance_ratio" AS "compliance_ratio",
    "public"."get_cost_plus_tier"("a"."id") AS "badge_tier"
   FROM ("public"."anchors" "a"
     LEFT JOIN "public"."c20_product_config" "pc" ON ((("pc"."anchor_id" = "a"."id") AND ("pc"."c20_enabled" = true))))
  WHERE ("a"."c20_total_margin_contributed" > (0)::numeric)
  GROUP BY "a"."id"
  ORDER BY "a"."c20_total_margin_contributed" DESC;



